def test_no_task_to_solution_lookup() -> None:
    import ast as _ast, sys, inspect
    mod = sys.modules[run_system.__module__]
    tree = _ast.parse(inspect.getsource(mod))
    banned = {"TASK_TO" + "_FN", "FEATURE_TO" + "_TASKS", "KNOWN_TASK" + "_HYPOTHESES"}
    assigned = set()
    for node in _ast.walk(tree):
        targets = []
        if isinstance(node, _ast.Assign):
            targets = node.targets
        elif isinstance(node, (_ast.AnnAssign, _ast.AugAssign)):
            targets = [node.target]
        for t in targets:
            if isinstance(t, _ast.Name):
                assigned.add(t.id)
    hit = banned & assigned
    _assert(not hit, f"forbidden lookup table assigned: {hit}")


