def test_improvement_chain_is_recursive() -> None:
    # The defining RSI property, as measured: SOME installed macro's body
    # references an earlier installed macro, and both generations are
    # load-bearing in adopted solutions of strictly ordered waves.
    rs = build_adaptive()
    macros = rs.searcher.macros

    def first_use_wave(mid: int):
        return min((rs.adopted_wave[tid]
                    for tid, toks in rs.adopted_tokens.items() if mid in toks),
                   default=None)

    found = False
    for child in macros.values():
        parents = [t for t in child.body if t >= MACRO_ID_BASE]
        for pid in parents:
            if pid not in macros:
                continue
            pw, cw = first_use_wave(pid), first_use_wave(child.mid)
            if pw is not None and cw is not None and cw > pw:
                found = True
                break
        if found:
            break
    _assert(found, "no load-bearing parent->child macro generation pair "
                   "with strict wave ordering")


