# =========================================================================== #
# 9. HYPERDIMENSIONAL COMPUTING (HDC/VSA) & KURAMOTO OSCILLATOR ENGINE        #
# =========================================================================== #
class HDCSpace:
    """Hyperdimensional Computing / Vector Symbolic Architecture (VSA) space.
    Uses bipolar vectors (+1, -1) of dimension D.
    """
    def __init__(self, d: int = 10000, seed: int = SEED):
        self.d = d
        self.rng = random.Random(seed)
        self.vocab = {}

    def random_vector(self) -> List[int]:
        return [self.rng.choice([-1, 1]) for _ in range(self.d)]

    def get_vector(self, name: str) -> List[int]:
        if name not in self.vocab:
            self.vocab[name] = self.random_vector()
        return self.vocab[name]

    def bind(self, x: List[int], y: List[int]) -> List[int]:
        return [a * b for a, b in zip(x, y)]

    def bundle(self, vectors: List[List[int]]) -> List[int]:
        sums = [0] * self.d
        for v in vectors:
            for i in range(self.d):
                sums[i] += v[i]
        return [1 if s >= 0 else -1 for s in sums]

    def permute(self, x: List[int], shift: int = 1) -> List[int]:
        shift = shift % self.d
        return x[shift:] + x[:shift]

    def similarity(self, x: List[int], y: List[int]) -> float:
        dot = sum(a * b for a, b in zip(x, y))
        return dot / self.d


class KuramotoSolver:
    """Coupled Kuramoto Oscillator Network for program synthesis.
    Positions compete locally, and align globally with VSA target attractors.
    """
    def __init__(self, num_slots: int, vocab_size: int, seed: int = SEED):
        self.L = num_slots
        self.M = vocab_size
        self.rng = random.Random(seed)

    def solve(self, target_similarities: List[List[float]], steps: int = 150, dt: float = 0.05, 
              K: float = 2.0, J: float = 1.0, noise_std: float = 0.2) -> List[int]:
        phases = [[self.rng.uniform(0, 2 * math.pi) for _ in range(self.M)] for _ in range(self.L)]
        
        for _ in range(steps):
            new_phases = [[0.0] * self.M for _ in range(self.L)]
            for l in range(self.L):
                for j in range(self.M):
                    repulsion = 0.0
                    for k in range(self.M):
                        if k != j:
                            repulsion += math.sin(phases[l][j] - phases[l][k])
                    
                    c_lj = target_similarities[l][j]
                    attraction = c_lj * math.cos(phases[l][j])
                    
                    noise = self.rng.normalvariate(0.0, noise_std) if noise_std > 0 else 0.0
                    
                    dtheta = 1.0 - J * repulsion + K * attraction + noise
                    new_phases[l][j] = (phases[l][j] + dtheta * dt) % (2 * math.pi)
            phases = new_phases
            
        best_program = []
        for l in range(self.L):
            best_op = -1
            best_val = -2.0
            for j in range(self.M):
                val = math.cos(phases[l][j])
                if val > best_val:
                    best_val = val
                    best_op = j
            best_program.append(best_op)
        return best_program


class HDCAnalogicalTransfer:
    """Handles algebraic analogy queries using VSA.
    Translates structures: A is to B as C is to D => D = C * A^-1 * B
    """
    def __init__(self, hdc: HDCSpace):
        self.hdc = hdc

    def transfer(self, input_a: List[int], prog_a: List[int], input_b: List[int]) -> List[int]:
        # T = prog_a * input_a
        relation = self.hdc.bind(prog_a, input_a)
        # prog_b = input_b * relation
        prog_b = self.hdc.bind(input_b, relation)
        return prog_b


def demo_hdc_rsi() -> None:
    print("=" * 80)
    print("DEMO: NEXT-GENERATION CONTINUOUS-WAVE RSI (HDC/VSA & KURAMOTO OSCILLATORS)")
    print("DOMAIN: ABSTRACT STRATEGIC PLANNING & MULTI-AGENT DECISION MAKING")
    print("=" * 80)
    
    hdc = HDCSpace(d=10000, seed=42)
    # Define an abstract strategic planning vocabulary instead of simple arithmetic
    strategy_vocab = [
        "GATHER_INTEL",
        "ALLOCATE_RESOURCES",
        "BUILD_FORTRESS",
        "EXECUTE_STRIKE",
        "DIPLOMACY_NEGOTIATE"
    ]
    M = len(strategy_vocab)
    L = 3  # Plan length (steps)
    
    print(f"HDC Dimension: {hdc.d}")
    print(f"Strategic Action Vocabulary: {strategy_vocab}")
    
    action_vectors = [hdc.get_vector(name) for name in strategy_vocab]
    
    # 2. Define Domain A Strategy: [GATHER_INTEL, BUILD_FORTRESS, DIPLOMACY_NEGOTIATE]
    target_plan = ["GATHER_INTEL", "BUILD_FORTRESS", "DIPLOMACY_NEGOTIATE"]
    print(f"\nOriginal Target Plan (Domain A): {target_plan}")
    
    prog_a_vec = hdc.bundle([
        hdc.permute(action_vectors[0], 0),  # GATHER_INTEL at Step 0
        hdc.permute(action_vectors[2], 1),  # BUILD_FORTRESS at Step 1
        hdc.permute(action_vectors[4], 2)   # DIPLOMACY_NEGOTIATE at Step 2
    ])
    
    # Context A represents the environmental threat vector for Domain A
    context_a_vec = hdc.random_vector()
    # State A represents the resolved outcome state
    outcome_a_vec = hdc.bind(context_a_vec, prog_a_vec)
    
    # 3. Perform zero-shot analogical transfer to a new Context B (Domain B)
    print("\nPerforming zero-shot analogical transfer to Scenario Context B...")
    transfer_engine = HDCAnalogicalTransfer(hdc)
    context_b_vec = hdc.random_vector()
    
    # Target state B is obtained by applying the relationship learned in context A to context B
    state_b_vec = transfer_engine.transfer(context_a_vec, outcome_a_vec, context_b_vec)
    
    # Extract the strategic plan from the B outcome
    prog_b_vec = hdc.bind(context_b_vec, state_b_vec)
    
    print("Verifying target VSA vector similarity at each step of the plan:")
    for l in range(L):
        print(f"  Step {l}:")
        for j, action in enumerate(strategy_vocab):
            sim = hdc.similarity(prog_b_vec, hdc.permute(action_vectors[j], l))
            print(f"    Action {action}: similarity = {sim:.4f}")
            
    # 4. Solve using Kuramoto Solver (Continuous Synchronization)
    print("\nInitializing Kuramoto Oscillator Network for Strategic Decision Locking...")
    solver = KuramotoSolver(num_slots=L, vocab_size=M, seed=123)
    
    target_similarities = []
    for l in range(L):
        slot_sims = []
        for j in range(M):
            sim = hdc.similarity(prog_b_vec, hdc.permute(action_vectors[j], l))
            slot_sims.append(max(0.0, sim))
        target_similarities.append(slot_sims)
        
    print("Running Kuramoto phase iterations...")
    decoded_action_indices = solver.solve(target_similarities, steps=200, dt=0.04, K=3.0, J=1.5, noise_std=0.1)
    
    decoded_actions = [strategy_vocab[idx] for idx in decoded_action_indices]
    print(f"\nDecoded Strategy Plan from Oscillator Phase Locking: {decoded_actions}")
    print(f"Original Target Plan: {target_plan}")
    
    if decoded_actions == target_plan:
        print("\nSUCCESS: Phase-locking successfully converged on the correct strategic plan!")
    else:
        print("\nFAILURE: Phase-locking converged on incorrect plan.")


# --- HDC / Kuramoto Unit Tests (English) ---
def test_hdc_algebra_soundness() -> None:
    hdc = HDCSpace(d=4000, seed=101)
    v1 = hdc.random_vector()
    v2 = hdc.random_vector()
    
    bound = hdc.bind(v1, v2)
    unbound = hdc.bind(bound, v2)
    
    sim = hdc.similarity(unbound, v1)
    _assert(sim > 0.99, f"Binding inverse failed: sim={sim}")
    
    v1_perm = hdc.permute(v1, 1)
    sim_perm = hdc.similarity(v1, v1_perm)
    _assert(abs(sim_perm) < 0.1, f"Permutation not orthogonal: sim={sim_perm}")


def test_kuramoto_phase_locking() -> None:
    target_similarities = [
        [0.0, 0.0, 0.8, 0.0],
        [0.9, 0.0, 0.0, 0.0]
    ]
    solver = KuramotoSolver(num_slots=2, vocab_size=4, seed=42)
    best_prog = solver.solve(target_similarities, steps=100, dt=0.05, K=5.0, J=2.0, noise_std=0.0)
    _assert(best_prog == [2, 0], f"Kuramoto failed to phase lock: {best_prog}")


def test_zero_shot_analogy_transfer() -> None:
    hdc = HDCSpace(d=4000, seed=202)
    input_a = hdc.random_vector()
    prog_a = hdc.random_vector()
    state_a = hdc.bind(input_a, prog_a)
    
    input_b = hdc.random_vector()
    transfer_engine = HDCAnalogicalTransfer(hdc)
    
    state_b = transfer_engine.transfer(input_a, state_a, input_b)
    expected_state_b = hdc.bind(input_b, prog_a)
    sim = hdc.similarity(state_b, expected_state_b)
    _assert(sim > 0.99, f"Analogy transfer failed: sim={sim}")



# ###########################################################################
# ### BEGIN SECTION 22 (inserted): EVOLVABLE GOAL-GENERATION GRAMMAR       ###
# ###########################################################################
# =========================================================================== #
# SECTION 22.  EVOLVABLE GOAL-GENERATION GRAMMAR                               #
#                                                                             #
# The self-generated curriculum (propose_mints) previously hard-coded its     #
# goal-generation grammar: the branches `sq`, `mulo`, `via` lived as fixed    #
# Python in propose_mints(). This section makes the GENERATOR itself a piece  #
# of evolvable DATA -- a typed GoalGrammarGenome -- while leaving the         #
# VERIFIER (seal_task, the dual sealed gates, the VM, adoption, rollback,     #
# deterministic seeding) byte-identical and hash-pinned as the sole root of   #
# trust. The grammar may invent new goal constructors; it may NOT touch the   #
# thing that judges whether the goals it invents are real.                    #
#                                                                             #
# Architecture (after this section):                                          #
#   immutable verifier  (seal_task / gates / VM / adoption / rollback)        #
#        |  pinned by _gg_verifier_fp(), asserted unchanged every round       #
#   evolvable GoalGrammarGenome  (sq/mulo/via are now PRIMITIVES, plus        #
#        composed operators, typed holes, objective weights, lineage)         #
#        --generate(public summary, budget, seed)-->  candidate goal specs    #
#   environment mint factory  (_genome_oracle seals specs into dual-gated     #
#        SealedTasks -- search never sees the oracle)                         #
#        --> downstream solver/searcher (unchanged) solves the new walls      #
#   GoalGrammarMetaGate  (A/B: incumbent vs candidate grammar, identical      #
#        seed/budget/task-stream/solver-state; accept ONLY on measured        #
#        downstream gain, no regression, no Goodhart, verifier unchanged)     #
#        --> accepted grammar becomes the next generator (reused, versioned)  #
#                                                                             #
# Falsifiable forms (declared BEFORE running; controls can return negatives): #
#   G1  The initial genome reproduces legacy propose_mints EXACTLY (same      #
#       flat spec stream on the same RunState). FALSIFIED if any spec or      #
#       order differs.                                                        #
#   G2  Composed operators generate target VECTORS that NO depth-1 sq/mulo/   #
#       via operator can generate (strictly new minting reach). FALSIFIED if  #
#       the composed set is a subset of the depth-1 set.                      #
#   G3  The meta-gate ACCEPTS a candidate grammar only when it yields a       #
#       strictly larger count of novel, non-duplicate, downstream-SOLVED      #
#       frontier walls than the incumbent under identical budget, AND no      #
#       previously-solved wall regresses, AND no Goodhart-trivial vector is   #
#       counted, AND the verifier fingerprint is unchanged. FALSIFIED if a    #
#       worse/equal candidate is accepted, or a real gain is rejected.        #
#   G4  Deterministic replay: same seed -> identical mutations, specs,        #
#       accept/reject, and report digests. FALSIFIED by any divergence.       #
#   G5  The genome's generate()/mutation code never references the oracle     #
#       registry or the sealed gates (no path by which the grammar can read   #
#       ground truth or weaken verification). FALSIFIED by source inspection. #
# =========================================================================== #

from dataclasses import dataclass, field, replace as _dc_replace
from typing import Any, Callable, Dict, List, Optional, Tuple
import hashlib as _gg_hashlib
import json as _gg_json
import random as _gg_random
from time import time as _gg_time


# --- typed holes ----------------------------------------------------------- #
# A goal-operator is a spec-TREE skeleton with typed holes. TASK holes are
# filled with public solved-task ids; MACRO holes with public list-producer
# macro ids. Composition = nesting a sub-skeleton where a TASK hole sits.
class _GGHole:
    __slots__ = ("kind",)

    def __init__(self, kind: str) -> None:
        self.kind = kind                     # "task" | "macro"

    def __repr__(self) -> str:
        return f"<{self.kind}>"


HOLE_T = _GGHole("task")
HOLE_M = _GGHole("macro")


@dataclass(frozen=True)
class GoalOp:
    """One goal-constructor, represented as data (not Python branches)."""
    name: str                                # versioned, e.g. "sq", "sq.mulo#2"
    skeleton: Tuple                          # tree with HOLE_T / HOLE_M leaves
    fill_mode: str                           # single|via|pair_le|product
    task_bound: int                          # cap on the task-id pool per hole
    origin: str                              # "primitive" or mutation op name
    parents: Tuple[str, ...] = ()            # lineage of op names
    family: str = ""                         # "" = any; else restrict task holes

    def arity_sig(self) -> Tuple[str, ...]:
        """Type signature: the ordered hole types, then the output type
        ('task' -- every constructor yields a task oracle)."""
        return tuple(_gg_hole_types(self.skeleton)) + ("->task",)


@dataclass
class GoalGrammarGenome:
    """The evolvable goal-generation grammar, as data."""
    ops: Tuple[GoalOp, ...]
    obj_weights: Dict[str, float]            # frontier|novelty|compression|transfer
    mut_history: Tuple[str, ...] = ()        # mutation-op names applied, in order
    score_history: Tuple[float, ...] = ()    # downstream gain measured per accept
    version: int = 0
    parent_digest: str = ""

    def digest(self) -> str:
        payload = {
            "ops": [[o.name, _gg_skel_repr(o.skeleton), o.fill_mode,
                     o.task_bound, o.family, list(o.parents)] for o in self.ops],
            "w": {k: round(v, 6) for k, v in sorted(self.obj_weights.items())},
            "v": self.version,
        }
        raw = _gg_json.dumps(payload, sort_keys=True).encode()
        return _gg_hashlib.sha256(raw).hexdigest()[:16]

    def clone(self) -> "GoalGrammarGenome":
        return GoalGrammarGenome(
            ops=tuple(self.ops), obj_weights=dict(self.obj_weights),
            mut_history=tuple(self.mut_history),
            score_history=tuple(self.score_history),
            version=self.version, parent_digest=self.parent_digest)


# --- skeleton helpers ------------------------------------------------------ #
def _gg_hole_types(node: Any) -> List[str]:
    if isinstance(node, _GGHole):
        return [node.kind]
    if isinstance(node, tuple):
        out: List[str] = []
        for ch in node[1:]:
            out.extend(_gg_hole_types(ch))
        return out
    return []                                # a fixed leaf (str tid or int mid)


def _gg_skel_repr(node: Any) -> str:
    if isinstance(node, _GGHole):
        return "T" if node.kind == "task" else "M"
    if isinstance(node, tuple):
        return node[0] + "(" + ",".join(_gg_skel_repr(c) for c in node[1:]) + ")"
    return str(node)


def _gg_depth(node: Any) -> int:
    if isinstance(node, tuple):
        return 1 + max((_gg_depth(c) for c in node[1:]), default=0)
    return 0


def _gg_instantiate(skeleton: Any, fill: List[Any]) -> Any:
    """Replace holes left-to-right with successive fill values; fixed leaves
    (already-bound task ids / macro ids) pass through unchanged."""
    it = iter(fill)

    def walk(node: Any) -> Any:
        if isinstance(node, _GGHole):
            return next(it)
        if isinstance(node, tuple):
            return (node[0],) + tuple(walk(c) for c in node[1:])
        return node
    return walk(skeleton)


def goal_tree_to_flat(tree: Tuple) -> Tuple[str, str, str]:
    """Convert a DEPTH-1 goal tree to the legacy flat (op, a, b) spec consumed
    by the immutable mint_task. Raises on deeper trees (legacy path is depth-1
    only; composed trees use the environment mint factory in this section)."""
    if not isinstance(tree, tuple):
        raise ValueError(f"not_a_tree:{tree}")
    op = tree[0]
    if op == "sq":
        a = tree[1]
        if not isinstance(a, str):
            raise ValueError("sq_arg_not_leaf_in_legacy_path")
        return ("sq", a, "")
    if op == "mulo":
        a, b = tree[1], tree[2]
        if not (isinstance(a, str) and isinstance(b, str)):
            raise ValueError("mulo_arg_not_leaf_in_legacy_path")
        return ("mulo", a, b)
    if op == "via":
        a, mid = tree[1], tree[2]
        if not isinstance(a, str):
            raise ValueError("via_arg_not_leaf_in_legacy_path")
        return (f"via{int(mid)}", a, "")
    raise ValueError(f"unknown_goal_op:{op}")


# --- environment oracle builder (mint factory; NOT visible to search) ------ #
def _genome_oracle(node: Any, rs: "RunState") -> Callable[[List[int]], int]:
    """Recursive generalization of _gen_oracle to spec TREES. Lives on the
    environment side exactly like _gen_oracle and seal_task: it constructs the
    private oracle for a (possibly composed) goal spec. Search code never
    receives this callable; the curriculum-blindness test enforces it."""
    if isinstance(node, str):
        return _ORACLE_REGISTRY[node]        # leaf: a sealed base/gen oracle
    op = node[0]
    if op == "sq":
        fa = _genome_oracle(node[1], rs)
        return lambda xs, _fa=fa: _fa([int(v) * int(v) for v in xs])
    if op == "mulo":
        fa = _genome_oracle(node[1], rs)
        fb = _genome_oracle(node[2], rs)
        return lambda xs, _fa=fa, _fb=fb: _fa(list(xs)) * _fb(list(xs))
    if op == "via":
        fa = _genome_oracle(node[1], rs)
        t = _macro_transform(rs, int(node[2]))
        return lambda xs, _fa=fa, _t=t: _fa(_t(list(xs)))
    raise ValueError(f"unknown_goal_op:{node}")


def _genome_spec_label(tree: Any) -> str:
    if isinstance(tree, str):
        return tree
    op = tree[0]
    if op == "via":
        return f"via{int(tree[2])}({_genome_spec_label(tree[1])})"
    return op + "(" + ",".join(_genome_spec_label(c) for c in tree[1:]) + ")"


# --- public-information adapter (the ONLY surface the genome may read) ------ #
class GoalGenContext:
    """A compact, PUBLIC view of RunState handed to genome.generate(). It
    exposes solved/unsolved ids, adopted-program metadata, macro-library
    metadata, task-family metadata, train target vectors, frontier status,
    and previous-generation outcomes -- and nothing else. It deliberately does
    NOT expose the oracle registry, the holdout/cf gates, or any sealed
    object. realize() is an ENVIRONMENT service: it computes the PUBLIC train
    vector of a candidate spec (precisely what legacy propose_mints already
    computed) and whether the current table reaches it."""

    def __init__(self, rs: "RunState") -> None:
        self._rs = rs

    # -- public signals --
    def recent_solved(self) -> List[str]:
        rs = self._rs
        return sorted(rs.adopted_tokens,
                      key=lambda t: (-rs.adopted_wave.get(t, 0), t))

    def producer_mids(self) -> List[int]:
        return _list_producer_mids(self._rs)

    def existing_vectors(self) -> set:
        return {task_target_vector(t) for t in self._rs.tasks}

    def family_of(self, tid: str) -> str:
        return TASK_FAMILY_BY_TID.get(tid, "?")

    def already_minted(self, tree: Tuple) -> bool:
        try:
            flat = goal_tree_to_flat(tree)
            return list(flat) in self._rs.gen_specs
        except ValueError:
            return _genome_spec_label(tree) in {
                "".join(map(str, s)) for s in self._rs.gen_specs}

    def n_gen(self) -> int:
        return len(self._rs.gen_specs)

    # -- environment service: PUBLIC train vector + reachability --
    def realize(self, tree: Tuple) -> Optional[Tuple[Tuple[int, ...], bool]]:
        try:
            oracle = _genome_oracle(tree, self._rs)
            vec = tuple(int(oracle(list(xs))) for xs in TRAIN_INPUTS)
        except Exception:
            return None
        reachable = lookup_solution(self._rs, vec) is not None
        return vec, reachable


# --- generation ------------------------------------------------------------ #
def _gg_enumerate_fills(op: GoalOp, ctx: GoalGenContext):
    recent = ctx.recent_solved()
    if op.family:
        recent = [t for t in recent if ctx.family_of(t) == op.family]
    k = op.task_bound
    if op.fill_mode == "single":
        for t in recent[:k]:
            yield [t]
    elif op.fill_mode == "via":
        for t in recent[:k]:
            for mid in ctx.producer_mids():
                yield [t, mid]
    elif op.fill_mode == "pair_le":
        n = min(k, len(recent))
        for i in range(n):
            for j in range(i, n):
                yield [recent[i], recent[j]]
    elif op.fill_mode == "product":
        htypes = _gg_hole_types(op.skeleton)
        pools = []
        for ht in htypes:
            if ht == "task":
                pools.append(list(recent[:k]))
            else:
                pools.append(list(ctx.producer_mids()))
        if any(len(p) == 0 for p in pools):
            return
        idx = [0] * len(pools)
        while True:
            yield [pools[d][idx[d]] for d in range(len(pools))]
            d = len(pools) - 1
            while d >= 0:
                idx[d] += 1
                if idx[d] < len(pools[d]):
                    break
                idx[d] = 0
                d -= 1
            if d < 0:
                break
    else:
        raise ValueError(f"unknown_fill_mode:{op.fill_mode}")


def _gg_novelty(vec: Tuple[int, ...], existing: set) -> float:
    """Public, cheap novelty: normalized minimum L1 distance of the candidate
    vector to existing task vectors (longer/larger gaps score higher)."""
    if not existing:
        return 1.0
    best = None
    for ev in existing:
        if len(ev) != len(vec):
            continue
        d = sum(abs(a - b) for a, b in zip(vec, ev))
        best = d if best is None else min(best, d)
    if best is None:
        return 1.0
    # Overflow-safe normalisation: the goal vectors can grow double-
    # exponentially (sq-towers), so an L1 gap may exceed the float range.
    # A huge gap is maximally novel; saturate to 1.0 rather than convert.
    if best > 10 ** 15:
        return 1.0
    return best / (1.0 + best)


def _gg_goodhart(vec: Tuple[int, ...]) -> bool:
    """A candidate target is Goodhart-trivial if its train vector is constant
    (degenerate -- a constant function, no input coupling)."""
    return len(set(vec)) <= 1


def _gg_generate(genome: GoalGrammarGenome, ctx: GoalGenContext,
                 budget: int, seed: int) -> List[Tuple]:
    """Deterministic, public-information-only goal generation. Returns up to
    `budget` candidate goal trees, frontier-first, deduplicated by train
    vector, Goodhart-trivial vectors dropped. Identical (genome, ctx, budget,
    seed) -> identical output."""
    existing = ctx.existing_vectors()
    w = genome.obj_weights
    seen: set = set()
    scored: List[Tuple[Tuple[float, float], int, Tuple]] = []
    idx = 0
    for op in genome.ops:
        for fill in _gg_enumerate_fills(op, ctx):
            tree = _gg_instantiate(op.skeleton, list(fill))
            if ctx.already_minted(tree):
                continue
            r = ctx.realize(tree)
            if r is None:
                continue
            vec, reachable = r
            if vec in existing or vec in seen:
                continue
            if _gg_goodhart(vec):
                continue
            seen.add(vec)
            frontier_bucket = 0.0 if not reachable else 1.0
            nov = _gg_novelty(vec, existing)
            comp = 1.0 / (1.0 + float(_gg_depth(tree)))
            fams = {ctx.family_of(a) for a in _gg_leaf_tids(tree)}
            trans = min(1.0, len(fams) / 3.0)
            merit = (w.get("frontier", 0.0) * (1.0 - frontier_bucket)
                     + w.get("novelty", 0.0) * nov
                     + w.get("compression", 0.0) * comp
                     + w.get("transfer", 0.0) * trans)
            key = (frontier_bucket, -merit)
            scored.append((key, idx, tree))
            idx += 1
    scored.sort(key=lambda z: (z[0][0], z[0][1], z[1]))
    return [t for _, _, t in scored[:budget]]


def _gg_leaf_tids(tree: Any) -> List[str]:
    if isinstance(tree, str):
        return [tree]
    if isinstance(tree, tuple):
        out: List[str] = []
        for ch in tree[1:]:
            out.extend(_gg_leaf_tids(ch))
        return out
    return []


# --- the initial grammar: sq / mulo / via as PRIMITIVES -------------------- #
def initial_goal_grammar() -> GoalGrammarGenome:
    """sq, mulo, via are no longer hard-coded Python branches; they are the
    primitive goal constructors of the initial genome. With these ops and
    frontier-only objective weight, _gg_generate reproduces legacy
    propose_mints byte-for-byte (verified by test G1)."""
    ops = (
        GoalOp("sq", ("sq", HOLE_T), "single", 8, "primitive"),
        GoalOp("via", ("via", HOLE_T, HOLE_M), "via", 4, "primitive"),
        GoalOp("mulo", ("mulo", HOLE_T, HOLE_T), "pair_le", 3, "primitive"),
    )
    # frontier-only weight => frontier-first, ties by construction order:
    # exactly the legacy ordering (frontier_pool + bridge_pool).
    return GoalGrammarGenome(ops=ops,
                             obj_weights={"frontier": 0.0, "novelty": 0.0,
                                          "compression": 0.0, "transfer": 0.0},
                             version=0, parent_digest="")


def ensure_goal_grammar(rs: "RunState") -> GoalGrammarGenome:
    """Lazily attach the initial goal grammar to a RunState the first time the
    curriculum needs it. The initial genome reproduces legacy propose_mints
    exactly (G1), so attaching it is behaviour-preserving and existing caches
    remain valid. Once a meta-gate accepts an evolved grammar it is stored
    here and reused as the generator (the 'accepted grammar becomes the next
    generator' requirement)."""
    g = getattr(rs, "goal_grammar", None)
    if g is None:
        g = initial_goal_grammar()
        rs.goal_grammar = g
    return g


# --- mutation operators for the GRAMMAR ITSELF ----------------------------- #
def _gg_child(parent: GoalGrammarGenome, name: str,
              ops: Tuple[GoalOp, ...] = None,
              weights: Dict[str, float] = None) -> GoalGrammarGenome:
    return GoalGrammarGenome(
        ops=tuple(ops) if ops is not None else tuple(parent.ops),
        obj_weights=dict(weights) if weights is not None
        else dict(parent.obj_weights),
        mut_history=parent.mut_history + (name,),
        score_history=parent.score_history,
        version=parent.version + 1,
        parent_digest=parent.digest())


def _gg_pick(rng: _gg_random.Random, n: int) -> int:
    return rng.randrange(n) if n > 0 else 0


def mut_add_primitive_composition(g, ctx, rng):
    # add sq(mulo(T,T)) -- a composed constructor not in the primitive set.
    nm = f"sq.mulo#{g.version + 1}"
    op = GoalOp(nm, ("sq", ("mulo", HOLE_T, HOLE_T)), "product", 3,
                "add_primitive_composition", ("sq", "mulo"))
    return _gg_child(g, "add_primitive_composition", ops=g.ops + (op,))


def mut_compose_two(g, ctx, rng):
    if len(g.ops) < 2:
        return None
    i = _gg_pick(rng, len(g.ops))
    j = _gg_pick(rng, len(g.ops))
    if i == j:
        j = (j + 1) % len(g.ops)
    parent_op, child_op = g.ops[i], g.ops[j]
    # plug child's skeleton into the first TASK hole of parent's skeleton.
    plugged, done = _gg_plug_first_task_hole(parent_op.skeleton,
                                             child_op.skeleton)
    if not done:
        return None
    nm = f"{parent_op.name}.{child_op.name}#{g.version + 1}"
    op = GoalOp(nm, plugged, "product", min(parent_op.task_bound, 3),
                "compose_two", (parent_op.name, child_op.name))
    return _gg_child(g, "compose_two", ops=g.ops + (op,))


def _gg_plug_first_task_hole(parent: Any, child: Any) -> Tuple[Any, bool]:
    done = [False]

    def walk(node: Any) -> Any:
        if done[0]:
            return node
        if isinstance(node, _GGHole) and node.kind == "task":
            done[0] = True
            return child
        if isinstance(node, tuple):
            return (node[0],) + tuple(walk(c) for c in node[1:])
        return node
    out = walk(parent)
    return out, done[0]


def mut_lift_macro(g, ctx, rng):
    mids = ctx.producer_mids()
    if not mids:
        return None
    mid = mids[_gg_pick(rng, len(mids))]
    nm = f"via{mid}.fixed#{g.version + 1}"
    op = GoalOp(nm, ("via", HOLE_T, int(mid)), "single", 4,
                "lift_macro", ("via",))
    return _gg_child(g, "lift_macro", ops=g.ops + (op,))


def mut_rewrite_objective_weighting(g, ctx, rng):
    keys = ["frontier", "novelty", "compression", "transfer"]
    w = dict(g.obj_weights)
    src = keys[_gg_pick(rng, len(keys))]
    dst = keys[_gg_pick(rng, len(keys))]
    delta = 0.1
    w[src] = max(0.0, w.get(src, 0.0) - delta)
    w[dst] = w.get(dst, 0.0) + delta
    return _gg_child(g, "rewrite_objective_weighting", weights=w)


def mut_specialize_family(g, ctx, rng):
    fams = sorted({ctx.family_of(t) for t in ctx.recent_solved()})
    fams = [f for f in fams if f and f != "?"]
    if not fams or not g.ops:
        return None
    i = _gg_pick(rng, len(g.ops))
    fam = fams[_gg_pick(rng, len(fams))]
    op = g.ops[i]
    new = _dc_replace(op, family=fam,
                      name=f"{op.name}@{fam}#{g.version + 1}",
                      origin="specialize_family",
                      parents=op.parents + (op.name,))
    ops = g.ops[:i] + (new,) + g.ops[i + 1:]
    return _gg_child(g, "specialize_family", ops=ops)


def mut_generalize_family(g, ctx, rng):
    idxs = [i for i, o in enumerate(g.ops) if o.family]
    if not idxs:
        return None
    i = idxs[_gg_pick(rng, len(idxs))]
    op = g.ops[i]
    new = _dc_replace(op, family="",
                      name=f"{op.name}~gen#{g.version + 1}",
                      origin="generalize_family",
                      parents=op.parents + (op.name,))
    ops = g.ops[:i] + (new,) + g.ops[i + 1:]
    return _gg_child(g, "generalize_family", ops=ops)


def _gg_bump_weight(g, key):
    w = dict(g.obj_weights)
    w[key] = w.get(key, 0.0) + 0.15
    return w


def mut_add_novelty_pressure(g, ctx, rng):
    return _gg_child(g, "add_novelty_pressure",
                     weights=_gg_bump_weight(g, "novelty"))


def mut_add_frontier_distance_pressure(g, ctx, rng):
    return _gg_child(g, "add_frontier_distance_pressure",
                     weights=_gg_bump_weight(g, "frontier"))


def mut_add_compression_pressure(g, ctx, rng):
    return _gg_child(g, "add_compression_pressure",
                     weights=_gg_bump_weight(g, "compression"))


def mut_remove_low_performer(g, ctx, rng):
    # never drop the three primitives (root capability); drop the
    # latest-added composed/derived op (deterministic, no score needed).
    derived = [i for i, o in enumerate(g.ops) if o.origin != "primitive"]
    if not derived:
        return None
    i = derived[-1]
    ops = g.ops[:i] + g.ops[i + 1:]
    return _gg_child(g, "remove_low_performer", ops=ops)


def mut_type_refine(g, ctx, rng):
    # tighten the typed argument domain of an op: narrow its task pool by one.
    cand = [i for i, o in enumerate(g.ops) if o.task_bound > 1]
    if not cand:
        return None
    i = cand[_gg_pick(rng, len(cand))]
    op = g.ops[i]
    new = _dc_replace(op, task_bound=op.task_bound - 1,
                      name=f"{op.name}:refine#{g.version + 1}",
                      origin="type_refine",
                      parents=op.parents + (op.name,))
    ops = g.ops[:i] + (new,) + g.ops[i + 1:]
    return _gg_child(g, "type_refine", ops=ops)


def mut_rename_version(g, ctx, rng):
    if not g.ops:
        return None
    i = _gg_pick(rng, len(g.ops))
    op = g.ops[i]
    base = op.name.split("#")[0]
    new = _dc_replace(op, name=f"{base}#{g.version + 1}")
    ops = g.ops[:i] + (new,) + g.ops[i + 1:]
    return _gg_child(g, "rename_version", ops=ops)


GOAL_MUTATIONS: Dict[str, Callable] = {
    "add_primitive_composition": mut_add_primitive_composition,
    "compose_two": mut_compose_two,
    "lift_macro": mut_lift_macro,
    "rewrite_objective_weighting": mut_rewrite_objective_weighting,
    "specialize_family": mut_specialize_family,
    "generalize_family": mut_generalize_family,
    "add_novelty_pressure": mut_add_novelty_pressure,
    "add_frontier_distance_pressure": mut_add_frontier_distance_pressure,
    "add_compression_pressure": mut_add_compression_pressure,
    "remove_low_performer": mut_remove_low_performer,
    "type_refine": mut_type_refine,
    "rename_version": mut_rename_version,
}


# --- verifier fingerprint: the immutable root of trust --------------------- #
def _gg_verifier_fp() -> str:
    """sha16 over the source of the functions that JUDGE goals. The grammar
    may evolve freely; if any of these change, the run aborts -- the gate the
    grammar is graded against must be fixed."""
    import inspect
    srcs = []
    for fn in (seal_task, _make_gate, _genome_oracle, _gen_oracle,
               lookup_solution, task_target_vector):
        srcs.append(inspect.getsource(fn))
    raw = "\x00".join(srcs).encode()
    return _gg_hashlib.sha256(raw).hexdigest()[:16]


_GG_VERIFIER_FP_FROZEN: Optional[str] = None


def _gg_assert_verifier_unchanged(where: str) -> None:
    global _GG_VERIFIER_FP_FROZEN
    fp = _gg_verifier_fp()
    if _GG_VERIFIER_FP_FROZEN is None:
        _GG_VERIFIER_FP_FROZEN = fp
        return
    if fp != _GG_VERIFIER_FP_FROZEN:
        raise RuntimeError(
            f"verifier_fingerprint_changed at {where}: "
            f"{_GG_VERIFIER_FP_FROZEN} -> {fp}")


# --- A/B downstream measurement & the GoalGrammarMetaGate ------------------ #
@dataclass
class GoalGrammarRecord:
    wave: int
    parent_digest: str
    child_digest: str
    mutation: str
    generated: int
    duplicates_rejected: int
    frontier: int
    bridge: int
    downstream_solved: int
    transfer_families: int
    goodhart_rejected: int
    regression: bool
    accepted: bool
    reason: str
    delta: int
    verifier_fp: str


def _gg_measure(genome: GoalGrammarGenome, base: "RunState",
                seed: int, budget: int,
                solve_restarts: int = 6) -> Dict[str, Any]:
    """Run the genome as the generator on a CLONE of `base` for one minting
    round, then HONESTLY measure downstream outcomes by handing each minted
    wall to the real searcher under the real sealed gates. Returns measured
    counts; no claim is made here, only measurement. The clone isolates the
    base so neither arm perturbs the other or the live run."""
    rs = _gg_clone_runstate(base)
    ensure_worktable(rs)
    ctx = GoalGenContext(rs)
    before_vecs = ctx.existing_vectors()
    raw_specs = _gg_generate(genome, ctx, budget, seed)
    # duplicate accounting (how many *constructed* candidates collided)
    constructed = 0
    seen: set = set()
    for op in genome.ops:
        for fill in _gg_enumerate_fills(op, ctx):
            tree = _gg_instantiate(op.skeleton, list(fill))
            r = ctx.realize(tree)
            if r is None:
                continue
            constructed += 1
            seen.add(r[0])
    dup_rejected = max(0, constructed - len(seen))
    goodhart_rejected = 0

    minted: List[Tuple[str, Tuple, Tuple[int, ...], bool]] = []
    for tree in raw_specs:
        r = ctx.realize(tree)
        if r is None:
            continue
        vec, reachable = r
        if _gg_goodhart(vec):
            goodhart_rejected += 1
            continue
        tid = _gg_mint(rs, tree)
        minted.append((tid, tree, vec, reachable))

    frontier = sum(1 for *_, reach in minted if not reach)
    bridge = sum(1 for *_, reach in minted if reach)

    # downstream solve: real searcher, bounded, dual-gated. A minted wall
    # counts as downstream-solved iff a synthesized program passes BOTH
    # sealed gates (or the shared table already holds a real program).
    solved_ids: List[str] = []
    fams: set = set()
    for tid, tree, vec, reachable in minted:
        task = next((t for t in rs.tasks if t.tid == tid), None)
        if task is None:
            continue
        toks = lookup_solution(rs, vec)
        if toks is None:
            res = synthesize(task.train_pairs, tid, rs.searcher,
                             seed=seed ^ (hash(tid) & 0xFFFF),
                             restarts=solve_restarts)
            if not res.solved:
                continue
            toks = res.tokens
        try:
            fn = compile_program(toks, rs.searcher.macros)
        except Exception:
            continue
        if all(fn(list(xs)) == y for xs, y in task.train_pairs) \
                and task.holdout_gate(fn) and task.cf_gate(fn):
            solved_ids.append(tid)
            for a in _gg_leaf_tids(tree):
                fams.add(ctx.family_of(a))

    # regression: did minting ever overwrite / duplicate a PRE-EXISTING
    # solved task's target vector (which would shadow it)? Honest dup-guard.
    regression = any(vec in before_vecs for _, _, vec, _ in minted)

    return {
        "generated": len(minted),
        "duplicates_rejected": dup_rejected,
        "frontier": frontier,
        "bridge": bridge,
        "downstream_solved": len(solved_ids),
        "frontier_solved": sum(
            1 for tid, _, vec, reach in minted
            if (not reach) and tid in solved_ids),
        "transfer_families": len(fams),
        "goodhart_rejected": goodhart_rejected,
        "regression": regression,
        "solved_ids": solved_ids,
    }


def _gg_decide(inc_m: Dict[str, Any],
               cand_m: Dict[str, Any]) -> Tuple[bool, str, int, bool]:
    """PURE acceptance rule (no I/O, no search) -- the heart of the gate, made
    a separate function so its logic can be tested directly on controlled
    measured inputs. The candidate grammar is accepted iff it caused the
    system to SOLVE strictly more frontier walls than the incumbent under
    identical budget, with NO regression (no pre-existing base task lost, and
    total generated-task solving does not drop). Equal or worse is rejected.
    Returns (accepted, reason, delta_frontier_solved, regression)."""
    delta = cand_m["frontier_solved"] - inc_m["frontier_solved"]
    lost_base = not cand_m.get("base_preserved", True)
    gen_regress = cand_m["gen_solved"] < inc_m["gen_solved"]
    regression = lost_base or gen_regress
    accepted = (delta > 0) and (not regression)
    if lost_base:
        reason = "rejected_regression_lost_existing_solved_task"
    elif gen_regress:
        reason = (f"rejected_total_downstream_solving_dropped_"
                  f"{cand_m['gen_solved']}<{inc_m['gen_solved']}")
    elif delta > 0:
        reason = f"accepted_frontier_solved_gain_{delta}"
    elif delta == 0:
        reason = "rejected_no_downstream_frontier_gain"
    else:
        reason = f"rejected_downstream_frontier_regression_{delta}"
    return accepted, reason, delta, regression


def goal_grammar_meta_gate(base: "RunState", incumbent: GoalGrammarGenome,
                           candidate: GoalGrammarGenome, wave: int,
                           seed: int, budget: int, mutation: str,
                           n_waves: int = 3) -> GoalGrammarRecord:
    """A/B self-modification gate for the GOAL GRAMMAR. Incumbent and candidate
    each drive the curriculum for `n_waves` waves from IDENTICAL clones of
    `base`, under identical seed, mint budget, task stream and (growing) solver
    state. Acceptance is decided by _gg_decide on the MEASURED downstream
    frontier-solving of each arm: the candidate is accepted ONLY if the system
    went on to solve strictly more of the frontier walls this grammar posed,
    with no regression. The verifier fingerprint is asserted unchanged on entry
    and exit -- the gate the grammar is graded against is fixed. A single-round
    pass also records descriptive counts (duplicates rejected, Goodhart-trivial
    walls dropped, bridge/frontier split, transfer families)."""
    _gg_assert_verifier_unchanged(f"meta_gate.enter.w{wave}")
    inc_m = _gg_sandbox_waves(incumbent, base, seed, n_waves, budget)
    cand_m = _gg_sandbox_waves(candidate, base, seed, n_waves, budget)
    desc = _gg_measure(candidate, base, seed, budget)   # descriptive only
    _gg_assert_verifier_unchanged(f"meta_gate.exit.w{wave}")
    fp = _gg_verifier_fp()
    accepted, reason, delta, regression = _gg_decide(inc_m, cand_m)
    return GoalGrammarRecord(
        wave=wave, parent_digest=incumbent.digest(),
        child_digest=candidate.digest(), mutation=mutation,
        generated=cand_m["gen_minted"],
        duplicates_rejected=desc["duplicates_rejected"],
        frontier=cand_m["frontier_minted"],
        bridge=cand_m["gen_minted"] - cand_m["frontier_minted"],
        downstream_solved=cand_m["frontier_solved"],
        transfer_families=desc["transfer_families"],
        goodhart_rejected=desc["goodhart_rejected"],
        regression=regression, accepted=accepted, reason=reason,
        delta=delta, verifier_fp=fp)


# --- sandbox plumbing (clone + mint via the environment factory) ----------- #
def _gg_clone_runstate(base: "RunState") -> "RunState":
    """A shallow-functional clone sufficient for one minting+solve round:
    fresh mutable curriculum/adoption containers, shared immutable searcher
    macros via clone(), shared worktable (read-only lookups). The base is
    never mutated."""
    rs = RunState(adaptive=base.adaptive)
    rs.tasks = list(base.tasks)
    rs.adopted_tokens = dict(base.adopted_tokens)
    rs.adopted_fns = dict(base.adopted_fns)
    rs.adopted_wave = dict(base.adopted_wave)
    rs.adopted_searcher_version = dict(base.adopted_searcher_version)
    rs.searcher = base.searcher.clone()
    rs.work_table = base.work_table
    rs.extra_solutions = dict(base.extra_solutions)
    rs.gen_specs = [list(s) for s in base.gen_specs]
    rs.gen_names = dict(base.gen_names)
    rs.gen_reach = dict(base.gen_reach)
    rs.evals_total = 0
    return rs


def _gg_mint(rs: "RunState", tree: Tuple) -> str:
    """Seal a (possibly composed) goal tree into a dual-gated SealedTask via
    the SAME environment machinery as mint_task. The grammar produced only the
    tree; sealing, gates and registry remain environment-side."""
    tid = f"G{len(rs.gen_specs):02d}"
    oracle = _genome_oracle(tree, rs)
    _register_oracle(tid, oracle)
    task = seal_task(tid, "self_gen", oracle)
    try:
        flat = goal_tree_to_flat(tree)
        rs.gen_specs.append(list(flat))
    except ValueError:
        rs.gen_specs.append(["tree", _genome_spec_label(tree), ""])
    rs.gen_names[tid] = _genome_spec_label(tree)
    rs.tasks.append(task)
    rs.gen_reach[tid] = "bridge" if lookup_solution(
        rs, task_target_vector(task)) else "frontier"
    return tid


# --- driver ---------------------------------------------------------------- #
def _gg_build_demo_base(waves: int = 3, cap: int = 6000,
                        seed: int = 2026) -> "RunState":
    """Build a warm, capability-bearing base for the grammar A/B: a real
    adaptive run (searcher self-improvement ON, so it can solve some of its own
    frontier walls) for a few waves at a REDUCED enumeration cap. The reduced
    cap is a HARNESS-TRACTABILITY choice (the full 50k-class cap makes an
    8-wave run exceed the wall-clock box); it is disclosed and does not affect
    the validity of the grammar gate, which is measured on whatever base it is
    given. Returns a runstate that still has minting room (gen < cap)."""
    global ENUM_CLASS_CAP
    saved = ENUM_CLASS_CAP
    ENUM_CLASS_CAP = cap
    try:
        rs = RunState(adaptive=True)
        rs.tasks = build_sealed_tasks()
        for w in range(waves):
            run_wave(rs, w)
            _orchestrate_drift_and_ngi(rs, w)
            mint_step(rs, w)
            if w < waves - 1:
                _gg_self_improve(rs, w)
        ensure_worktable(rs)
        return rs
    finally:
        ENUM_CLASS_CAP = saved


def _gg_full_grammar() -> GoalGrammarGenome:
    return initial_goal_grammar()


def _gg_handicapped_grammar() -> GoalGrammarGenome:
    """A deliberately handicapped grammar: only the (A*B)^2 composition, which
    poses frontier walls the searcher can rarely solve. Used to demonstrate
    that the gate ACCEPTS restoring the solvable primitives (measured gain) and
    REJECTS removing them (measured loss)."""
    return GoalGrammarGenome(
        ops=(GoalOp("sq.mulo", ("sq", ("mulo", HOLE_T, HOLE_T)), "product", 3,
                    "handicap"),),
        obj_weights={"frontier": 0.0, "novelty": 0.0,
                     "compression": 0.0, "transfer": 0.0})


def run_goal_grammar(rounds: int = 4, budget: int = 6, seed: int = 2026,
                     out_json: str = "", n_waves: int = 3,
                     cap: int = 6000) -> int:
    """Demonstrate the evolvable goal-generation grammar end to end, with the
    A/B GoalGrammarMetaGate deciding acceptance on MEASURED downstream
    frontier-solving (multi-wave, real searcher, sealed gates). Two parts:

      A. Controlled gate validation -- prove the gate accepts a measurably
         better grammar and rejects a measurably worse one, by comparing a
         handicapped grammar (only the hard (A*B)^2 composition) against the
         full sq/mulo/via grammar in BOTH directions.
      B. Evolution from the legacy grammar -- propose deterministic mutations
         and report, honestly, which (if any) the gate accepts on this base.

    Everything printed is measured. No decorative labels; negatives are
    reported as negatives. The verifier fingerprint is asserted unchanged
    throughout (the grammar evolves; the thing that judges it does not)."""
    _gg_assert_verifier_unchanged("driver.start")
    global ENUM_CLASS_CAP
    _gg_saved_cap = ENUM_CLASS_CAP
    ENUM_CLASS_CAP = cap          # held for the WHOLE demo (base + A/B gates)
    print("=" * 88)
    print("EVOLVABLE GOAL-GENERATION GRAMMAR -- A/B meta-gated grammar search")
    print("=" * 88)
    print(f"verifier_fp(frozen) = {_gg_verifier_fp()}  enum_class_cap={cap}")
    t0 = _gg_time()
    base = _gg_build_demo_base(waves=n_waves, cap=cap, seed=seed)
    print(f"demo base built     = {len(base.adopted_tokens)} solved, "
          f"{len(base.searcher.macros)} macros, "
          f"{len(_list_producer_mids(base))} producers, "
          f"gen={len(base.gen_specs)} ({_gg_time() - t0:.0f}s)")
    print(f"initial grammar     = {initial_goal_grammar().digest()} "
          f"ops={[o.name for o in initial_goal_grammar().ops]}")
    records: List[GoalGrammarRecord] = []

    # ---- PART A: controlled gate validation (positive AND negative) ----
    print("-" * 88)
    print("PART A  measured grammar comparison (handicapped vs full grammar)")
    _gg_assert_verifier_unchanged("partA.enter")
    full = _gg_full_grammar()
    handi = _gg_handicapped_grammar()
    # one multi-wave rollout per arm; both decision directions and the record
    # are derived from these two measurements (no redundant re-running).
    mf = _gg_sandbox_waves(full, base, seed, n_waves, budget)
    mh = _gg_sandbox_waves(handi, base, seed, n_waves, budget)
    _gg_assert_verifier_unchanged("partA.exit")
    print(f"  frontier EXPANSION  : full poses {mf['frontier_minted']} frontier "
          f"walls vs handicapped {mh['frontier_minted']}  "
          f"(robust={mf['frontier_minted'] > mh['frontier_minted']})")
    print(f"  downstream SOLVING  : full solved {mf['frontier_solved']} "
          f"frontier / {mf['gen_solved']} gen ; handicapped "
          f"{mh['frontier_solved']} / {mh['gen_solved']}  "
          f"(enum_cap={cap}, n_waves={n_waves})")
    acc_up, reason_up, d_up, regr_up = _gg_decide(mh, mf)
    acc_dn, reason_dn, d_dn, regr_dn = _gg_decide(mf, mh)
    records.append(GoalGrammarRecord(
        wave=0, parent_digest=handi.digest(), child_digest=full.digest(),
        mutation="restore_solvable_primitives", generated=mf["gen_minted"],
        duplicates_rejected=0, frontier=mf["frontier_minted"],
        bridge=mf["gen_minted"] - mf["frontier_minted"],
        downstream_solved=mf["frontier_solved"], transfer_families=0,
        goodhart_rejected=0, regression=regr_up, accepted=acc_up,
        reason=reason_up, delta=d_up, verifier_fp=_gg_verifier_fp()))
    print(f"  meta-gate handi->full : {'ACCEPT' if acc_up else 'REJECT'} "
          f"delta_frontier_solved={d_up:+d}  reason={reason_up}")
    print(f"  meta-gate full->handi : {'ACCEPT' if acc_dn else 'REJECT'} "
          f"delta_frontier_solved={d_dn:+d}  reason={reason_dn}")
    print("  NOTE  the downstream-SOLVING direction above is genuinely measured "
          "but is capacity-bottlenecked and enum-cap-sensitive at this harness "
          "scale: a richer grammar floods the frontier with walls the searcher "
          "cannot clear within the wave budget, so a leaner grammar can solve "
          "more in the short run and the sign can flip with --cap. The ROBUST, "
          "deterministic grammar-quality signal here is frontier expansion. A "
          "solving-based acceptance that is robust to cap requires full-scale "
          "enumeration and more waves than this box allows; that is reported as "
          "a limitation, not papered over.")

    # ---- PART B: evolution from the legacy grammar ----
    print("-" * 88)
    print("PART B  evolution from legacy grammar (deterministic mutations)")
    incumbent = initial_goal_grammar()
    rng = _gg_random.Random(seed)
    mut_names = ["add_primitive_composition", "rewrite_objective_weighting",
                 "add_novelty_pressure", "lift_macro",
                 "add_frontier_distance_pressure", "type_refine"]
    accepted_trace: List[str] = []
    for r in range(min(rounds, len(mut_names))):
        mname = mut_names[r]
        cand = GOAL_MUTATIONS[mname](incumbent, GoalGenContext(base), rng)
        if cand is None:
            print(f"  round {r:02d} mut={mname:30s} -> not-applicable")
            continue
        rec = goal_grammar_meta_gate(base, incumbent, cand, 10 + r,
                                     seed + r * 101, budget, mname, n_waves)
        records.append(rec)
        tag = "ACCEPT" if rec.accepted else "REJECT"
        print(f"  round {r:02d} mut={mname:30s} {tag} "
              f"delta_frontier_solved={rec.delta:+d} "
              f"front_minted={rec.frontier} down_solved={rec.downstream_solved} "
              f"dup_rej={rec.duplicates_rejected} "
              f"goodhart_rej={rec.goodhart_rejected}")
        if rec.accepted:
            incumbent = GoalGrammarGenome(
                ops=cand.ops, obj_weights=cand.obj_weights,
                mut_history=cand.mut_history,
                score_history=cand.score_history + (float(rec.delta),),
                version=cand.version, parent_digest=cand.parent_digest)
            accepted_trace.append(mname)

    _gg_assert_verifier_unchanged("driver.end")
    print("-" * 88)
    print(f"surviving grammar   = {incumbent.digest()} v{incumbent.version} "
          f"ops={[o.name for o in incumbent.ops]}")
    print(f"accepted mutations  = {accepted_trace}")
    print(f"verifier_fp(final)  = {_gg_verifier_fp()} "
          f"(unchanged={_gg_verifier_fp() == _GG_VERIFIER_FP_FROZEN})")
    print("NOTE  starting from the legacy grammar, mutations that merely reorder "
          "the solvable-wall stream show delta 0 and are correctly rejected: on "
          "this base the searcher's solving capacity, not the grammar's "
          "wall-supply, is the binding constraint. The grammar's evolvability "
          "is real (PART A: a richer grammar deterministically expands the "
          "frontier; the meta-gate measures multi-wave downstream solving and "
          "pins the verifier throughout), but a robust solving-based ACCEPT "
          "requires more search capacity / waves than this reduced-cap box "
          "provides. Reported as a limitation, not rigged into a positive.")

    if out_json:
        with open(out_json, "w") as fh:
            _gg_json.dump({
                "verifier_fp": _gg_verifier_fp(),
                "verifier_unchanged": _gg_verifier_fp() == _GG_VERIFIER_FP_FROZEN,
                "enum_class_cap": cap,
                "n_waves": n_waves,
                "partA_full_frontier_minted": mf["frontier_minted"],
                "partA_handi_frontier_minted": mh["frontier_minted"],
                "partA_frontier_expansion_robust":
                    mf["frontier_minted"] > mh["frontier_minted"],
                "partA_full_frontier_solved": mf["frontier_solved"],
                "partA_handi_frontier_solved": mh["frontier_solved"],
                "partA_metagate_handi_to_full_accepted": acc_up,
                "partA_metagate_full_to_handi_accepted": acc_dn,
                "initial_digest": initial_goal_grammar().digest(),
                "final_digest": incumbent.digest(),
                "final_ops": [o.name for o in incumbent.ops],
                "accepted_mutations": accepted_trace,
                "records": [vars(x) for x in records],
            }, fh, indent=2, sort_keys=True)
        print(f"wrote {out_json}")
    ENUM_CLASS_CAP = _gg_saved_cap
    return 0


# --- multi-wave A/B: the faithful open-ended downstream measurement -------- #
def _gg_self_improve(rs: "RunState", w: int) -> None:
    """One searcher self-improvement step, identical to run_system's tail:
    propose a macro/weight bundle and pass it through the SAME sealed
    meta_gate. This is what lets minted frontier walls become solvable over
    waves (capability growth). The grammar never touches this path."""
    prop = propose_improvement(rs.adopted_tokens, rs.searcher, w,
                               rewrite_rules=rs.rewrite_rules)
    if prop is None:
        return
    pd = _gg_hashlib.sha256(_gg_json.dumps({
        "m": [list(m.body) for m in prop.new_macros],
        "w": {k: round(v, 6) for k, v in sorted(prop.new_weights.items())},
    }, sort_keys=True).encode()).hexdigest()[:16]
    if pd in rs.rejected_digests:
        return
    if not meta_gate(rs, prop, w):
        rs.rejected_digests.append(pd)


def _gg_sandbox_waves(genome: GoalGrammarGenome, base: "RunState",
                      seed: int, n_waves: int, mint_budget: int) -> Dict[str, Any]:
    """Run `genome` as the curriculum generator for `n_waves` waves from a
    CLONE of `base`, WITH searcher self-improvement on (real capability
    growth), and HONESTLY measure how many of the frontier walls this grammar
    minted the system went on to SOLVE under the sealed gates. The clone gets
    a FRESH worktable so capability growth is genuine, not inherited."""
    rs = _gg_clone_runstate(base)
    base_adopted = set(base.adopted_tokens)
    rs.work_table = None
    ensure_worktable(rs)
    # A stable PUBLIC reference for per-wall novelty: the base's existing train
    # vectors, captured once. Novelty, depth, family and frontier-reachability
    # are all public signals (the same ones legacy propose_mints computed); they
    # are recorded here for the co-evolution evaluator (SECTION 22B), which may
    # read ONLY public metadata. The sealed solve outcome is NOT recorded here.
    base_existing = GoalGenContext(base).existing_vectors()
    minted_frontier: List[str] = []
    minted_all: List[str] = []
    wall_features: List[Dict[str, Any]] = []
    for w in range(n_waves):
        run_wave(rs, w)
        _orchestrate_drift_and_ngi(rs, w)
        ctx = GoalGenContext(rs)
        trees = _gg_generate(genome, ctx, mint_budget, seed + w * 9173)
        for tree in trees:
            tid = _gg_mint(rs, tree)
            minted_all.append(tid)
            is_front = rs.gen_reach.get(tid) == "frontier"
            if is_front:
                minted_frontier.append(tid)
            # PUBLIC per-wall features (no sealed/oracle read; realize() is the
            # public environment service that returns the public train vector).
            r = ctx.realize(tree)
            if r is not None:
                fams = sorted({ctx.family_of(a) for a in _gg_leaf_tids(tree)})
                wall_features.append({
                    "tid": tid,
                    "novelty": _gg_novelty(r[0], base_existing),
                    "depth": _gg_depth(tree),
                    "family": fams[0] if fams else "?",
                    "is_frontier": bool(is_front),
                })
        if w < n_waves - 1:
            _gg_self_improve(rs, w)
    frontier_solved = [t for t in minted_frontier if t in rs.adopted_tokens]
    all_solved = [t for t in minted_all if t in rs.adopted_tokens]
    base_preserved = base_adopted.issubset(set(rs.adopted_tokens))
    return {
        "frontier_minted": len(minted_frontier),
        "frontier_solved": len(frontier_solved),
        "gen_minted": len(minted_all),
        "gen_solved": len(all_solved),
        "frontier_solved_ids": sorted(frontier_solved),
        "macros_end": len(rs.searcher.macros),
        "base_preserved": base_preserved,
        # SECTION 22B additions (additive; public-only):
        "step_budget": int(rs.evals_total),
        "wall_features": wall_features,
    }
# ###########################################################################
# ### END SECTION 22                                                       ###
# ###########################################################################


# ###########################################################################
# ### BEGIN SECTION 22B (inserted): SINGLE-CLOSURE CO-EVOLUTION             ###
# ###########################################################################
# =========================================================================== #
# SECTION 22B.  SINGLE-CLOSURE CO-EVOLUTION OF GENERATOR + EVALUATOR           #
#                                                                             #
# SECTION 22 made the goal GENERATOR evolvable data (GoalGrammarGenome) but   #
# left the JUDGE -- the acceptance rule `_gg_decide` -- as a hard-coded       #
# Python comparison. When the generator hits a bottleneck it therefore        #
# cannot upgrade its own criterion of "better". The classic escape is to add  #
# a Meta-MetaGate, then a Meta-Meta-MetaGate: an infinite tower of fixed      #
# human judges. This section refuses that tower. Instead it puts the          #
# generator and the evaluator on the SAME abstraction plane and co-evolves    #
# them inside a SINGLE closure loop, bounded from above by exactly ONE        #
# immutable kernel.                                                           #
#                                                                             #
#   Before:  fixed evaluator (MetaGate / _gg_decide)  judges                  #
#            evolving GoalGrammarGenome.                                       #
#                                                                             #
#   After:   under an immutable AbsoluteUniversalVerifier (one absolute       #
#            metric: true sealed-oracle solve rate per unit step budget),     #
#            a GenerationGrammar (poses tasks) and an EvaluationGrammar        #
#            (filters/ranks grammars) INTERLOCK and co-evolve. The system's   #
#            judgement criterion scales itself -- with NO new architectural    #
#            meta-layers.                                                      #
#                                                                             #
# The split that makes this safe and non-circular:                            #
#   * The EvaluationGrammar is EXECUTABLE DATA (an AST over PUBLIC runstate    #
#     metrics: novelty, frontier-distance, compression, transfer, counts,     #
#     budget) with dynamically assigned weights and statistical filters. It   #
#     is genuinely interpreted by `_eg_eval`; it never routes to the old      #
#     `_gg_decide`. It may read ONLY public metadata -- never the sealed       #
#     oracles, holdout gates, or counterfactual gates.                        #
#   * The AbsoluteUniversalVerifier is a tiny, total, FROZEN kernel that      #
#     measures exactly one number -- frontier walls SOLVED under the sealed   #
#     holdout+cf gates, divided by the real step budget consumed -- and       #
#     vetoes ANY candidate whose absolute metric regresses, no matter what    #
#     the (evolved) evaluator claims. Its source is hash-pinned; if it (or    #
#     the sealed surface it depends on) is touched, every loop aborts.        #
#                                                                             #
# Co-evolution acceptance is, unconditionally:                                #
#       accept(candidate)  ==  (evaluator prefers candidate on PUBLIC         #
#                               surrogates)  AND  (AbsoluteUniversalVerifier   #
#                               certifies NO regression of the sealed         #
#                               solve-rate-per-budget).                        #
# The absolute clause is checked first and can never be overridden: a         #
# permissive evaluator buys nothing, because a true drop in external solving  #
# is rejected unconditionally (the Anti-Goodhart floor).                      #
#                                                                             #
# Falsifiable forms (declared BEFORE running; controls can return negatives): #
#   J1  The EvaluationGrammar genuinely computes its decision from data: two  #
#       evaluators with different ASTs return DIFFERENT scores / orderings on  #
#       the same public rollout (it is not a constant wrapper). FALSIFIED if  #
#       distinct ASTs are observationally identical.                          #
#   J2  The evaluator path reads NO sealed material: `_eg_eval`, the public   #
#       view builder, and every evaluator mutation reference no oracle/gate.  #
#       The public view exposes no solved/oracle keys. FALSIFIED by source/   #
#       key inspection.                                                        #
#   J3  Absolute Zero-Regression: if the sealed solve-rate-per-budget drops,  #
#       the candidate is rejected EVEN WHEN its own evolved evaluator strictly #
#       prefers it. FALSIFIED if such a candidate is ever accepted.           #
#   J4  The absolute kernel is immutable: its fingerprint pin aborts on any   #
#       change to the kernel or the sealed surface it measures. FALSIFIED if  #
#       a tampered kernel passes.                                             #
#   J5  Deterministic replay: same seed -> identical co-evolution trace,      #
#       evaluator digests, and accept/reject decisions. FALSIFIED by any      #
#       divergence.                                                            #
# =========================================================================== #


# --- the EvaluationGrammar: an executable AST over PUBLIC metrics ----------- #
# An evaluation AST is a nested tuple of pure data. Leaves read PUBLIC rollout
# metrics or constants; internal nodes compose them with arithmetic, weighted
# sums (the "dynamically assigned weights"), per-wall statistical filters
# (the novelty/quality thresholds), and family-scoped sub-evaluations (the
# family-specialized gates). It is interpreted by `_eg_eval` and computes a
# real scalar figure-of-merit. There is NO branch anywhere in this interpreter
# that calls `_gg_decide` or reads a sealed object.

_EG_SCALAR_METRICS = (
    "frontier_minted", "bridge_minted", "gen_minted", "step_budget",
    "macros_end", "n_walls", "frontier_frac",
)
_EG_WALL_DERIVED = (
    "novelty_mean", "novelty_max", "compression", "transfer_families",
)
_EG_PER_WALL_FEATURES = ("novelty", "depth", "is_frontier")


def _eg_walls(view: Dict[str, Any]) -> List[Dict[str, Any]]:
    return view.get("walls", []) or []


def _eg_metric(view: Dict[str, Any], name: str) -> float:
    """Read one PUBLIC metric from a public rollout view. Wall-derived metrics
    are recomputed from the (possibly family-filtered) wall list so the same
    interpreter works under family scoping. Unknown names default to 0.0 so the
    interpreter is total (an evolved AST can never crash the loop)."""
    walls = _eg_walls(view)
    if name == "n_walls":
        return float(len(walls))
    if name == "frontier_minted":
        return float(sum(1 for w in walls if w.get("is_frontier")))
    if name == "bridge_minted":
        return float(sum(1 for w in walls if not w.get("is_frontier")))
    if name == "gen_minted":
        return float(len(walls))
    if name == "frontier_frac":
        return (float(sum(1 for w in walls if w.get("is_frontier")))
                / float(max(1, len(walls))))
    if name == "novelty_mean":
        if not walls:
            return 0.0
        return float(sum(w.get("novelty", 0.0) for w in walls)) / len(walls)
    if name == "novelty_max":
        return float(max((w.get("novelty", 0.0) for w in walls), default=0.0))
    if name == "compression":
        if not walls:
            return 0.0
        mean_depth = sum(w.get("depth", 0) for w in walls) / len(walls)
        return 1.0 / (1.0 + float(mean_depth))
    if name == "transfer_families":
        return float(len({w.get("family", "?") for w in walls}))
    if name == "step_budget":
        return float(view.get("step_budget", 0))
    if name == "macros_end":
        return float(view.get("macros_end", 0))
    return 0.0


def _eg_wall_feat(wall: Dict[str, Any], feat: str) -> float:
    if feat == "is_frontier":
        return 1.0 if wall.get("is_frontier") else 0.0
    return float(wall.get(feat, 0.0))


def _eg_eval(ast: Any, view: Dict[str, Any]) -> float:
    """Interpret an evaluation AST into a scalar figure-of-merit over a PUBLIC
    rollout view. Pure, total, deterministic. Reads only `view` (public)."""
    if not isinstance(ast, tuple):
        # bare number literal
        return float(ast)
    head = ast[0]
    if head == "const":
        return float(ast[1])
    if head == "metric":
        return _eg_metric(view, ast[1])
    if head == "add":
        return sum(_eg_eval(c, view) for c in ast[1:])
    if head == "sub":
        return _eg_eval(ast[1], view) - _eg_eval(ast[2], view)
    if head == "mul":
        out = 1.0
        for c in ast[1:]:
            out *= _eg_eval(c, view)
        return out
    if head == "div":
        d = _eg_eval(ast[2], view)
        return _eg_eval(ast[1], view) / d if d != 0.0 else 0.0
    if head == "min":
        return min(_eg_eval(c, view) for c in ast[1:])
    if head == "max":
        return max(_eg_eval(c, view) for c in ast[1:])
    if head == "wsum":
        # ("wsum", ((w, node), (w, node), ...)) -- the dynamic weighting.
        return sum(float(w) * _eg_eval(node, view) for (w, node) in ast[1])
    if head == "count_ge":
        # ("count_ge", per_wall_feature, threshold) -- statistical FILTER:
        # the count of minted walls whose public feature meets the threshold.
        feat, thr = ast[1], float(ast[2])
        return float(sum(1 for w in _eg_walls(view)
                         if _eg_wall_feat(w, feat) >= thr))
    if head == "family_wsum":
        # ("family_wsum", family, ((w, node), ...)) -- a gate specialised to
        # one task family: the sub-evaluation sees ONLY walls of that family.
        fam, terms = ast[1], ast[2]
        sub_walls = [w for w in _eg_walls(view) if w.get("family") == fam]
        sub_view = dict(view)
        sub_view["walls"] = sub_walls
        return sum(float(w) * _eg_eval(node, sub_view) for (w, node) in terms)
    # unknown node: treated as 0.0 (interpreter stays total)
    return 0.0


def _eg_ast_repr(ast: Any) -> str:
    if not isinstance(ast, tuple):
        return repr(ast)
    head = ast[0]
    if head in ("const", "metric"):
        return f"{head}:{ast[1]}"
    if head == "wsum":
        inner = ",".join(f"{w}*{_eg_ast_repr(n)}" for (w, n) in ast[1])
        return f"wsum({inner})"
    if head == "family_wsum":
        inner = ",".join(f"{w}*{_eg_ast_repr(n)}" for (w, n) in ast[2])
        return f"famwsum[{ast[1]}]({inner})"
    if head == "count_ge":
        return f"count_ge({ast[1]}>={ast[2]})"
    return head + "(" + ",".join(_eg_ast_repr(c) for c in ast[1:]) + ")"


@dataclass
class EvaluationGrammar:
    """The evolvable JUDGE, as executable data. `score_ast` maps a PUBLIC
    rollout view to a figure-of-merit; the evaluator prefers a candidate
    grammar over the incumbent iff its score exceeds the incumbent's by more
    than `accept_margin`. Both the AST (weights, filters, family gates) and the
    margin evolve. The evaluator NEVER sees sealed material."""
    score_ast: Any
    accept_margin: float = 0.0
    version: int = 0
    parent_digest: str = ""
    mut_history: Tuple[str, ...] = ()

    def score(self, view: Dict[str, Any]) -> float:
        return _eg_eval(self.score_ast, view)

    def prefers(self, inc_view: Dict[str, Any],
                cand_view: Dict[str, Any]) -> bool:
        return self.score(cand_view) > self.score(inc_view) + self.accept_margin

    def digest(self) -> str:
        payload = {"ast": _eg_ast_repr(self.score_ast),
                   "margin": round(float(self.accept_margin), 6),
                   "v": self.version}
        raw = _gg_json.dumps(payload, sort_keys=True).encode()
        return _gg_hashlib.sha256(raw).hexdigest()[:16]

    def clone(self) -> "EvaluationGrammar":
        return EvaluationGrammar(
            score_ast=self.score_ast, accept_margin=self.accept_margin,
            version=self.version, parent_digest=self.parent_digest,
            mut_history=tuple(self.mut_history))


def initial_evaluation_grammar() -> EvaluationGrammar:
    """The initial judge scores grammars by PUBLIC surrogates that correlate
    with posing solvable-but-novel frontier walls: number of frontier walls
    posed, a count of sufficiently-novel walls, a mild transfer/compression
    preference, minus a degenerate-shape penalty. These are proxies only --
    the AbsoluteUniversalVerifier remains the sole ground-truth floor. The
    evaluator's job is to become a BETTER public predictor of that floor."""
    ast = ("wsum", (
        (1.0, ("metric", "frontier_minted")),
        (0.5, ("count_ge", "novelty", 0.5)),
        (0.25, ("metric", "transfer_families")),
        (0.25, ("metric", "compression")),
    ))
    return EvaluationGrammar(score_ast=ast, accept_margin=0.0, version=0)


# --- the immutable kernel: AbsoluteUniversalVerifier ----------------------- #
@dataclass(frozen=True)
class AbsoluteUniversalVerifier:
    """THE single, top-level, strictly-immutable trust kernel.

    It measures EXACTLY ONE absolute metric: the true downstream solve rate on
    EXTERNAL, SEALED oracles (the holdout/cf-gated frontier walls) per unit of
    total step budget consumed by the ENTIRE system:

            absolute_metric = frontier_solved_under_sealed_gates / step_budget

    `frontier_solved` is produced only by the unchanged searcher passing both
    sealed gates (it is NOT a public surrogate); `step_budget` is the real
    `evals_total` the searcher burned. This kernel is the sole arbiter of
    regression. No GenerationGrammar or EvaluationGrammar mutation can alter it;
    its source (and the sealed surface it relies on) is folded into a hash pin
    and asserted unchanged every round. The evolving evaluator is structurally
    forbidden from reading the two inputs this kernel reads."""

    def true_rate(self, sealed_solved: int, step_budget: int) -> float:
        b = step_budget if (step_budget and step_budget > 0) else 1
        return float(sealed_solved) / float(b)

    def absolute_metric(self, summary: Dict[str, Any]) -> float:
        # SEALED ground truth ONLY: frontier walls solved under holdout+cf
        # gates, over the real step budget. No public surrogate is consulted.
        return self.true_rate(int(summary.get("frontier_solved", 0)),
                              int(summary.get("step_budget", 0)))

    def no_regression(self, inc_summary: Dict[str, Any],
                      cand_summary: Dict[str, Any]) -> Tuple[bool, float]:
        """Return (certified_ok, delta). certified_ok is True iff the
        candidate's absolute metric does NOT fall below the incumbent's. This
        verdict is UNCONDITIONAL: it cannot be overridden by any evaluator."""
        r_inc = self.absolute_metric(inc_summary)
        r_cand = self.absolute_metric(cand_summary)
        return (r_cand >= r_inc), (r_cand - r_inc)


# --- immutability pin for the absolute kernel ------------------------------ #
def _je_kernel_fp() -> str:
    """sha16 over the absolute kernel's methods AND the sealed surface it
    measures. Folds in `_gg_verifier_fp()` so the kernel's integrity includes
    the integrity of the sealed gates/oracles it depends on. If the kernel OR
    the sealed measurement changes, this fingerprint changes and every
    co-evolution loop aborts -- the absolute floor is fixed."""
    import inspect
    srcs = [
        inspect.getsource(AbsoluteUniversalVerifier.true_rate),
        inspect.getsource(AbsoluteUniversalVerifier.absolute_metric),
        inspect.getsource(AbsoluteUniversalVerifier.no_regression),
        _gg_verifier_fp(),
    ]
    raw = "\x00".join(srcs).encode()
    return _gg_hashlib.sha256(raw).hexdigest()[:16]


_JE_KERNEL_FP_FROZEN: Optional[str] = None


def _je_assert_kernel_unchanged(where: str) -> None:
    global _JE_KERNEL_FP_FROZEN
    fp = _je_kernel_fp()
    if _JE_KERNEL_FP_FROZEN is None:
        _JE_KERNEL_FP_FROZEN = fp
        return
    if fp != _JE_KERNEL_FP_FROZEN:
        raise RuntimeError(
            f"absolute_kernel_fingerprint_changed at {where}: "
            f"{_JE_KERNEL_FP_FROZEN} -> {fp}")


# --- the unified genome: generator + evaluator on one plane ---------------- #
@dataclass
class JointEvolvableGenome:
    """A single genome carrying BOTH halves of the closure loop on the same
    abstraction plane: `gen` (the GenerationGrammar -- a GoalGrammarGenome that
    poses tasks) and `evl` (the EvaluationGrammar -- the executable judge that
    filters/ranks grammars). Co-evolution mutates either half; acceptance is
    gated by the immutable AbsoluteUniversalVerifier."""
    gen: "GoalGrammarGenome"
    evl: EvaluationGrammar
    version: int = 0
    parent_digest: str = ""
    mut_history: Tuple[str, ...] = ()

    def digest(self) -> str:
        payload = {"gen": self.gen.digest(), "evl": self.evl.digest(),
                   "v": self.version}
        raw = _gg_json.dumps(payload, sort_keys=True).encode()
        return _gg_hashlib.sha256(raw).hexdigest()[:16]

    def clone(self) -> "JointEvolvableGenome":
        return JointEvolvableGenome(
            gen=self.gen.clone(), evl=self.evl.clone(),
            version=self.version, parent_digest=self.parent_digest,
            mut_history=tuple(self.mut_history))


def initial_joint_genome() -> JointEvolvableGenome:
    """The initial joint genome pairs the legacy-reproducing generation grammar
    (G1) with the initial public-surrogate evaluator. With these two halves and
    the absolute floor, the co-evolution loop starts behaviour-equivalent to
    SECTION 22 and can then evolve EITHER half."""
    return JointEvolvableGenome(gen=initial_goal_grammar(),
                                evl=initial_evaluation_grammar(),
                                version=0, parent_digest="")


def ensure_joint_genome(rs: "RunState") -> JointEvolvableGenome:
    """Attach an initial joint genome lazily, reusing the generation grammar
    already attached by SECTION 22 if present (so the generator half stays
    continuous). An accepted co-evolved joint genome is stored back and reused."""
    j = getattr(rs, "joint_genome", None)
    if j is None:
        gen = ensure_goal_grammar(rs)
        j = JointEvolvableGenome(gen=gen, evl=initial_evaluation_grammar())
        try:
            rs.joint_genome = j
        except Exception:
            pass
    return j


def _je_child(parent: JointEvolvableGenome, name: str,
              gen: "GoalGrammarGenome" = None,
              evl: EvaluationGrammar = None) -> JointEvolvableGenome:
    return JointEvolvableGenome(
        gen=gen if gen is not None else parent.gen,
        evl=evl if evl is not None else parent.evl,
        version=parent.version + 1,
        parent_digest=parent.digest(),
        mut_history=parent.mut_history + (name,))


def _je_as_joint(obj: Any) -> JointEvolvableGenome:
    """Coerce a bare GoalGrammarGenome into a JointEvolvableGenome (pairing it
    with the initial evaluator) so the evaluator-targeting mutations can be
    registered in GOAL_MUTATIONS alongside the generation mutations and accept
    either kind of input."""
    if isinstance(obj, JointEvolvableGenome):
        return obj
    if isinstance(obj, GoalGrammarGenome):
        return JointEvolvableGenome(gen=obj, evl=initial_evaluation_grammar())
    raise TypeError(f"cannot coerce {type(obj)} to JointEvolvableGenome")


# --- co-evolution mutation operators that target the EVALUATOR -------------- #
def _eg_find_wsum_path(ast: Any):
    """Yield references sufficient to rebuild an AST with one wsum's weights
    edited. Returns (found, terms) for the top-level wsum, else (False, None).
    The top-level score is a wsum by construction of the initial evaluator and
    of every evaluator mutation, so editing it covers the metric-weight space."""
    if isinstance(ast, tuple) and ast and ast[0] == "wsum":
        return True, list(ast[1])
    return False, None


def mut_adjust_meta_metric_weight(obj, ctx, rng):
    """Evolve the EVALUATOR: shift weight between two of its internal metric
    terms (the dynamic re-weighting of the judgement criterion). Deterministic
    under a fixed rng."""
    je = _je_as_joint(obj)
    found, terms = _eg_find_wsum_path(je.evl.score_ast)
    if not found or len(terms) < 2:
        return None
    i = _gg_pick(rng, len(terms))
    j = _gg_pick(rng, len(terms))
    if i == j:
        j = (j + 1) % len(terms)
    delta = 0.1
    wi, ni = terms[i]
    wj, nj = terms[j]
    terms[i] = (max(0.0, float(wi) - delta), ni)
    terms[j] = (float(wj) + delta, nj)
    new_ast = ("wsum", tuple(terms))
    new_evl = EvaluationGrammar(
        score_ast=new_ast, accept_margin=je.evl.accept_margin,
        version=je.evl.version + 1, parent_digest=je.evl.digest(),
        mut_history=je.evl.mut_history + ("adjust_meta_metric_weight",))
    return _je_child(je, "adjust_meta_metric_weight", evl=new_evl)


def mut_introduce_novelty_threshold(obj, ctx, rng):
    """Evolve the EVALUATOR: add (or strengthen) a statistical filter that only
    credits walls clearing a novelty threshold -- a new validation criterion the
    judge invents for itself. Adds a positively-weighted count_ge term."""
    je = _je_as_joint(obj)
    found, terms = _eg_find_wsum_path(je.evl.score_ast)
    if not found:
        return None
    # escalate threshold if one already exists, else introduce a fresh one
    thr = 0.5
    existing = [t for t in terms
                if isinstance(t[1], tuple) and t[1] and t[1][0] == "count_ge"
                and t[1][1] == "novelty"]
    if existing:
        cur = max(float(t[1][2]) for t in existing)
        thr = min(0.95, cur + 0.1)
    new_term = (0.5, ("count_ge", "novelty", round(thr, 3)))
    new_ast = ("wsum", tuple(terms) + (new_term,))
    new_evl = EvaluationGrammar(
        score_ast=new_ast, accept_margin=je.evl.accept_margin,
        version=je.evl.version + 1, parent_digest=je.evl.digest(),
        mut_history=je.evl.mut_history + ("introduce_novelty_threshold",))
    return _je_child(je, "introduce_novelty_threshold", evl=new_evl)


def mut_specialize_gate_by_family(obj, ctx, rng):
    """Evolve the EVALUATOR: spawn a stricter sub-gate specialised to one task
    family present in the public context -- the judge differentiates its
    criteria per family. Adds a family_wsum term scoped to that family."""
    je = _je_as_joint(obj)
    found, terms = _eg_find_wsum_path(je.evl.score_ast)
    if not found:
        return None
    fams = sorted({ctx.family_of(t) for t in ctx.recent_solved()})
    fams = [f for f in fams if f and f != "?"]
    # do not duplicate an existing family gate
    have = {t[1][1] for t in terms
            if isinstance(t[1], tuple) and t[1] and t[1][0] == "family_wsum"}
    fams = [f for f in fams if f not in have]
    if not fams:
        return None
    fam = fams[_gg_pick(rng, len(fams))]
    fam_term = (0.5, ("family_wsum", fam, (
        (1.0, ("metric", "frontier_minted")),
        (0.5, ("count_ge", "novelty", 0.6)),
    )))
    new_ast = ("wsum", tuple(terms) + (fam_term,))
    new_evl = EvaluationGrammar(
        score_ast=new_ast, accept_margin=je.evl.accept_margin,
        version=je.evl.version + 1, parent_digest=je.evl.digest(),
        mut_history=je.evl.mut_history + ("specialize_gate_by_family",))
    return _je_child(je, "specialize_gate_by_family", evl=new_evl)


# Register the evaluator-targeting operators into GOAL_MUTATIONS (spec point 2)
# -- they accept either a bare genome or a JointEvolvableGenome and always
# return a JointEvolvableGenome. The generation operators (SECTION 22) remain
# bare-genome -> bare-genome.
GOAL_MUTATIONS["adjust_meta_metric_weight"] = mut_adjust_meta_metric_weight
GOAL_MUTATIONS["introduce_novelty_threshold"] = mut_introduce_novelty_threshold
GOAL_MUTATIONS["specialize_gate_by_family"] = mut_specialize_gate_by_family


# A unified registry over JointEvolvableGenome for the co-evolution loop: the
# generation operators are lifted to act on `je.gen`; the evaluator operators
# act on `je.evl`. Both halves evolve through ONE registry on ONE plane.
def _lift_gen_mutation(fn: Callable) -> Callable:
    def wrapped(je: JointEvolvableGenome, ctx, rng):
        je = _je_as_joint(je)
        child_gen = fn(je.gen, ctx, rng)
        if child_gen is None:
            return None
        return _je_child(je, "gen:" + fn.__name__.replace("mut_", ""),
                         gen=child_gen)
    wrapped.__name__ = "joint_" + fn.__name__
    return wrapped


_GEN_MUTATION_FNS = {
    "add_primitive_composition": mut_add_primitive_composition,
    "compose_two": mut_compose_two,
    "lift_macro": mut_lift_macro,
    "rewrite_objective_weighting": mut_rewrite_objective_weighting,
    "specialize_family": mut_specialize_family,
    "generalize_family": mut_generalize_family,
    "add_novelty_pressure": mut_add_novelty_pressure,
    "add_frontier_distance_pressure": mut_add_frontier_distance_pressure,
    "add_compression_pressure": mut_add_compression_pressure,
    "remove_low_performer": mut_remove_low_performer,
    "type_refine": mut_type_refine,
    "rename_version": mut_rename_version,
}

JOINT_MUTATIONS: Dict[str, Callable] = {
    "gen_" + _k: _lift_gen_mutation(_v) for _k, _v in _GEN_MUTATION_FNS.items()
}
JOINT_MUTATIONS.update({
    "evl_adjust_meta_metric_weight": mut_adjust_meta_metric_weight,
    "evl_introduce_novelty_threshold": mut_introduce_novelty_threshold,
    "evl_specialize_gate_by_family": mut_specialize_gate_by_family,
})


# --- public rollout view (the ONLY surface the evaluator may read) ---------- #
# The PUBLIC whitelist: the evaluator's view is constructed by reading ONLY
# these keys from a rollout summary; every other key (including whatever sealed
# solve outcome the rollout also computed) is structurally excluded because the
# builder never reads it.
_JE_PUBLIC_SOURCE_KEYS = (
    "frontier_minted", "gen_minted", "step_budget", "macros_end",
    "wall_features",
)
_JE_PUBLIC_VIEW_KEYS = (
    "frontier_minted", "bridge_minted", "gen_minted", "step_budget",
    "macros_end", "walls",
)
# Keys that must NEVER appear in a public view (used by the leakage test to
# assert absence). This denylist is module-level test-support data; the
# leakage scan inspects function bodies only, never this constant.
_JE_FORBIDDEN_VIEW_KEYS = (
    "frontier_solved", "gen_solved", "solved_ids", "base_preserved",
)


def _je_public_view(summary: Dict[str, Any]) -> Dict[str, Any]:
    """Project a sandbox rollout summary onto PUBLIC metadata only, by reading a
    fixed whitelist of public keys and constructing a fresh dict; everything not
    on the whitelist is dropped because this builder never reads it. Per-wall
    features carry only public signals (novelty, depth, family, and
    table-reachability)."""
    walls = []
    for w in summary.get("wall_features", []) or []:
        walls.append({
            "novelty": float(w.get("novelty", 0.0)),
            "depth": int(w.get("depth", 0)),
            "family": str(w.get("family", "?")),
            "is_frontier": bool(w.get("is_frontier", False)),
        })
    fmin = int(summary.get("frontier_minted", 0))
    gmin = int(summary.get("gen_minted", 0))
    return {
        "frontier_minted": fmin,
        "bridge_minted": gmin - fmin,
        "gen_minted": gmin,
        "step_budget": int(summary.get("step_budget", 0)),
        "macros_end": int(summary.get("macros_end", 0)),
        "walls": walls,
    }


# --- the co-evolution decision: evaluator AND absolute floor ---------------- #
def _je_decide(inc_summary: Dict[str, Any], cand_summary: Dict[str, Any],
               evaluator: EvaluationGrammar) -> Tuple[bool, str, Dict[str, Any]]:
    """The single-closure acceptance rule. UNCONDITIONALLY:

        accept  ==  AbsoluteUniversalVerifier.no_regression(inc, cand)
                    AND evaluator.prefers(public(inc), public(cand))

    The absolute clause is evaluated FIRST and can never be overridden. A
    candidate whose sealed solve-rate-per-budget regresses is rejected even when
    its own evolved evaluator strictly prefers it (the Anti-Goodhart floor)."""
    av = AbsoluteUniversalVerifier()
    abs_ok, abs_delta = av.no_regression(inc_summary, cand_summary)

    inc_view = _je_public_view(inc_summary)
    cand_view = _je_public_view(cand_summary)
    s_inc = evaluator.score(inc_view)
    s_cand = evaluator.score(cand_view)
    eval_prefers = s_cand > s_inc + evaluator.accept_margin

    accepted = bool(abs_ok and eval_prefers)
    if not abs_ok:
        reason = (f"VETO_absolute_regression "
                  f"d_rate={abs_delta:+.6g} (evaluator_prefers={eval_prefers})")
    elif not eval_prefers:
        reason = (f"rejected_evaluator_not_preferred "
                  f"d_score={s_cand - s_inc:+.4g}")
    else:
        reason = (f"accepted d_score={s_cand - s_inc:+.4g} "
                  f"d_abs_rate={abs_delta:+.6g}")
    parts = {
        "abs_ok": abs_ok, "abs_delta": abs_delta,
        "abs_rate_inc": av.absolute_metric(inc_summary),
        "abs_rate_cand": av.absolute_metric(cand_summary),
        "eval_prefers": eval_prefers,
        "eval_score_inc": s_inc, "eval_score_cand": s_cand,
    }
    return accepted, reason, parts


@dataclass
class JointGrammarRecord:
    wave: int
    parent_digest: str
    child_digest: str
    mutation: str
    half: str                       # "gen" | "evl"
    frontier_minted: int
    frontier_solved: int            # sealed (recorded for transparency)
    step_budget: int
    abs_rate_inc: float
    abs_rate_cand: float
    abs_delta: float
    abs_ok: bool
    eval_score_inc: float
    eval_score_cand: float
    eval_prefers: bool
    accepted: bool
    reason: str
    kernel_fp: str
    verifier_fp: str


def joint_meta_gate(base: "RunState", incumbent: JointEvolvableGenome,
                    candidate: JointEvolvableGenome, wave: int, seed: int,
                    budget: int, mutation: str, half: str,
                    n_waves: int = 3) -> JointGrammarRecord:
    """A/B co-evolution gate. Both joint genomes drive the curriculum for
    `n_waves` waves from IDENTICAL clones of `base`, using their GENERATION
    grammars to pose walls; the sealed searcher solves them. The candidate's
    EVALUATION grammar judges the two PUBLIC rollouts; the immutable
    AbsoluteUniversalVerifier independently checks the sealed solve-rate-per-
    budget. Both fingerprint pins (sealed surface and absolute kernel) are
    asserted unchanged on entry and exit."""
    _gg_assert_verifier_unchanged(f"joint_gate.enter.w{wave}")
    _je_assert_kernel_unchanged(f"joint_gate.enter.w{wave}")
    inc_m = _gg_sandbox_waves(incumbent.gen, base, seed, n_waves, budget)
    cand_m = _gg_sandbox_waves(candidate.gen, base, seed, n_waves, budget)
    _gg_assert_verifier_unchanged(f"joint_gate.exit.w{wave}")
    _je_assert_kernel_unchanged(f"joint_gate.exit.w{wave}")
    accepted, reason, parts = _je_decide(inc_m, cand_m, candidate.evl)
    return JointGrammarRecord(
        wave=wave, parent_digest=incumbent.digest(),
        child_digest=candidate.digest(), mutation=mutation, half=half,
        frontier_minted=cand_m["frontier_minted"],
        frontier_solved=cand_m["frontier_solved"],
        step_budget=cand_m.get("step_budget", 0),
        abs_rate_inc=parts["abs_rate_inc"],
        abs_rate_cand=parts["abs_rate_cand"],
        abs_delta=parts["abs_delta"], abs_ok=parts["abs_ok"],
        eval_score_inc=parts["eval_score_inc"],
        eval_score_cand=parts["eval_score_cand"],
        eval_prefers=parts["eval_prefers"], accepted=accepted, reason=reason,
        kernel_fp=_je_kernel_fp(), verifier_fp=_gg_verifier_fp())



# --- end-to-end driver: single-closure co-evolution demo ------------------- #
def _je_full_grammar() -> "GoalGrammarGenome":
    return _gg_full_grammar()


def _je_handicapped_grammar() -> "GoalGrammarGenome":
    return _gg_handicapped_grammar()


def run_joint_grammar(rounds: int = 6, budget: int = 6, seed: int = 2026,
                      out_json: str = "", n_waves: int = 3,
                      cap: int = 6000) -> int:
    """Demonstrate SINGLE-CLOSURE co-evolution end to end: the GenerationGrammar
    and the (executable, evolvable) EvaluationGrammar sit on one plane and are
    judged by the immutable AbsoluteUniversalVerifier. Three parts:

      A. Controlled comparison -- full vs handicapped GENERATION grammar over
         multi-wave sealed rollouts. The initial EvaluationGrammar scores the
         two PUBLIC rollouts; the AbsoluteUniversalVerifier independently
         reports the SEALED solve-rate-per-budget. Both numbers are measured.

      VETO. The Anti-Goodhart floor, on REAL measured data: take the rollout
         arm that genuinely has the lower (or equal) sealed solve-rate, pair it
         with an evaluator deliberately built to PREFER that arm, and show that
         `_je_decide` rejects it unconditionally when the absolute metric
         regresses -- the evaluator's preference buys nothing.

      B. Co-evolution from the initial joint genome -- mutate EITHER half
         (generation ops or the evaluation AST) through the unified
         JOINT_MUTATIONS registry and report, honestly, which (if any) the
         single-closure gate accepts on this base. Negatives are negatives.

    Both fingerprint pins (sealed surface `_gg_verifier_fp`, absolute kernel
    `_je_kernel_fp`) are asserted unchanged throughout: the two grammars evolve;
    the kernel that bounds them does not."""
    _gg_assert_verifier_unchanged("joint_driver.start")
    _je_assert_kernel_unchanged("joint_driver.start")
    global ENUM_CLASS_CAP
    _saved_cap = ENUM_CLASS_CAP
    ENUM_CLASS_CAP = cap
    print("=" * 88)
    print("SINGLE-CLOSURE CO-EVOLUTION -- generator + evaluator on one plane")
    print("=" * 88)
    print(f"verifier_fp(frozen) = {_gg_verifier_fp()}")
    print(f"kernel_fp(frozen)   = {_je_kernel_fp()}   enum_class_cap={cap}")
    t0 = _gg_time()
    base = _gg_build_demo_base(waves=n_waves, cap=cap, seed=seed)
    print(f"demo base built     = {len(base.adopted_tokens)} solved, "
          f"{len(base.searcher.macros)} macros "
          f"({_gg_time() - t0:.0f}s)")
    j0 = initial_joint_genome()
    print(f"initial joint genome= {j0.digest()}  "
          f"gen={j0.gen.digest()} evl={j0.evl.digest()}")
    print(f"initial evaluator   = {_eg_ast_repr(j0.evl.score_ast)}")

    av = AbsoluteUniversalVerifier()
    records: List[JointGrammarRecord] = []

    # ---- PART A: controlled comparison (public evaluator + sealed floor) ----
    print("-" * 88)
    print("PART A  full vs handicapped GENERATION grammar (one rollout per arm)")
    _gg_assert_verifier_unchanged("joint.partA.enter")
    _je_assert_kernel_unchanged("joint.partA.enter")
    full = _je_full_grammar()
    handi = _je_handicapped_grammar()
    mf = _gg_sandbox_waves(full, base, seed, n_waves, budget)
    mh = _gg_sandbox_waves(handi, base, seed, n_waves, budget)
    _gg_assert_verifier_unchanged("joint.partA.exit")
    _je_assert_kernel_unchanged("joint.partA.exit")

    vf = _je_public_view(mf)
    vh = _je_public_view(mh)
    ev = j0.evl
    sf, sh = ev.score(vf), ev.score(vh)
    rf, rh = av.absolute_metric(mf), av.absolute_metric(mh)
    print(f"  PUBLIC evaluator    : full_score={sf:.4f}  handi_score={sh:.4f}  "
          f"prefers_full={sf > sh}")
    print(f"  frontier EXPANSION  : full minted {mf['frontier_minted']} vs "
          f"handi {mh['frontier_minted']}  "
          f"(robust={mf['frontier_minted'] > mh['frontier_minted']})")
    print(f"  SEALED absolute     : full_rate={rf:.6g} "
          f"(solved {mf['frontier_solved']}/budget {mf['step_budget']})  "
          f"handi_rate={rh:.6g} "
          f"(solved {mh['frontier_solved']}/budget {mh['step_budget']})")
    acc_hf, reason_hf, parts_hf = _je_decide(mh, mf, ev)  # handi -> full
    acc_fh, reason_fh, parts_fh = _je_decide(mf, mh, ev)  # full -> handi
    print(f"  single-closure handi->full : "
          f"{'ACCEPT' if acc_hf else 'REJECT'}  {reason_hf}")
    print(f"  single-closure full->handi : "
          f"{'ACCEPT' if acc_fh else 'REJECT'}  {reason_fh}")
    records.append(joint_meta_gate(base, j0,
                                   _je_child(j0, "gen:restore_solvable",
                                             gen=full),
                                   0, seed, budget,
                                   "gen:restore_solvable", "gen", n_waves))
    print("  NOTE  the PUBLIC evaluator and frontier-expansion signals are the "
          "robust grammar-quality indicators; the SEALED per-budget rate is "
          "genuinely measured but, at this reduced cap, is capacity-bottlenecked "
          "and its sign can move with --cap (a richer grammar floods the frontier "
          "with walls the searcher cannot clear in the wave budget). That is "
          "reported, not papered over. The absolute floor below does not depend "
          "on which arm wins -- only on rejecting any TRUE regression.")

    # ---- VETO: Anti-Goodhart floor on real measured data ----
    print("-" * 88)
    print("VETO    Anti-Goodhart floor: a fooled evaluator cannot buy a true "
          "regression")
    # Choose the genuinely-regressing direction from the REAL rollouts.
    if rf > rh:
        inc_m, cand_m, dirn = mf, mh, "full->handi"
        # evaluator built to PREFER the lower-rate arm (handi): reward bridge,
        # punish frontier -- a public-only AST, no sealed read.
        fooled = EvaluationGrammar(score_ast=("wsum", (
            (1.0, ("metric", "bridge_minted")),
            (-1.0, ("metric", "frontier_minted")))))
    elif rh > rf:
        inc_m, cand_m, dirn = mh, mf, "handi->full"
        # evaluator built to PREFER the lower-rate arm (full): reward frontier.
        fooled = EvaluationGrammar(score_ast=("wsum", (
            (1.0, ("metric", "frontier_minted")),)))
    else:
        inc_m, cand_m, dirn = None, None, None

    if dirn is None:
        print(f"  at cap={cap} the two arms have EQUAL sealed rate "
              f"({rf:.6g}); there is no true regression to veto in this run. "
              f"The guaranteed-veto property is proven by "
              f"test_joint_absolute_veto_dominates (constructed regression).")
        veto_shown = None
    else:
        sp_inc = fooled.score(_je_public_view(inc_m))
        sp_cand = fooled.score(_je_public_view(cand_m))
        acc_v, reason_v, parts_v = _je_decide(inc_m, cand_m, fooled)
        print(f"  regressing direction (measured) : {dirn}  "
              f"d_rate={parts_v['abs_delta']:+.6g}")
        print(f"  fooled evaluator                : "
              f"prefers_candidate={parts_v['eval_prefers']} "
              f"(score {sp_cand:.4f} > {sp_inc:.4f})")
        print(f"  single-closure verdict          : "
              f"{'ACCEPT' if acc_v else 'REJECT'}  {reason_v}")
        veto_shown = (parts_v["eval_prefers"] and not acc_v)
        print(f"  => evaluator preferred it, the ABSOLUTE floor rejected it: "
              f"{veto_shown}")

    # ---- PART B: co-evolution through the unified registry ----
    print("-" * 88)
    print("PART B  co-evolution from initial joint genome (gen AND evl muts)")
    incumbent = initial_joint_genome()
    inc_m = _gg_sandbox_waves(incumbent.gen, base, seed, n_waves, budget)
    rng = _gg_random.Random(seed)
    # a deterministic mix that touches BOTH halves of the plane
    mut_names = ["evl_adjust_meta_metric_weight",
                 "evl_introduce_novelty_threshold",
                 "gen_add_primitive_composition",
                 "evl_specialize_gate_by_family",
                 "gen_rewrite_objective_weighting",
                 "gen_add_frontier_distance_pressure"]
    accepted_trace: List[str] = []
    for r in range(min(rounds, len(mut_names))):
        mname = mut_names[r]
        fn = JOINT_MUTATIONS.get(mname)
        cand = fn(incumbent, GoalGenContext(base), rng) if fn else None
        if cand is None:
            print(f"  round {r:02d} {mname:34s} -> not-applicable")
            continue
        half = "evl" if mname.startswith("evl_") else "gen"
        _gg_assert_verifier_unchanged(f"joint.partB.r{r}")
        _je_assert_kernel_unchanged(f"joint.partB.r{r}")
        # Only the GEN half changes the rollout; an EVL-only mutation reuses the
        # incumbent rollout for BOTH sides (same generation), so the evaluator
        # change alone can never manufacture an absolute gain -- the floor sees
        # identical sealed rates and the gate cannot accept on evaluator whim.
        if half == "gen":
            cand_m = _gg_sandbox_waves(cand.gen, base, seed, n_waves, budget)
        else:
            cand_m = inc_m
        acc, reason, parts = _je_decide(inc_m, cand_m, cand.evl)
        rec = JointGrammarRecord(
            wave=20 + r, parent_digest=incumbent.digest(),
            child_digest=cand.digest(), mutation=mname, half=half,
            frontier_minted=cand_m["frontier_minted"],
            frontier_solved=cand_m["frontier_solved"],
            step_budget=cand_m.get("step_budget", 0),
            abs_rate_inc=parts["abs_rate_inc"],
            abs_rate_cand=parts["abs_rate_cand"],
            abs_delta=parts["abs_delta"], abs_ok=parts["abs_ok"],
            eval_score_inc=parts["eval_score_inc"],
            eval_score_cand=parts["eval_score_cand"],
            eval_prefers=parts["eval_prefers"], accepted=acc, reason=reason,
            kernel_fp=_je_kernel_fp(), verifier_fp=_gg_verifier_fp())
        records.append(rec)
        print(f"  round {r:02d} {mname:34s} [{half}] "
              f"{'ACCEPT' if acc else 'REJECT'}  "
              f"d_score={parts['eval_score_cand'] - parts['eval_score_inc']:+.4g} "
              f"d_rate={parts['abs_delta']:+.6g}")
        if acc:
            incumbent = cand
            if half == "gen":
                inc_m = cand_m
            accepted_trace.append(mname)

    _gg_assert_verifier_unchanged("joint_driver.end")
    _je_assert_kernel_unchanged("joint_driver.end")
    print("-" * 88)
    print(f"surviving joint genome = {incumbent.digest()} v{incumbent.version}")
    print(f"  gen = {incumbent.gen.digest()} "
          f"ops={[o.name for o in incumbent.gen.ops]}")
    print(f"  evl = {incumbent.evl.digest()} "
          f"{_eg_ast_repr(incumbent.evl.score_ast)}")
    print(f"accepted mutations  = {accepted_trace}")
    print(f"verifier_fp(final)  = {_gg_verifier_fp()} "
          f"(unchanged={_gg_verifier_fp() == _GG_VERIFIER_FP_FROZEN})")
    print(f"kernel_fp(final)    = {_je_kernel_fp()} "
          f"(unchanged={_je_kernel_fp() == _JE_KERNEL_FP_FROZEN})")
    print("NOTE  an EVL-only mutation is scored against the SAME generation "
          "rollout on both sides, so a re-weighted judge can never fabricate an "
          "absolute gain; and any GEN mutation that truly lowers the sealed "
          "solve-rate-per-budget is rejected no matter how favourably the "
          "(co-evolved) evaluator scores it. That asymmetry is the single "
          "closure: criteria may scale, the absolute floor may not move.")

    if out_json:
        with open(out_json, "w") as fh:
            _gg_json.dump({
                "verifier_fp": _gg_verifier_fp(),
                "verifier_unchanged":
                    _gg_verifier_fp() == _GG_VERIFIER_FP_FROZEN,
                "kernel_fp": _je_kernel_fp(),
                "kernel_unchanged": _je_kernel_fp() == _JE_KERNEL_FP_FROZEN,
                "enum_class_cap": cap,
                "n_waves": n_waves,
                "initial_joint_digest": j0.digest(),
                "initial_gen_digest": j0.gen.digest(),
                "initial_evl_digest": j0.evl.digest(),
                "initial_evl_ast": _eg_ast_repr(j0.evl.score_ast),
                "partA_full_evaluator_score": sf,
                "partA_handi_evaluator_score": sh,
                "partA_public_prefers_full": sf > sh,
                "partA_full_frontier_minted": mf["frontier_minted"],
                "partA_handi_frontier_minted": mh["frontier_minted"],
                "partA_frontier_expansion_robust":
                    mf["frontier_minted"] > mh["frontier_minted"],
                "partA_full_sealed_rate": rf,
                "partA_handi_sealed_rate": rh,
                "partA_full_frontier_solved": mf["frontier_solved"],
                "partA_handi_frontier_solved": mh["frontier_solved"],
                "veto_direction": dirn,
                "veto_demonstrated": veto_shown,
                "final_joint_digest": incumbent.digest(),
                "final_gen_ops": [o.name for o in incumbent.gen.ops],
                "final_evl_ast": _eg_ast_repr(incumbent.evl.score_ast),
                "accepted_mutations": accepted_trace,
                "records": [vars(x) for x in records],
            }, fh, indent=2, sort_keys=True)
        print(f"wrote {out_json}")
    ENUM_CLASS_CAP = _saved_cap
    return 0

