# --- SECTION 22 tests: evolvable goal-generation grammar (spec point 9) ----- #
# Registered into the global TESTS list below. Naming/▒style mirror the
# existing suite (no-arg functions, _assert). The expensive end-to-end gate
# test is bounded (two multi-wave arms at a reduced enumeration cap).

def test_grammar_sq_mulo_via_not_hardcoded() -> None:
    """The goal grammar must be DATA, not Python: propose_mints no longer
    contains the literal sq / mulo / via branches it used to."""
    import inspect
    src = inspect.getsource(propose_mints)
    _assert('("sq", t,' not in src and "('sq', t," not in src,
            "propose_mints still hard-codes an sq branch")
    _assert('("mulo", solved' not in src and "('mulo', solved" not in src,
            "propose_mints still hard-codes a mulo branch")
    _assert('f"via{mid}"' not in src and "f'via{mid}'" not in src,
            "propose_mints still hard-codes a via branch")
    # and the constructors now live in the genome as primitives:
    ops = {o.name: o for o in initial_goal_grammar().ops}
    _assert(set(ops) == {"sq", "via", "mulo"},
            f"initial grammar primitives wrong: {sorted(ops)}")
    _assert(all(o.origin == "primitive" for o in ops.values()),
            "sq/mulo/via must be PRIMITIVE ops of the initial genome")


def test_grammar_G1_reproduces_legacy() -> None:
    """The initial genome reproduces the historical generator: on a real base
    every emitted spec is a depth-1 sq/mulo/via spec (the legacy vocabulary),
    and generation is byte-identical to propose_mints' own output."""
    rs = build_frozen()
    ensure_worktable(rs)
    legacy_heads = set()
    for w in (3, 5, 7, 11):
        out = propose_mints(rs, w)
        for spec in out:
            head = spec[0]
            base_head = head if not head.startswith("via") else "via"
            legacy_heads.add(base_head)
            _assert(len(spec) == 3, f"non-legacy spec arity: {spec}")
        # genome generate path must agree with propose_mints exactly
        g = initial_goal_grammar()
        trees = _gg_generate(g, GoalGenContext(rs), MINT_PER_WAVE,
                             SEED + w * 9173)
        regen = [goal_tree_to_flat(t) for t in trees]
        _assert([tuple(s) for s in out] == [tuple(s) for s in regen],
                f"genome generate != propose_mints at wave {w}")
    _assert(legacy_heads <= {"sq", "mulo", "via"},
            f"grammar emitted non-legacy heads: {legacy_heads}")


def test_grammar_composition_generates_new_specs() -> None:
    """A composed constructor sq(mulo(T,T)) reaches target VECTORS that no
    depth-1 sq/mulo/via operator can reach (strictly new minting reach, G2)."""
    rs = build_frozen()
    ensure_worktable(rs)
    ctx = GoalGenContext(rs)
    depth1 = set()
    for op in initial_goal_grammar().ops:
        for fill in _gg_enumerate_fills(op, ctx):
            r = ctx.realize(_gg_instantiate(op.skeleton, list(fill)))
            if r:
                depth1.add(r[0])
    comp = GoalOp("sq.mulo", ("sq", ("mulo", HOLE_T, HOLE_T)), "product", 3,
                  "derived")
    comp_vecs = set()
    for fill in _gg_enumerate_fills(comp, ctx):
        r = ctx.realize(_gg_instantiate(comp.skeleton, list(fill)))
        if r:
            comp_vecs.add(r[0])
    new = comp_vecs - depth1
    _assert(len(new) >= 1,
            "composition reached no vector beyond the depth-1 grammar")


def test_grammar_duplicate_vectors_rejected() -> None:
    """generate() admits no two specs with the same train vector, and never a
    vector already realised by an existing task."""
    rs = build_frozen()
    ensure_worktable(rs)
    ctx = GoalGenContext(rs)
    existing = ctx.existing_vectors()
    g = initial_goal_grammar()
    trees = _gg_generate(g, ctx, 8, SEED)
    vecs = [ctx.realize(t)[0] for t in trees if ctx.realize(t)]
    _assert(len(vecs) == len(set(vecs)),
            "generate emitted duplicate train vectors")
    _assert(all(v not in existing for v in vecs),
            "generate emitted a vector that duplicates an existing task")


def test_grammar_generation_path_has_no_oracle_access() -> None:
    """No function on the GENERATION or MUTATION path may read sealed material
    (the oracle registry, the holdout/cf gates, or the oracle builders). The
    grammar sees only the public GoalGenContext adapter (G5)."""
    import inspect
    forbidden = ["_ORACLE_REGISTRY", "holdout_gate", "cf_gate", "_gen_oracle",
                 "_genome_oracle", "seal_task", "_make_gate"]
    targets = [_gg_generate, _gg_enumerate_fills, _gg_novelty, _gg_goodhart,
               _gg_instantiate]
    targets += list(GOAL_MUTATIONS.values())
    for fn in targets:
        src = inspect.getsource(fn)
        for tok in forbidden:
            _assert(tok not in src,
                    f"{fn.__name__} references sealed material '{tok}'")
    # the public adapter may compute public train vectors but must not read the
    # registry or gates directly:
    csrc = inspect.getsource(GoalGenContext)
    for tok in ["_ORACLE_REGISTRY", "holdout_gate", "cf_gate"]:
        _assert(tok not in csrc,
                f"GoalGenContext references sealed material '{tok}'")


def test_grammar_cannot_modify_verifier_gates() -> None:
    """The trust kernel is outside the mutable grammar: no genome op carries
    gate state, and the verifier fingerprint pin ABORTS if the judging
    functions ever change."""
    # (a) the fingerprint covers the gate-makers and oracle sealers
    import inspect
    fpsrc = inspect.getsource(_gg_verifier_fp)
    for fn in ("seal_task", "_make_gate", "lookup_solution",
               "task_target_vector"):
        _assert(fn in fpsrc, f"verifier fingerprint omits {fn}")
    # (b) a genome is pure spec-data: its ops carry only skeletons/typing
    g = initial_goal_grammar()
    for o in g.ops:
        for bad in ("gate", "oracle", "holdout"):
            _assert(bad not in repr(o.skeleton).lower(),
                    f"genome op skeleton references '{bad}'")
    # (c) the pin actually fires on a simulated verifier change
    global _GG_VERIFIER_FP_FROZEN
    saved = _GG_VERIFIER_FP_FROZEN
    try:
        _GG_VERIFIER_FP_FROZEN = "deadbeefdeadbeef"   # pretend gates changed
        raised = False
        try:
            _gg_assert_verifier_unchanged("test.tamper")
        except RuntimeError:
            raised = True
        _assert(raised, "verifier pin did NOT abort on a changed fingerprint")
    finally:
        _GG_VERIFIER_FP_FROZEN = saved


def test_grammar_metagate_rejects_worse() -> None:
    """The acceptance rule rejects a candidate that solves fewer frontier walls
    (or regresses a previously solved task) -- no decorative acceptance."""
    inc = {"frontier_solved": 2, "gen_solved": 4, "base_preserved": True}
    worse = {"frontier_solved": 1, "gen_solved": 4, "base_preserved": True}
    acc, reason, delta, regr = _gg_decide(inc, worse)
    _assert((not acc) and delta < 0, f"worse grammar accepted: {reason}")
    equal = {"frontier_solved": 2, "gen_solved": 4, "base_preserved": True}
    acc2, r2, d2, _ = _gg_decide(inc, equal)
    _assert(not acc2 and d2 == 0, f"equal grammar accepted: {r2}")
    regress = {"frontier_solved": 9, "gen_solved": 4, "base_preserved": False}
    acc3, r3, _, regr3 = _gg_decide(inc, regress)
    _assert(not acc3 and regr3,
            f"grammar that lost a solved task accepted: {r3}")


def test_grammar_metagate_accepts_better() -> None:
    """The acceptance rule accepts a candidate that solves strictly more
    frontier walls with no regression."""
    inc = {"frontier_solved": 1, "gen_solved": 3, "base_preserved": True}
    better = {"frontier_solved": 2, "gen_solved": 4, "base_preserved": True}
    acc, reason, delta, regr = _gg_decide(inc, better)
    _assert(acc and delta > 0 and not regr,
            f"better grammar rejected: {reason}")


def test_grammar_accepted_grammar_is_reused() -> None:
    """An accepted/attached grammar becomes the generator: ensure_goal_grammar
    returns the SAME object on repeated calls, and an evolved genome attached
    to the RunState is what propose_mints generates from."""
    rs = build_frozen()
    ensure_worktable(rs)
    g1 = ensure_goal_grammar(rs)
    g2 = ensure_goal_grammar(rs)
    _assert(g1 is g2, "ensure_goal_grammar did not reuse the attached genome")
    # attach an evolved (re-weighted) genome and confirm it is the generator
    rng = _gg_random.Random(0)
    evolved = mut_add_novelty_pressure(g1, GoalGenContext(rs), rng)
    _assert(evolved is not None and evolved.version == g1.version + 1,
            "mutation did not produce a versioned child")
    _assert(evolved.parent_digest == g1.digest(),
            "evolved genome does not record its parent in lineage")
    rs.goal_grammar = evolved
    _assert(ensure_goal_grammar(rs) is evolved,
            "attached evolved genome was not reused by the curriculum")


def test_grammar_deterministic_replay() -> None:
    """Same seed -> identical generated spec trees and identical mutation
    child digests (G4: deterministic, reproducible)."""
    rs = build_frozen()
    ensure_worktable(rs)
    g = initial_goal_grammar()
    a = _gg_generate(g, GoalGenContext(rs), 6, 4242)
    b = _gg_generate(g, GoalGenContext(rs), 6, 4242)
    _assert([_gg_skel_repr(t) for t in a] == [_gg_skel_repr(t) for t in b],
            "generation is not deterministic under a fixed seed")
    for name, fn in sorted(GOAL_MUTATIONS.items()):
        c1 = fn(g, GoalGenContext(rs), _gg_random.Random(11))
        c2 = fn(g, GoalGenContext(rs), _gg_random.Random(11))
        d1 = c1.digest() if c1 else None
        d2 = c2.digest() if c2 else None
        _assert(d1 == d2, f"mutation {name} not deterministic")


def test_grammar_metagate_measures_real_downstream_gain() -> None:
    """End-to-end, MEASURED and DETERMINISTIC: drive two distinct grammars
    (full sq/mulo/via vs a handicap that supplies only the hard (A*B)^2
    composition) for several waves under the sealed gates, and assert the gate
    DECIDES on real measured downstream frontier-solving -- it accepts exactly
    the arm that solved strictly more frontier walls and rejects the other (or
    rejects both when tied), never the reverse -- while the verifier
    fingerprint stays pinned. The absolute counts are small and depend on the
    (disclosed, reduced) enumeration cap; the gate's INTEGRITY -- decision
    tracks measurement, verifier untouched -- does not. This is the property
    the spec demands: measured improvement, not asserted improvement."""
    global ENUM_CLASS_CAP
    saved = ENUM_CLASS_CAP
    ENUM_CLASS_CAP = 6000
    try:
        fp0 = _gg_verifier_fp()
        base = _gg_build_demo_base(waves=3, cap=6000, seed=2026)
        full = initial_goal_grammar()
        handi = GoalGrammarGenome(
            ops=(GoalOp("sq.mulo", ("sq", ("mulo", HOLE_T, HOLE_T)),
                        "product", 3, "handicap"),),
            obj_weights={"frontier": 0.0, "novelty": 0.0,
                         "compression": 0.0, "transfer": 0.0})
        m_full = _gg_sandbox_waves(full, base, 2026, 3, 6)
        m_handi = _gg_sandbox_waves(handi, base, 2026, 3, 6)
        # both arms preserved every previously-solved base task (no regression)
        _assert(m_full["base_preserved"] and m_handi["base_preserved"],
                "a sandbox arm lost a previously solved base task")
        # the gate's decision must track the measured frontier-solving:
        acc_fh, _, d_fh, _ = _gg_decide(m_handi, m_full)   # handi -> full
        acc_hf, _, d_hf, _ = _gg_decide(m_full, m_handi)   # full -> handi
        ff, fh = m_full["frontier_solved"], m_handi["frontier_solved"]
        if ff > fh:
            _assert(acc_fh and not acc_hf,
                    f"full solved more ({ff}>{fh}) but gate did not accept it")
        elif fh > ff:
            _assert(acc_hf and not acc_fh,
                    f"handi solved more ({fh}>{ff}) but gate did not accept it")
        else:
            _assert(not acc_fh and not acc_hf,
                    f"tie ({ff}=={fh}) but gate accepted a change")
        # at least one arm exercised real frontier-solving (machinery works)
        _assert(max(ff, fh) >= 1,
                "neither grammar solved any frontier wall over the waves")
        # the judging functions were never touched
        _assert(_gg_verifier_fp() == fp0,
                "verifier fingerprint changed during the A/B")
    finally:
        ENUM_CLASS_CAP = saved


TESTS.extend([
    test_grammar_sq_mulo_via_not_hardcoded,
    test_grammar_G1_reproduces_legacy,
    test_grammar_composition_generates_new_specs,
    test_grammar_duplicate_vectors_rejected,
    test_grammar_generation_path_has_no_oracle_access,
    test_grammar_cannot_modify_verifier_gates,
    test_grammar_metagate_rejects_worse,
    test_grammar_metagate_accepts_better,
    test_grammar_accepted_grammar_is_reused,
    test_grammar_deterministic_replay,
    test_grammar_metagate_measures_real_downstream_gain,
])


# --- SECTION 22B tests: single-closure co-evolution (J1..J5 + spec) -------- #
def _jt_view(nf: int, nb: int, nov: float = 0.8, depth: int = 2,
             fam: str = "F", budget: int = 1000) -> Dict[str, Any]:
    """A synthetic PUBLIC rollout view for the pure-logic evaluator tests."""
    walls = [{"novelty": nov, "depth": depth, "family": fam,
              "is_frontier": True} for _ in range(nf)]
    walls += [{"novelty": nov, "depth": depth, "family": fam,
               "is_frontier": False} for _ in range(nb)]
    return {"frontier_minted": nf, "bridge_minted": nb, "gen_minted": nf + nb,
            "step_budget": budget, "macros_end": 3, "walls": walls}


def test_joint_evaluator_is_executable_not_constant() -> None:
    """J1: the EvaluationGrammar genuinely computes from data. Two evaluators
    with different ASTs return different scores and DIFFERENT orderings on the
    same pair of public views -- it is not a constant wrapper around a fixed
    rule."""
    full, handi = _jt_view(15, 2), _jt_view(4, 1)
    e_init = initial_evaluation_grammar()
    e_anti = EvaluationGrammar(score_ast=("wsum", (
        (1.0, ("metric", "bridge_minted")),
        (-1.0, ("metric", "frontier_minted")))))
    sfi, shi = e_init.score(full), e_init.score(handi)
    sfa, sha = e_anti.score(full), e_anti.score(handi)
    _assert(sfi > shi, "initial evaluator should prefer the frontier-rich view")
    _assert(sfa < sha, "anti-frontier evaluator should prefer the lean view")
    _assert(sfi != sfa, "distinct ASTs gave identical scores (constant?)")
    # a constant AST really is constant (control):
    e_const = EvaluationGrammar(score_ast=("const", 1.0))
    _assert(e_const.score(full) == e_const.score(handi) == 1.0,
            "const AST must be constant")


def test_joint_evaluator_reads_no_sealed_material() -> None:
    """J2: no information leakage. The interpreter, the public-view builder, and
    every evaluator mutation reference no sealed/oracle/gate symbol; the public
    view exposes none of the sealed solve keys."""
    import inspect
    eval_path = [_eg_eval, _eg_metric, _eg_wall_feat, _eg_ast_repr,
                 _je_public_view, mut_adjust_meta_metric_weight,
                 mut_introduce_novelty_threshold, mut_specialize_gate_by_family]
    sealed = ["frontier_solved", "gen_solved", "solved_ids", "adopted_tokens",
              "seal_task", "_make_gate", "_genome_oracle", "_gen_oracle",
              "lookup_solution", "holdout", "counterfactual", "base_preserved"]
    for fn in eval_path:
        src = inspect.getsource(fn)
        for tok in sealed:
            _assert(tok not in src,
                    f"evaluator-path fn {fn.__name__} references sealed `{tok}`")
    # a summary carrying sealed keys must yield a view WITHOUT them
    poisoned = {"frontier_minted": 5, "gen_minted": 7, "step_budget": 100,
                "macros_end": 2, "wall_features": [],
                "frontier_solved": 99, "gen_solved": 99, "solved_ids": [1, 2],
                "base_preserved": True}
    view = _je_public_view(poisoned)
    for k in _JE_FORBIDDEN_VIEW_KEYS:
        _assert(k not in view, f"public view leaked sealed key `{k}`")


def test_joint_absolute_veto_dominates() -> None:
    """J3: Absolute Zero-Regression. A candidate whose SEALED solve-rate-per-
    budget falls is rejected EVEN WHEN its own evolved evaluator strictly
    prefers it. Constructed (not measured) so the regression is guaranteed."""
    inc = {"frontier_minted": 15, "frontier_solved": 3, "gen_minted": 17,
           "step_budget": 1000, "macros_end": 3,
           "wall_features": [{"novelty": 0.8, "depth": 2, "family": "F",
                              "is_frontier": True} for _ in range(15)]}
    cand = {"frontier_minted": 4, "frontier_solved": 1, "gen_minted": 5,
            "step_budget": 1000, "macros_end": 3,
            "wall_features": [{"novelty": 0.8, "depth": 2, "family": "F",
                               "is_frontier": False} for _ in range(4)]}
    anti = EvaluationGrammar(score_ast=("wsum", (
        (1.0, ("metric", "bridge_minted")),
        (-1.0, ("metric", "frontier_minted")))))
    acc, reason, parts = _je_decide(inc, cand, anti)
    _assert(parts["eval_prefers"] is True,
            "the adversarial evaluator should prefer the regressing candidate")
    _assert(parts["abs_delta"] < 0, "the candidate must truly regress")
    _assert(acc is False, "a true regression was accepted (floor breached)")
    _assert("VETO_absolute_regression" in reason,
            f"veto reason not surfaced: {reason}")
    # symmetric positive control: real gain is accepted by a sane evaluator
    acc2, _, parts2 = _je_decide(cand, inc, initial_evaluation_grammar())
    _assert(parts2["abs_delta"] > 0 and acc2 is True,
            "a real absolute gain preferred by the evaluator must be accepted")


def test_joint_kernel_is_immutable() -> None:
    """J4: the AbsoluteUniversalVerifier is hash-pinned. Its fingerprint is a
    pure function of the kernel's own source plus the sealed verifier surface;
    any edit flips it; the pin raises on any mismatch."""
    import inspect, hashlib
    src_tr = inspect.getsource(AbsoluteUniversalVerifier.true_rate)
    src_am = inspect.getsource(AbsoluteUniversalVerifier.absolute_metric)
    src_nr = inspect.getsource(AbsoluteUniversalVerifier.no_regression)
    vfp = _gg_verifier_fp()
    recomputed = hashlib.sha256(
        ("\x00".join([src_tr, src_am, src_nr, vfp])).encode()).hexdigest()[:16]
    _assert(recomputed == _je_kernel_fp(),
            "kernel fp is not a pure function of its source + sealed surface")
    # an edit to ANY kernel method changes the fingerprint
    edited = hashlib.sha256(
        ("\x00".join([src_tr + "  # edit\n", src_am, src_nr, vfp]))
        .encode()).hexdigest()[:16]
    _assert(edited != _je_kernel_fp(), "a source edit did not change the fp")
    # the absolute metric reads ONLY sealed truth / budget (not public counts)
    av = AbsoluteUniversalVerifier()
    _assert(av.absolute_metric({"frontier_solved": 6, "step_budget": 2000})
            == 6.0 / 2000.0, "absolute_metric must be solved/budget exactly")
    _assert(av.absolute_metric({"frontier_minted": 999, "step_budget": 1000})
            == 0.0, "absolute_metric must ignore public minted counts")
    # the pin fires on mismatch
    global _JE_KERNEL_FP_FROZEN
    saved = _JE_KERNEL_FP_FROZEN
    try:
        _JE_KERNEL_FP_FROZEN = "0000000000000000"
        fired = False
        try:
            _je_assert_kernel_unchanged("test_probe")
        except RuntimeError:
            fired = True
        _assert(fired, "kernel pin did not fire on a fingerprint mismatch")
    finally:
        _JE_KERNEL_FP_FROZEN = saved


def test_joint_mutations_deterministic_and_real() -> None:
    """J5: deterministic replay. Each evaluator mutation, under a fixed seed,
    yields the same evaluator digest and the same AST, and it actually CHANGES
    the AST (it is a real mutation, not a no-op)."""
    class _Ctx:
        def recent_solved(self): return ["t1", "t2"]
        def family_of(self, t): return "F"
    g = initial_joint_genome()
    init_ast = _eg_ast_repr(g.evl.score_ast)
    for mut in (mut_adjust_meta_metric_weight, mut_introduce_novelty_threshold,
                mut_specialize_gate_by_family):
        a = mut(g, _Ctx(), _gg_random.Random(123))
        b = mut(g, _Ctx(), _gg_random.Random(123))
        _assert(a is not None and b is not None,
                f"{mut.__name__} returned None on a viable context")
        _assert(a.evl.digest() == b.evl.digest(),
                f"{mut.__name__} not deterministic under a fixed seed")
        _assert(_eg_ast_repr(a.evl.score_ast) != init_ast,
                f"{mut.__name__} did not change the evaluation AST")
        _assert(isinstance(a, JointEvolvableGenome),
                f"{mut.__name__} must return a JointEvolvableGenome")


def test_joint_evaluator_mutations_registered() -> None:
    """Spec point 2: the three evaluator-targeting operators are present in
    GOAL_MUTATIONS, and the unified JOINT_MUTATIONS registry carries both the
    lifted generation operators and the evaluator operators on one plane."""
    for m in ("adjust_meta_metric_weight", "introduce_novelty_threshold",
              "specialize_gate_by_family"):
        _assert(m in GOAL_MUTATIONS, f"GOAL_MUTATIONS missing evaluator op {m}")
    gen_lifted = [k for k in JOINT_MUTATIONS if k.startswith("gen_")]
    evl_ops = [k for k in JOINT_MUTATIONS if k.startswith("evl_")]
    _assert(len(gen_lifted) >= 10, f"too few lifted gen ops: {len(gen_lifted)}")
    _assert(len(evl_ops) == 3, f"expected 3 evaluator ops, got {len(evl_ops)}")


def test_joint_genome_pairs_both_halves() -> None:
    """Structural: a JointEvolvableGenome carries BOTH a GoalGrammarGenome
    (generation) and an EvaluationGrammar (evaluation) on one plane; the
    initial joint genome reuses the legacy-equivalent generator and the public
    initial evaluator; digests are stable and clones are independent."""
    j = initial_joint_genome()
    _assert(isinstance(j.gen, GoalGrammarGenome), "gen half wrong type")
    _assert(isinstance(j.evl, EvaluationGrammar), "evl half wrong type")
    _assert(j.gen.digest() == initial_goal_grammar().digest(),
            "initial joint gen must equal the legacy-equivalent grammar (G1)")
    _assert(j.digest() == initial_joint_genome().digest(),
            "joint digest not stable")
    c = j.clone()
    _assert(c.digest() == j.digest(), "clone changed the digest")


def test_joint_eval_only_mutation_cannot_fake_absolute_gain() -> None:
    """Anti-cheat: an EVL-only change is scored against the SAME generation
    rollout on both sides, so a re-weighted judge sees identical sealed rates
    and can never manufacture an absolute gain -- the gate cannot accept on
    evaluator whim alone."""
    summ = {"frontier_minted": 10, "frontier_solved": 2, "gen_minted": 12,
            "step_budget": 1000, "macros_end": 3,
            "wall_features": [{"novelty": 0.8, "depth": 2, "family": "F",
                               "is_frontier": True} for _ in range(10)]}
    # even a maximally self-serving evaluator: same rollout both sides
    greedy = EvaluationGrammar(score_ast=("wsum", (
        (999.0, ("metric", "frontier_minted")),)))
    acc, reason, parts = _je_decide(summ, summ, greedy)
    _assert(parts["abs_delta"] == 0.0,
            "identical rollouts must have zero absolute delta")
    _assert(parts["eval_prefers"] is False,
            "with identical views the evaluator cannot strictly prefer")
    _assert(acc is False,
            "an evl-only change fabricated an acceptance (cheat!)")


def test_joint_measured_end_to_end() -> None:
    """End-to-end, MEASURED and DETERMINISTIC: drive the full sq/mulo/via
    GENERATION grammar against a handicap over several sealed waves; the public
    evaluator scores the two rollouts and the immutable AbsoluteUniversalVerifier
    independently measures the sealed solve-rate-per-budget. We assert the
    INTEGRITY properties that must hold regardless of the (cap-sensitive)
    absolute counts: the single-closure decision never accepts a true sealed
    regression, an evl-only re-score cannot move the floor, and BOTH fingerprint
    pins stay fixed across the whole A/B. Absolute magnitudes depend on the
    disclosed reduced cap; their INTEGRITY does not."""
    global ENUM_CLASS_CAP
    saved = ENUM_CLASS_CAP
    ENUM_CLASS_CAP = 6000
    try:
        fp0 = _gg_verifier_fp()
        kfp0 = _je_kernel_fp()
        base = _gg_build_demo_base(waves=3, cap=6000, seed=2026)
        full = initial_goal_grammar()
        handi = GoalGrammarGenome(
            ops=(GoalOp("sq.mulo", ("sq", ("mulo", HOLE_T, HOLE_T)),
                        "product", 3, "handicap"),),
            obj_weights={"frontier": 0.0, "novelty": 0.0,
                         "compression": 0.0, "transfer": 0.0})
        mf = _gg_sandbox_waves(full, base, 2026, 3, 6)
        mh = _gg_sandbox_waves(handi, base, 2026, 3, 6)
        _assert(mf["base_preserved"] and mh["base_preserved"],
                "a sandbox arm lost a previously solved base task")
        av = AbsoluteUniversalVerifier()
        ev = initial_evaluation_grammar()
        # the public view the evaluator reads carries NO sealed key
        for v in (_je_public_view(mf), _je_public_view(mh)):
            for k in _JE_FORBIDDEN_VIEW_KEYS:
                _assert(k not in v, f"measured public view leaked `{k}`")
        # the single-closure decision must NEVER certify a true sealed
        # regression, in EITHER direction, no matter how the evaluator scores.
        for inc, cand in ((mf, mh), (mh, mf)):
            acc, reason, parts = _je_decide(inc, cand, ev)
            if parts["abs_delta"] < 0:
                _assert(not acc,
                        f"accepted a sealed regression: {reason}")
        # an evl-only re-score against the SAME rollout cannot be accepted
        acc_self, _, parts_self = _je_decide(mf, mf, EvaluationGrammar(
            score_ast=("wsum", ((999.0, ("metric", "frontier_minted")),))))
        _assert(parts_self["abs_delta"] == 0.0 and not acc_self,
                "evl-only re-score fabricated an acceptance on a fixed rollout")
        # the absolute verifier consumed the real step budget the searcher burned
        _assert(mf["step_budget"] > 0 and mh["step_budget"] > 0,
                "step budget was not measured")
        _assert(av.absolute_metric(mf) == mf["frontier_solved"]
                / float(mf["step_budget"]),
                "absolute metric is not sealed_solved / measured budget")
        # at least one arm exercised real frontier-solving (machinery lives)
        _assert(max(mf["frontier_solved"], mh["frontier_solved"]) >= 1,
                "neither grammar solved any frontier wall over the waves")
        # both pins fixed across the whole measured A/B
        _assert(_gg_verifier_fp() == fp0, "verifier fp moved during the A/B")
        _assert(_je_kernel_fp() == kfp0, "kernel fp moved during the A/B")
    finally:
        ENUM_CLASS_CAP = saved


TESTS.extend([
    test_joint_evaluator_is_executable_not_constant,
    test_joint_evaluator_reads_no_sealed_material,
    test_joint_absolute_veto_dominates,
    test_joint_kernel_is_immutable,
    test_joint_mutations_deterministic_and_real,
    test_joint_evaluator_mutations_registered,
    test_joint_genome_pairs_both_halves,
    test_joint_eval_only_mutation_cannot_fake_absolute_gain,
    test_joint_measured_end_to_end,
])




def run_tests(only: str = "") -> None:
    failures = 0
    selected = [t for t in TESTS if not only or only in t.__name__]
    for t in selected:
        try:
            t()
            print(f"PASS {t.__name__}")
        except Exception as e:
            failures += 1
            print(f"FAIL {t.__name__}: {e}")
    print(f"RESULT: {len(selected) - failures} passed, {failures} failed")
    if failures:
        raise SystemExit(1)
    print("ALL TESTS PASSED")

