def test_gd_meta_select_structure() -> None:
    best, scores = gd_meta_select(None, {}, seed=3)
    _assert(best in GD_CONFIGS, f"chosen config invalid: {best}")
    _assert(len(scores) == len(GD_CONFIGS), "score table incomplete")
    _assert(all(0.0 <= v <= 1.0 for v in scores.values()),
            f"self-scores out of range: {scores}")


def test_gd_generation_drift_shows_qualitative_gain() -> None:
    base = gd_run_family(GD_SCARCE_FAMILY_B, (False, "debate", False),
                         None, {}, seed0=123)
    base_audit = sum(a for _, a in base) / len(base)
    hist = gd_generation_loop(gens=2, seed=SEED + 9, macros={})
    _assert(len(hist) == 2, "generation loop truncated")
    _assert(hist[-1]["prm_updates"] > 0, "GD-PRM never trained")
    _assert(hist[-1]["audit_acc"] > base_audit,
            f"no audited gain over baseline: {hist[-1]['audit_acc']} <= "
            f"{base_audit} (macros/PRM failed to extend reach)")


def test_prm_channel_bookkeeping_in_adaptive_run() -> None:
    rs = build_adaptive()
    _assert("prm" in rs.channel_stats, "prm channel absent from stats")
    _assert(any("PRM_STATE" in e for e in rs.events),
            "PRM training left no event trace")
    _assert(rs.prm is not None and getattr(rs.prm, "updates", 0) > 0,
            "adaptive arm carries no trained PRM")
    _assert(rs.wm_acts > 0,
            "adaptive arm never bootstrapped the world model")
    _assert(rs.prm_prefix_runs > 0, "PRM prefix featurization spent no acts")

