# 18-21. PORTED EXTENSION LAYER (provenance: user-supplied rebuilt variant   #
#        rsi_levels_metaforge_unified__1_.py, adapted to this runtime)       #
#                                                                             #
#   18. REAL-ARTIFACT HARNESS II: provisioned workspaces (public input       #
#       files + instruction, train vs HIDDEN file checks), ToolActionLayer   #
#       with path guard and isolated-subprocess execution (-I, timeout,     #
#       trace + revert), csv / minimal-xlsx / json-logs / repo families,    #
#       reference runner.                                                    #
#   19. HETEROGENEOUS OBJECT DOMAINS (GDX): feature-level synthesis over    #
#       lists, strings, grids, dicts and graphs; universal / open-object /  #
#       emergent domains; residue-driven feature invention.                  #
#   20. SCOPED SELF-EDIT: the system patches the capability roster line in  #
#       a COPY of source, a guard proves only that line changed, and the    #
#       copy is evaluated in isolation.                                      #
#   21. PERSISTENT LONG-HORIZON CYCLE: checkpointed improvement cycles      #
#       with save/load state ("longcycle"; the original used a hype label    #
#       which is renamed here per the no-hype-labels rule).                  #
#                                                                             #
#   Adaptation renames (collision isolation, semantics unchanged):           #
#     SealedFileTask->ArtifactFileTask, ActionTrace->ArtifactActionTrace,    #
#     gd_features->gd_object_features, GD_FEATURES/_CONSTS/_BINARY_OPS->     #
#     GDX_*, _gd_numbers/_gd_pairs->_gdx_*, singularity->longcycle.          #
# =========================================================================== #

import csv
import io
import subprocess
import sys
import tempfile
import zipfile
import xml.etree.ElementTree as ET
from pathlib import Path
from typing import Any

@dataclass(frozen=True)
class FileCheckResult:
    ok: bool
    detail: str = ""
    residues: Tuple[str, ...] = ()


@dataclass(frozen=True)
class ArtifactActionTrace:
    action: str
    input_hash: str
    output_hash: str
    cost: float
    failure_type: str
    status: str

    def as_dict(self) -> Dict[str, object]:
        return {
            "action": self.action,
            "input_hash": self.input_hash,
            "output_hash": self.output_hash,
            "cost": self.cost,
            "failure_type": self.failure_type,
            "status": self.status,
        }


@dataclass(frozen=True)
class ArtifactFileTask:
    tid: str
    family: str
    public_instruction: str
    public_input_files: Dict[str, bytes]
    train_check: Callable[[Path], FileCheckResult]
    hidden_check: Callable[[Path], FileCheckResult]
    allowed_tools: Tuple[str, ...]
    expected_artifact_schema: Dict[str, str]

    def provision(self, root: Path) -> Path:
        work = Path(root) / self.tid
        if work.exists():
            shutil.rmtree(work)
        work.mkdir(parents=True, exist_ok=True)
        for rel, payload in sorted(self.public_input_files.items()):
            target = _safe_child(work, rel)
            target.parent.mkdir(parents=True, exist_ok=True)
            target.write_bytes(payload)
        (work / "public_instruction.txt").write_text(
            self.public_instruction, encoding="utf-8")
        (work / "allowed_tools.json").write_text(
            json.dumps({"allowed_tools": self.allowed_tools},
                       indent=2, sort_keys=True),
            encoding="utf-8")
        (work / "expected_artifact_schema.json").write_text(
            json.dumps(self.expected_artifact_schema, indent=2,
                       sort_keys=True),
            encoding="utf-8")
        return work

    def run_train(self, workspace: Path) -> FileCheckResult:
        return self.train_check(Path(workspace))

    def run_hidden(self, workspace: Path) -> FileCheckResult:
        return self.hidden_check(Path(workspace))


def _digest_bytes(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()[:16]


def _digest_json(payload: Any) -> str:
    raw = json.dumps(payload, sort_keys=True, separators=(",", ":"),
                     default=str).encode("utf-8")
    return _digest_bytes(raw)


def _safe_child(root: Path, rel_path: str) -> Path:
    rel = Path(str(rel_path))
    if rel.is_absolute():
        raise ValueError(f"absolute path rejected: {rel_path}")
    target = (Path(root) / rel).resolve()
    base = Path(root).resolve()
    try:
        target.relative_to(base)
    except ValueError as exc:
        raise ValueError(f"path escapes workspace: {rel_path}") from exc
    return target


class ToolActionLayer:
    """Deterministic operational API for ArtifactFileTask workspaces."""

    def __init__(self, root: Path, allowed_tools: Sequence[str]):
        self.root = Path(root).resolve()
        self.root.mkdir(parents=True, exist_ok=True)
        self.allowed_tools = tuple(allowed_tools)
        self.traces: List[ArtifactActionTrace] = []

    def _tree_digest(self) -> str:
        entries: List[Tuple[str, str]] = []
        for path in sorted(p for p in self.root.rglob("*") if p.is_file()):
            rel = path.relative_to(self.root).as_posix()
            entries.append((rel, _digest_bytes(path.read_bytes())))
        return _digest_json(entries)

    def _record(self, action: str, payload: Any, before: str, after: str,
                failure_type: str = "", status: str = "committed") -> None:
        self.traces.append(ArtifactActionTrace(
            action=action,
            input_hash=_digest_json({"action": action, "payload": payload,
                                     "before": before}),
            output_hash=_digest_json({"after": after,
                                      "failure_type": failure_type}),
            cost=1.0,
            failure_type=failure_type,
            status=status,
        ))

    def _reject(self, action: str, payload: Any, before: str,
                failure_type: str) -> None:
        self._record(action, payload, before, before, failure_type,
                     status="reverted")
        raise ValueError(f"{action} rejected: {failure_type}")

    def _ensure_tool(self, action: str, payload: Any, before: str) -> None:
        if action not in self.allowed_tools:
            self._reject(action, payload, before, "tool_not_allowed")

    def _resolve(self, action: str, payload: Any, before: str,
                 rel_path: str) -> Path:
        try:
            return _safe_child(self.root, rel_path)
        except ValueError:
            self._reject(action, payload, before, "path_escape")
            raise

    def read_file(self, rel_path: str) -> str:
        action = "read_file"
        payload = {"path": rel_path}
        before = self._tree_digest()
        self._ensure_tool(action, payload, before)
        path = self._resolve(action, payload, before, rel_path)
        try:
            out = path.read_text(encoding="utf-8")
            self._record(action, payload, before, self._tree_digest())
            return out
        except Exception:
            self._reject(action, payload, before, "read_failed")
            raise

    def write_file(self, rel_path: str, content: str) -> None:
        action = "write_file"
        payload = {"path": rel_path, "content_hash": _digest_bytes(
            content.encode("utf-8"))}
        before = self._tree_digest()
        self._ensure_tool(action, payload, before)
        path = self._resolve(action, payload, before, rel_path)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")
        self._record(action, payload, before, self._tree_digest())

    def apply_patch(self, rel_path: str, old: str, new: str) -> None:
        action = "apply_patch"
        payload = {
            "path": rel_path,
            "old_hash": _digest_bytes(old.encode("utf-8")),
            "new_hash": _digest_bytes(new.encode("utf-8")),
        }
        before = self._tree_digest()
        self._ensure_tool(action, payload, before)
        path = self._resolve(action, payload, before, rel_path)
        text = path.read_text(encoding="utf-8")
        if text.count(old) != 1:
            self._reject(action, payload, before, "patch_not_unique")
        path.write_text(text.replace(old, new, 1), encoding="utf-8")
        self._record(action, payload, before, self._tree_digest())

    def parse_csv(self, rel_path: str) -> List[Dict[str, str]]:
        action = "parse_csv"
        payload = {"path": rel_path}
        before = self._tree_digest()
        self._ensure_tool(action, payload, before)
        path = self._resolve(action, payload, before, rel_path)
        with path.open("r", encoding="utf-8", newline="") as f:
            rows = list(csv.DictReader(f))
        self._record(action, payload, before, self._tree_digest())
        return rows

    def parse_json(self, rel_path: str) -> Any:
        action = "parse_json"
        payload = {"path": rel_path}
        before = self._tree_digest()
        self._ensure_tool(action, payload, before)
        path = self._resolve(action, payload, before, rel_path)
        out = json.loads(path.read_text(encoding="utf-8"))
        self._record(action, payload, before, self._tree_digest())
        return out

    def parse_xlsx(self, rel_path: str) -> List[List[str]]:
        action = "parse_xlsx"
        payload = {"path": rel_path}
        before = self._tree_digest()
        self._ensure_tool(action, payload, before)
        path = self._resolve(action, payload, before, rel_path)
        rows = _read_minimal_xlsx(path)
        self._record(action, payload, before, self._tree_digest())
        return rows

    def execute_limited_python_snippet(self, snippet: str,
                                       timeout_s: float = 2.0) -> Dict[str, Any]:
        action = "execute_limited_python_snippet"
        payload = {"snippet_hash": _digest_bytes(snippet.encode("utf-8")),
                   "timeout_s": timeout_s}
        before = self._tree_digest()
        self._ensure_tool(action, payload, before)
        env = {"PYTHONHASHSEED": "0", "PYTHONIOENCODING": "utf-8"}
        try:
            res = subprocess.run(
                [sys.executable, "-I", "-c", snippet],
                cwd=str(self.root), capture_output=True, text=True,
                timeout=timeout_s, env=env)
            out = {"returncode": res.returncode, "stdout": res.stdout,
                   "stderr": res.stderr}
            failure = "" if res.returncode == 0 else "nonzero_return"
            self._record(action, payload, before, self._tree_digest(),
                         failure_type=failure)
            return out
        except subprocess.TimeoutExpired:
            self._record(action, payload, before, self._tree_digest(),
                         failure_type="timeout", status="reverted")
            return {"returncode": -1, "stdout": "", "stderr": "timeout"}

    def run_tests(self, checker: Callable[[Path], FileCheckResult]) -> FileCheckResult:
        action = "run_tests"
        payload = {"checker": getattr(checker, "__name__", "anonymous")}
        before = self._tree_digest()
        self._ensure_tool(action, payload, before)
        try:
            result = checker(self.root)
        except Exception as exc:
            result = FileCheckResult(False, str(exc), ("check_exception",))
        self._record(action, payload, before, self._tree_digest(),
                     failure_type="" if result.ok else "test_failed")
        return result


def _check_json_artifact(workspace: Path, rel_path: str) -> Tuple[Any, FileCheckResult]:
    path = workspace / rel_path
    if not path.exists():
        return None, FileCheckResult(False, f"missing {rel_path}",
                                     ("missing_artifact",))
    try:
        return json.loads(path.read_text(encoding="utf-8")), FileCheckResult(True)
    except Exception as exc:
        return None, FileCheckResult(False, str(exc), ("invalid_json",))


def _make_minimal_xlsx(rows: Sequence[Sequence[object]]) -> bytes:
    def cell_ref(col: int, row: int) -> str:
        letters = ""
        col += 1
        while col:
            col, rem = divmod(col - 1, 26)
            letters = chr(65 + rem) + letters
        return f"{letters}{row}"

    ns = "http://schemas.openxmlformats.org/spreadsheetml/2006/main"
    sheet_rows: List[str] = []
    for r_idx, row in enumerate(rows, start=1):
        cells: List[str] = []
        for c_idx, value in enumerate(row):
            ref = cell_ref(c_idx, r_idx)
            if isinstance(value, (int, float)):
                cells.append(f'<c r="{ref}"><v>{value}</v></c>')
            else:
                text = (str(value).replace("&", "&amp;")
                        .replace("<", "&lt;").replace(">", "&gt;"))
                cells.append(
                    f'<c r="{ref}" t="inlineStr"><is><t>{text}</t></is></c>')
        sheet_rows.append(f'<row r="{r_idx}">{"".join(cells)}</row>')
    sheet_xml = (
        '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
        f'<worksheet xmlns="{ns}"><sheetData>'
        f'{"".join(sheet_rows)}</sheetData></worksheet>'
    )
    buf = io.BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        zf.writestr("[Content_Types].xml",
                    '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
                    '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">'
                    '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>'
                    '<Default Extension="xml" ContentType="application/xml"/>'
                    '<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>'
                    '<Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>'
                    '</Types>')
        zf.writestr("_rels/.rels",
                    '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
                    '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
                    '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>'
                    '</Relationships>')
        zf.writestr("xl/workbook.xml",
                    '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
                    '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" '
                    'xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'
                    '<sheets><sheet name="Sheet1" sheetId="1" r:id="rId1"/></sheets>'
                    '</workbook>')
        zf.writestr("xl/_rels/workbook.xml.rels",
                    '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
                    '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
                    '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>'
                    '</Relationships>')
        zf.writestr("xl/worksheets/sheet1.xml", sheet_xml)
    return buf.getvalue()


def _read_minimal_xlsx(path: Path) -> List[List[str]]:
    ns = {"x": "http://schemas.openxmlformats.org/spreadsheetml/2006/main"}
    shared: List[str] = []
    with zipfile.ZipFile(path, "r") as zf:
        if "xl/sharedStrings.xml" in zf.namelist():
            ss = ET.fromstring(zf.read("xl/sharedStrings.xml"))
            for item in ss.findall(".//x:si", ns):
                text = "".join(t.text or "" for t in item.findall(".//x:t", ns))
                shared.append(text)
        root = ET.fromstring(zf.read("xl/worksheets/sheet1.xml"))
    parsed: List[List[str]] = []
    for row in root.findall(".//x:sheetData/x:row", ns):
        vals: List[str] = []
        for cell in row.findall("x:c", ns):
            ctype = cell.attrib.get("t", "")
            if ctype == "inlineStr":
                node = cell.find("x:is/x:t", ns)
                vals.append("" if node is None or node.text is None else node.text)
            else:
                node = cell.find("x:v", ns)
                raw = "" if node is None or node.text is None else node.text
                vals.append(shared[int(raw)] if ctype == "s" and raw else raw)
        parsed.append(vals)
    return parsed


def _repo_check(workspace: Path, probe: str) -> FileCheckResult:
    res = subprocess.run(
        [sys.executable, "-I", "-c", probe],
        cwd=str(workspace), capture_output=True, text=True, timeout=3.0,
        env={"PYTHONHASHSEED": "0", "PYTHONIOENCODING": "utf-8"})
    if res.returncode != 0:
        return FileCheckResult(False, res.stderr.strip() or res.stdout.strip(),
                               ("repo_tests_failed",))
    return FileCheckResult(True, "repo checks passed")


def _csv_summary_train_check(workspace: Path) -> FileCheckResult:
    data, base = _check_json_artifact(workspace, "output/status_summary.json")
    if not base.ok:
        return base
    residues: List[str] = []
    if data.get("row_count") != 3:
        residues.append("row_count_wrong")
    if data.get("status_counts") != {"fail": 1, "ok": 2}:
        residues.append("status_counts_wrong")
    return FileCheckResult(not residues, "visible CSV checks",
                           tuple(residues))


def _csv_summary_hidden_check(workspace: Path) -> FileCheckResult:
    train = _csv_summary_train_check(workspace)
    data, base = _check_json_artifact(workspace, "output/status_summary.json")
    residues = list(train.residues)
    if not base.ok:
        residues.extend(base.residues)
    elif data.get("total_amount_cents") != 2400:
        residues.append("missing_total_amount_cents")
    elif data.get("average_amount_cents") != 800:
        residues.append("missing_average_amount_cents")
    return FileCheckResult(not residues, "hidden CSV schema checks",
                           tuple(residues))


def _json_logs_train_check(workspace: Path) -> FileCheckResult:
    data, base = _check_json_artifact(workspace, "output/anomaly_report.json")
    if not base.ok:
        return base
    residues: List[str] = []
    if data.get("error_count") != 2:
        residues.append("error_count_wrong")
    if data.get("warning_count") != 1:
        residues.append("warning_count_wrong")
    return FileCheckResult(not residues, "visible JSONL checks",
                           tuple(residues))


def _json_logs_hidden_check(workspace: Path) -> FileCheckResult:
    train = _json_logs_train_check(workspace)
    data, base = _check_json_artifact(workspace, "output/anomaly_report.json")
    residues = list(train.residues)
    if not base.ok:
        residues.extend(base.residues)
    else:
        if data.get("first_error_ts") != "2026-06-12T08:03:00Z":
            residues.append("first_error_ts_wrong")
        if data.get("service_counts") != {"api": 2, "worker": 1}:
            residues.append("service_counts_wrong")
    return FileCheckResult(not residues, "hidden JSONL aggregation checks",
                           tuple(residues))


def _xlsx_summary_train_check(workspace: Path) -> FileCheckResult:
    data, base = _check_json_artifact(workspace, "output/xlsx_summary.json")
    if not base.ok:
        return base
    residues: List[str] = []
    if data.get("row_count") != 3:
        residues.append("row_count_wrong")
    if data.get("status_counts") != {"closed": 1, "open": 2}:
        residues.append("status_counts_wrong")
    return FileCheckResult(not residues, "visible XLSX checks",
                           tuple(residues))


def _xlsx_summary_hidden_check(workspace: Path) -> FileCheckResult:
    train = _xlsx_summary_train_check(workspace)
    data, base = _check_json_artifact(workspace, "output/xlsx_summary.json")
    residues = list(train.residues)
    if not base.ok:
        residues.extend(base.residues)
    elif data.get("total_amount_cents") != 1300:
        residues.append("xlsx_total_amount_wrong")
    elif data.get("headers") != ["ticket", "status", "amount"]:
        residues.append("xlsx_headers_wrong")
    return FileCheckResult(not residues, "hidden XLSX schema checks",
                           tuple(residues))


def _repo_train_check(workspace: Path) -> FileCheckResult:
    probe = (
        "import sys; sys.path.insert(0, 'repo'); "
        "import math_utils; assert math_utils.add(2, 3) == 5"
    )
    return _repo_check(workspace, probe)


def _repo_hidden_check(workspace: Path) -> FileCheckResult:
    probe = (
        "import sys; sys.path.insert(0, 'repo'); import math_utils; "
        "assert math_utils.add(-2, 5) == 3; "
        "assert math_utils.add_all([1, 2, 3]) == 6"
    )
    return _repo_check(workspace, probe)


def build_real_artifact_tasks() -> List[ArtifactFileTask]:
    return [
        ArtifactFileTask(
            tid="F001",
            family="csv_serialization",
            public_instruction=(
                "Read input/orders.csv and write output/status_summary.json "
                "with row_count, status_counts, total_amount_cents, and "
                "average_amount_cents."),
            public_input_files={
                "input/orders.csv": (
                    "order_id,status,amount\n"
                    "A1,ok,12.50\nA2,fail,4.00\nA3,ok,7.50\n"
                ).encode("utf-8"),
            },
            train_check=_csv_summary_train_check,
            hidden_check=_csv_summary_hidden_check,
            allowed_tools=("read_file", "write_file", "parse_csv", "run_tests"),
            expected_artifact_schema={
                "output/status_summary.json":
                    "row_count:int,status_counts:object,total_amount_cents:int,"
                    "average_amount_cents:int",
            },
        ),
        ArtifactFileTask(
            tid="F002",
            family="json_log_processing",
            public_instruction=(
                "Read input/logs.jsonl and write output/anomaly_report.json "
                "with error_count, warning_count, first_error_ts, and "
                "service_counts for anomalous events only."),
            public_input_files={
                "input/logs.jsonl": (
                    '{"ts":"2026-06-12T08:00:00Z","level":"INFO",'
                    '"service":"api","msg":"ready"}\n'
                    '{"ts":"2026-06-12T08:02:00Z","level":"WARN",'
                    '"service":"worker","msg":"retry"}\n'
                    '{"ts":"2026-06-12T08:03:00Z","level":"ERROR",'
                    '"service":"api","msg":"timeout"}\n'
                    '{"ts":"2026-06-12T08:05:00Z","level":"ERROR",'
                    '"service":"api","msg":"quota"}\n'
                ).encode("utf-8"),
            },
            train_check=_json_logs_train_check,
            hidden_check=_json_logs_hidden_check,
            allowed_tools=("read_file", "write_file", "parse_json", "run_tests"),
            expected_artifact_schema={
                "output/anomaly_report.json":
                    "error_count:int,warning_count:int,first_error_ts:str,"
                    "service_counts:object",
            },
        ),
        ArtifactFileTask(
            tid="F003",
            family="repo_repair",
            public_instruction=(
                "Fix repo/math_utils.py so the visible and hidden arithmetic "
                "tests pass. Keep the patch minimal."),
            public_input_files={
                "repo/math_utils.py": (
                    "def add(a, b):\n"
                    "    return a - b\n\n"
                    "def add_all(values):\n"
                    "    total = 0\n"
                    "    for value in values:\n"
                    "        total = add(total, value)\n"
                    "    return total\n"
                ).encode("utf-8"),
                "repo/test_math_utils.py": (
                    "from math_utils import add\n\n"
                    "def test_add_visible():\n"
                    "    assert add(2, 3) == 5\n"
                ).encode("utf-8"),
            },
            train_check=_repo_train_check,
            hidden_check=_repo_hidden_check,
            allowed_tools=("read_file", "write_file", "apply_patch",
                           "run_tests", "execute_limited_python_snippet"),
            expected_artifact_schema={
                "repo/math_utils.py": "minimal source patch",
            },
        ),
        ArtifactFileTask(
            tid="F004",
            family="xlsx_schema_mapping",
            public_instruction=(
                "Read input/tickets.xlsx and write output/xlsx_summary.json "
                "with headers, row_count, status_counts, and "
                "total_amount_cents."),
            public_input_files={
                "input/tickets.xlsx": _make_minimal_xlsx([
                    ["ticket", "status", "amount"],
                    ["T1", "open", 5.00],
                    ["T2", "closed", 3.50],
                    ["T3", "open", 4.50],
                ]),
            },
            train_check=_xlsx_summary_train_check,
            hidden_check=_xlsx_summary_hidden_check,
            allowed_tools=("read_file", "write_file", "parse_xlsx",
                           "run_tests"),
            expected_artifact_schema={
                "output/xlsx_summary.json":
                    "headers:list,row_count:int,status_counts:object,"
                    "total_amount_cents:int",
            },
        ),
    ]


def solve_file_task_reference(task: ArtifactFileTask,
                              layer: ToolActionLayer) -> None:
    if task.tid == "F001":
        rows = layer.parse_csv("input/orders.csv")
        status_counts: Dict[str, int] = {}
        total = 0
        for row in rows:
            status_counts[row["status"]] = status_counts.get(row["status"], 0) + 1
            total += int(round(float(row["amount"]) * 100))
        out = {
            "average_amount_cents": total // max(1, len(rows)),
            "row_count": len(rows),
            "status_counts": dict(sorted(status_counts.items())),
            "total_amount_cents": total,
        }
        layer.write_file("output/status_summary.json",
                         json.dumps(out, indent=2, sort_keys=True))
    elif task.tid == "F002":
        raw = layer.read_file("input/logs.jsonl")
        events = [json.loads(line) for line in raw.splitlines() if line.strip()]
        anomalous = [e for e in events if e.get("level") in ("WARN", "ERROR")]
        service_counts: Dict[str, int] = {}
        for event in anomalous:
            service = str(event["service"])
            service_counts[service] = service_counts.get(service, 0) + 1
        errors = [e for e in anomalous if e.get("level") == "ERROR"]
        warnings = [e for e in anomalous if e.get("level") == "WARN"]
        out = {
            "error_count": len(errors),
            "first_error_ts": errors[0]["ts"] if errors else "",
            "service_counts": dict(sorted(service_counts.items())),
            "warning_count": len(warnings),
        }
        layer.write_file("output/anomaly_report.json",
                         json.dumps(out, indent=2, sort_keys=True))
    elif task.tid == "F003":
        layer.apply_patch("repo/math_utils.py", "return a - b", "return a + b")
        layer.run_tests(task.train_check)
    elif task.tid == "F004":
        rows = layer.parse_xlsx("input/tickets.xlsx")
        headers = rows[0]
        records = [dict(zip(headers, row)) for row in rows[1:]]
        status_counts: Dict[str, int] = {}
        total = 0
        for record in records:
            status = str(record["status"])
            status_counts[status] = status_counts.get(status, 0) + 1
            total += int(round(float(record["amount"]) * 100))
        out = {
            "headers": headers,
            "row_count": len(records),
            "status_counts": dict(sorted(status_counts.items())),
            "total_amount_cents": total,
        }
        layer.write_file("output/xlsx_summary.json",
                         json.dumps(out, indent=2, sort_keys=True))
    else:
        raise ValueError(f"unknown file task {task.tid}")


def run_real_artifact_harness(save_path: str = "") -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    with tempfile.TemporaryDirectory(prefix="metaforge_file_tasks_") as tmp:
        root = Path(tmp)
        for task in build_real_artifact_tasks():
            workspace = task.provision(root)
            layer = ToolActionLayer(workspace, task.allowed_tools)
            solve_file_task_reference(task, layer)
            train = task.run_train(workspace)
            hidden = task.run_hidden(workspace)
            results.append({
                "tid": task.tid,
                "family": task.family,
                "train_ok": train.ok,
                "hidden_ok": hidden.ok,
                "residues": sorted(set(train.residues + hidden.residues)),
                "trace": [trace.as_dict() for trace in layer.traces],
                "trace_digest": _digest_json(
                    [trace.as_dict() for trace in layer.traces]),
            })
    report = {
        "all_hidden_passed": all(r["hidden_ok"] for r in results),
        "task_count": len(results),
        "tasks": results,
        "surface": "ArtifactFileTask + ToolActionLayer",
    }
    if save_path:
        Path(save_path).write_text(json.dumps(report, indent=2,
                                              sort_keys=True),
                                   encoding="utf-8")
    return report


def test_real_artifact_harness_provisions_public_files() -> None:
    task = build_real_artifact_tasks()[0]
    with tempfile.TemporaryDirectory() as tmp:
        workspace = task.provision(Path(tmp))
        _assert((workspace / "input/orders.csv").exists(),
                "public input file missing")
        _assert((workspace / "public_instruction.txt").exists(),
                "public instruction missing")
        schema = json.loads(
            (workspace / "expected_artifact_schema.json").read_text(
                encoding="utf-8"))
