def open_object_domain_report() -> Dict[str, object]:
    train, frontier, unsupported = build_open_object_domain_tasks()
    cold_macros: Dict[str, GDXMacro] = {}
    train_result = gdx_solve_tasks(train, cold_macros, max_cost=3)
    solved_train: Dict[str, GDXExpr] = train_result["solved_exprs"]  # type: ignore[assignment]
    proposed = gdx_mine_macros(solved_train, cold_macros, min_support=2, max_new=3)
    candidate_macros = dict(cold_macros)
    for macro in proposed:
        candidate_macros[macro.name] = macro

    cold_frontier = gdx_solve_tasks(frontier, cold_macros, max_cost=4)
    warm_frontier = gdx_solve_tasks(frontier, candidate_macros, max_cost=4)
    accepted = int(warm_frontier["validated"]) > int(cold_frontier["validated"])
    accepted_macros = candidate_macros if accepted else cold_macros
    unsupported_result = gdx_solve_tasks(unsupported, accepted_macros, max_cost=4)
    recursive_rows = [
        row for row in warm_frontier["rows"]  # type: ignore[index]
        if "GM0(GM0" in str(row.get("expr", ""))
    ]
    return {
        "claim_boundary": (
            "open-object-domain recursive self-improvement over JSON-like "
            "tree/graph/table/manifest/timeseries/trace/AST-shaped objects; "
            "not proof over every possible domain"
        ),
        "search_visibility": "train examples only; holdout used only for validation",
        "source_domains": sorted({task.domain for task in train}),
        "frontier_domains": sorted({task.domain for task in frontier}),
        "train_validated": train_result["validated"],
        "train_total": train_result["total"],
        "proposed_macros": [
            {
                "name": macro.name,
                "body": gdx_expr_key(macro.body),
                "source_tasks": list(macro.source_tasks),
            }
            for macro in proposed
        ],
        "meta_gate": {
            "accepted": accepted,
            "cold_frontier_validated": cold_frontier["validated"],
            "warm_frontier_validated": warm_frontier["validated"],
            "delta": int(warm_frontier["validated"]) - int(cold_frontier["validated"]),
            "budget_max_cost": 4,
            "recursive_self_composition_rows": len(recursive_rows),
        },
        "cold_frontier": {k: v for k, v in cold_frontier.items() if k != "solved_exprs"},
        "warm_frontier": {k: v for k, v in warm_frontier.items() if k != "solved_exprs"},
        "unsupported_probe": {k: v for k, v in unsupported_result.items() if k != "solved_exprs"},
    }


def run_open_object_domain_self_improvement_test(save_path: str = "") -> int:
    report = open_object_domain_report()
    if save_path:
        with open(save_path, "w", encoding="utf-8") as f:
            json.dump(report, f, indent=2, sort_keys=True)
    print(json.dumps(report, indent=2, sort_keys=True))
    meta = report["meta_gate"]  # type: ignore[assignment]
    if not meta["accepted"]:  # type: ignore[index]
        return 1
    if int(meta["warm_frontier_validated"]) <= int(meta["cold_frontier_validated"]):  # type: ignore[index]
        return 1
    if int(meta["recursive_self_composition_rows"]) < 2:  # type: ignore[index]
        return 1
    unsupported = report["unsupported_probe"]  # type: ignore[assignment]
    if int(unsupported["validated"]) != 0:  # type: ignore[index]
        return 1
    return 0




def _eod_safe_key(key: object) -> str:
    raw = str(key)
    out = "".join(ch if ch.isalnum() else "_" for ch in raw)[:32]
    return out or "blank"


def _eod_collect_key_features(obj) -> Dict[str, int]:
    vals: Dict[str, int] = {}

    def add(name: str, amount: int) -> None:
        vals[name] = int(vals.get(name, 0) + int(amount))

    def rec(x) -> None:
        if isinstance(x, dict):
            for key in sorted(x, key=lambda k: str(k)):
                safe = _eod_safe_key(key)
                value = x[key]
                nums = _gdx_numbers(value)
                strings = _gdx_flat_strings(value)
                add(f"KEYCOUNT_{safe}", 1)
                add(f"KEYSUM_{safe}", sum(nums))
                add(f"KEYNUMS_{safe}", len(nums))
                add(f"KEYSTRLEN_{safe}", sum(len(s) for s in strings))
                rec(value)
            return
        if isinstance(x, (list, tuple)):
            for item in x:
                rec(item)

    rec(obj)
    return vals


def eod_features(obj) -> Dict[str, int]:
    out = gd_object_features(obj)
    out.update(_eod_collect_key_features(obj))
    return out


def eod_candidate_features(inputs: Sequence[object]) -> Tuple[str, ...]:
    names = set(GDX_FEATURES)
    for obj in inputs:
        names.update(eod_features(obj))
    return tuple(sorted(names))


def eod_expr_eval(e: GDXExpr, obj, macros: Dict[str, GDXMacro],
                  slot_value: Optional[int] = None) -> int:
    if e.op == "FEATURE":
        return eod_features(obj).get(e.name, 0)
    if e.op == "CONST":
        return e.value
    if e.op == "SLOT":
        if slot_value is None:
            raise ValueError("slot used without value")
        return int(slot_value)
    if e.op == "MACRO":
        if e.name not in macros:
            raise ValueError(f"unknown macro {e.name}")
        arg = eod_expr_eval(e.args[0], obj, macros, slot_value)
        return eod_expr_eval(macros[e.name].body, obj, macros, arg)
    a = eod_expr_eval(e.args[0], obj, macros, slot_value)
    b = eod_expr_eval(e.args[1], obj, macros, slot_value)
    if e.op == "ADD":
        return a + b
    if e.op == "SUB":
        return a - b
    if e.op == "MUL":
        return a * b
    if e.op == "MAX":
        return a if a >= b else b
    if e.op == "MIN":
        return a if a <= b else b
    raise ValueError(f"unknown op {e.op}")


def eod_synthesize(task: GDXTask,
                   macros: Dict[str, GDXMacro],
                   max_cost: int) -> Optional[GDXExpr]:
    features = eod_candidate_features([x for x, _ in task.train])
    exprs = gdx_enumerate_exprs(macros, max_cost, features=features)
    for expr in exprs:
        ok = True
        for x, y in task.train:
            try:
                if eod_expr_eval(expr, x, macros) != y:
                    ok = False
                    break
            except Exception:
                ok = False
                break
        if ok:
            return expr
    return None


def eod_validates(task: GDXTask, expr: GDXExpr,
                  macros: Dict[str, GDXMacro]) -> bool:
    for x, y in task.holdout:
        try:
            if eod_expr_eval(expr, x, macros) != y:
                return False
        except Exception:
            return False
    return True


def eod_solve_tasks(tasks: Sequence[GDXTask],
                    macros: Dict[str, GDXMacro],
                    max_cost: int) -> Dict[str, object]:
    rows = []
    solved: Dict[str, GDXExpr] = {}
    feature_counts: Dict[str, int] = {}
    for task in tasks:
        features = eod_candidate_features([x for x, _ in task.train])
        feature_counts[task.name] = len(features)
        expr = eod_synthesize(task, macros, max_cost)
        valid = bool(expr is not None and eod_validates(task, expr, macros))
        if valid and expr is not None:
            solved[task.name] = expr
        rows.append({
            "name": task.name,
            "domain": task.domain,
            "validated": valid,
            "expr": gdx_expr_key(expr) if expr is not None else "",
            "feature_count": len(features),
            "emergent_features": [
                f for f in features
                if f.startswith("KEYSUM_") or f.startswith("KEYCOUNT_")
            ][:8],
        })
    return {
        "validated": sum(1 for row in rows if row["validated"]),
        "total": len(rows),
        "rows": rows,
        "solved_exprs": solved,
        "feature_counts": feature_counts,
    }


def build_emergent_domain_tasks() -> Tuple[List[GDXTask], List[GDXTask], List[GDXTask]]:
    source = {
        "workflow_signal": (
            {"job": {"signal": 2, "noise": 100}, "steps": [{"noise": 7}]},
            {"job": {"signal": 3}, "noise": [4, 5]},
            {"signal": 4, "meta": {"noise": 9}},
        ),
        "market_alpha": (
            {"portfolio": [{"alpha": 1}, {"alpha": 2}], "beta": 50},
            {"portfolio": [{"alpha": 4}], "beta": 2},
            {"book": {"alpha": 3, "cash": 99}},
        ),
        "medical_marker": (
            {"patient": {"marker": 2, "age": 60}, "labs": [{"noise": 8}]},
            {"patient": {"marker": 5}, "labs": [{"noise": 1}]},
            {"marker": 3, "other": [10, 11]},
        ),
        "policy_weight": (
            {"clause": {"weight": 1}, "appendix": {"weight": 2}, "page": 30},
            {"sections": [{"weight": 7}], "page": 5},
            {"weight": 3, "irrelevant": {"score": 100}},
        ),
    }
    source_holdout = {
        "workflow_signal": (
            {"job": {"signal": 5}, "steps": [{"noise": 7}, {"noise": 8}]},
            {"signal": 1, "noise": 99},
        ),
        "market_alpha": (
            {"portfolio": [{"alpha": 2}, {"alpha": 5}], "beta": 9},
            {"book": {"alpha": 6}, "beta": 4},
        ),
        "medical_marker": (
            {"patient": {"marker": 4, "age": 70}},
            {"marker": 1, "other": [20]},
        ),
        "policy_weight": (
            {"sections": [{"weight": 2}, {"weight": 2}], "page": 9},
            {"weight": 5, "irrelevant": {"score": 1}},
        ),
    }
    train = [
        GDXTask("workflow_signal_square", "workflow_source",
               _gdx_pairs(source["workflow_signal"], lambda x: eod_features(x)["KEYSUM_signal"] ** 2),
               _gdx_pairs(source_holdout["workflow_signal"], lambda x: eod_features(x)["KEYSUM_signal"] ** 2)),
        GDXTask("market_alpha_square", "market_source",
               _gdx_pairs(source["market_alpha"], lambda x: eod_features(x)["KEYSUM_alpha"] ** 2),
               _gdx_pairs(source_holdout["market_alpha"], lambda x: eod_features(x)["KEYSUM_alpha"] ** 2)),
        GDXTask("medical_marker_square", "medical_source",
               _gdx_pairs(source["medical_marker"], lambda x: eod_features(x)["KEYSUM_marker"] ** 2),
               _gdx_pairs(source_holdout["medical_marker"], lambda x: eod_features(x)["KEYSUM_marker"] ** 2)),
        GDXTask("policy_weight_square", "policy_source",
               _gdx_pairs(source["policy_weight"], lambda x: eod_features(x)["KEYSUM_weight"] ** 2),
               _gdx_pairs(source_holdout["policy_weight"], lambda x: eod_features(x)["KEYSUM_weight"] ** 2)),
    ]

    frontier = [
        GDXTask("chemistry_energy_fourth", "chemistry_unseen",
               _gdx_pairs((
                   {"molecule": {"energy": 2, "mass": 99}},
                   {"atoms": [{"energy": 1}, {"energy": 2}], "mass": 40},
                   {"energy": 4, "distractor": [7, 8]},
               ), lambda x: eod_features(x)["KEYSUM_energy"] ** 4),
               _gdx_pairs((
                   {"molecule": {"energy": 3, "mass": 100}},
                   {"atoms": [{"energy": 2}, {"energy": 3}], "mass": 9},
               ), lambda x: eod_features(x)["KEYSUM_energy"] ** 4)),
        GDXTask("legal_risk_depth_square", "legal_unseen",
               _gdx_pairs((
                   {"clause": {"risk": 2, "text": "x"}, "noise": 50},
                   {"section": {"sub": {"risk": 1}}, "noise": [7, 8]},
                   {"risk": 3, "appendix": {"noise": 9}},
               ), lambda x: (eod_features(x)["KEYSUM_risk"] + eod_features(x)["DEPTH"]) ** 2),
               _gdx_pairs((
                   {"clause": {"risk": 4}, "noise": 1},
                   {"outer": {"inner": {"risk": 2}}, "noise": 10},
               ), lambda x: (eod_features(x)["KEYSUM_risk"] + eod_features(x)["DEPTH"]) ** 2)),
        GDXTask("robot_latency_fourth", "robotics_unseen",
               _gdx_pairs((
                   {"route": [{"latency": 1}, {"latency": 2}], "battery": 50},
                   {"plan": {"latency": 4}, "battery": 1},
                   {"latency": 3, "noise": [10]},
               ), lambda x: eod_features(x)["KEYSUM_latency"] ** 4),
               _gdx_pairs((
                   {"route": [{"latency": 2}, {"latency": 3}], "battery": 80},
                   {"plan": {"latency": 1}, "battery": 99},
               ), lambda x: eod_features(x)["KEYSUM_latency"] ** 4)),
        GDXTask("music_tone_count_square", "music_unseen",
               _gdx_pairs((
                   {"score": [{"tone": 2}, {"tone": 3}], "tempo": 120},
                   {"score": [{"tone": 3}], "tempo": 90},
                   {"tone": 1, "noise": [8, 9]},
               ), lambda x: (eod_features(x)["KEYSUM_tone"] + eod_features(x)["KEYCOUNT_tone"]) ** 2),
               _gdx_pairs((
                   {"score": [{"tone": 4}, {"tone": 1}], "tempo": 100},
                   {"tone": 2, "noise": 60},
               ), lambda x: (eod_features(x)["KEYSUM_tone"] + eod_features(x)["KEYCOUNT_tone"]) ** 2)),
        GDXTask("climate_flux_fourth", "climate_unseen",
               _gdx_pairs((
                   {"cells": [{"flux": 1}, {"flux": 1}, {"flux": 1}], "year": 2030},
                   {"flux": 2, "meta": {"noise": 70}},
                   {"grid": {"flux": 4}, "noise": [3]},
               ), lambda x: eod_features(x)["KEYSUM_flux"] ** 4),
               _gdx_pairs((
                   {"cells": [{"flux": 2}, {"flux": 2}], "year": 2040},
                   {"flux": 3, "noise": 9},
               ), lambda x: eod_features(x)["KEYSUM_flux"] ** 4)),
        GDXTask("security_severity_depth_square", "security_unseen",
               _gdx_pairs((
                   {"incident": {"aaa": 99, "severity": 2}, "noise": 99},
                   {"incident": {"nested": {"aaa": 8, "severity": 1}}, "noise": [4]},
                   {"aaa": 100, "severity": 3, "notes": "ignore"},
               ), lambda x: (eod_features(x)["KEYSUM_severity"] + eod_features(x)["DEPTH"]) ** 2),
               _gdx_pairs((
                   {"incident": {"aaa": 7, "severity": 4}, "noise": 11},
                   {"incident": {"nested": {"aaa": 6, "severity": 2}}, "noise": 1},
               ), lambda x: (eod_features(x)["KEYSUM_severity"] + eod_features(x)["DEPTH"]) ** 2)),
    ]

    unsupported = [
        GDXTask("semantic_negation_scope", "semantic_unsupported",
               _gdx_pairs((
                   "not approved",
                   "approved",
                   "not denied",
                   "denied",
               ), lambda x: 1 if x.startswith("not ") else 0),
               _gdx_pairs(("not ready", "ready", "notice"), lambda x: 1 if x.startswith("not ") else 0)),
        GDXTask("nonlocal_graph_reachability", "algorithmic_unsupported",
               _gdx_pairs((
                   {"nodes": ["a", "b", "c"], "edges": [["a", "b"], ["b", "c"]], "query": ["a", "c"]},
                   {"nodes": ["a", "b"], "edges": [["a", "b"]], "query": ["b", "a"]},
                   {"nodes": ["x"], "edges": [], "query": ["x", "x"]},
               ), lambda x: 1 if x["query"] == ["a", "c"] or x["query"][0] == x["query"][1] else 0),
               _gdx_pairs((
                   {"nodes": ["a", "b", "c", "d"], "edges": [["a", "b"], ["b", "c"], ["c", "d"]], "query": ["a", "d"]},
                   {"nodes": ["m", "n"], "edges": [["m", "n"]], "query": ["n", "m"]},
               ), lambda x: 1 if x["query"] == ["a", "d"] else 0)),
    ]
    return train, frontier, unsupported


def emergent_domain_report() -> Dict[str, object]:
    train, frontier, unsupported = build_emergent_domain_tasks()
    cold_macros: Dict[str, GDXMacro] = {}
    train_result = eod_solve_tasks(train, cold_macros, max_cost=3)
    solved_train: Dict[str, GDXExpr] = train_result["solved_exprs"]  # type: ignore[assignment]
    proposed = gdx_mine_macros(solved_train, cold_macros, min_support=2, max_new=3)
    candidate_macros = dict(cold_macros)
    for macro in proposed:
        candidate_macros[macro.name] = macro

    cold_frontier = eod_solve_tasks(frontier, cold_macros, max_cost=4)
    warm_frontier = eod_solve_tasks(frontier, candidate_macros, max_cost=4)
    accepted = int(warm_frontier["validated"]) > int(cold_frontier["validated"])
    accepted_macros = candidate_macros if accepted else cold_macros
    unsupported_result = eod_solve_tasks(unsupported, accepted_macros, max_cost=4)
    recursive_rows = [
        row for row in warm_frontier["rows"]  # type: ignore[index]
        if "GM0(GM0" in str(row.get("expr", ""))
    ]
    public_train_inputs = [x for task in list(train) + list(frontier)
                           for x, _ in task.train]
    invented_features = sorted(
        {
            feat for feat in eod_candidate_features(public_train_inputs)
            if feat.startswith("KEYSUM_") or feat.startswith("KEYCOUNT_")
        },
        key=lambda name: (0 if name.startswith("KEYSUM_") else 1, name),
    )
    return {
        "claim_boundary": (
            "emergent key-feature invention plus recursive macro reuse over "
            "unregistered JSON-like domains; still a falsifiable benchmark, "
            "not a proof of RSI for every mathematically possible domain"
        ),
        "feature_discovery": (
            "features are discovered by recursive object traversal from public "
            "train inputs; hidden holdout is validation-only"
        ),
        "source_domains": sorted({task.domain for task in train}),
        "frontier_domains": sorted({task.domain for task in frontier}),
        "train_validated": train_result["validated"],
        "train_total": train_result["total"],
        "invented_feature_examples": invented_features[:40],
        "proposed_macros": [
            {
                "name": macro.name,
                "body": gdx_expr_key(macro.body),
                "source_tasks": list(macro.source_tasks),
            }
            for macro in proposed
        ],
        "meta_gate": {
            "accepted": accepted,
            "cold_frontier_validated": cold_frontier["validated"],
            "warm_frontier_validated": warm_frontier["validated"],
            "delta": int(warm_frontier["validated"]) - int(cold_frontier["validated"]),
            "budget_max_cost": 4,
            "recursive_self_composition_rows": len(recursive_rows),
        },
        "cold_frontier": {k: v for k, v in cold_frontier.items() if k != "solved_exprs"},
        "warm_frontier": {k: v for k, v in warm_frontier.items() if k != "solved_exprs"},
        "unsupported_probe": {k: v for k, v in unsupported_result.items() if k != "solved_exprs"},
    }


def run_emergent_domain_self_improvement_test(save_path: str = "") -> int:
    report = emergent_domain_report()
    if save_path:
        with open(save_path, "w", encoding="utf-8") as f:
            json.dump(report, f, indent=2, sort_keys=True)
    print(json.dumps(report, indent=2, sort_keys=True))
    meta = report["meta_gate"]  # type: ignore[assignment]
    if not meta["accepted"]:  # type: ignore[index]
        return 1
    if int(meta["cold_frontier_validated"]) != 0:  # type: ignore[index]
        return 1
    if int(meta["warm_frontier_validated"]) < 6:  # type: ignore[index]
        return 1
    if int(meta["recursive_self_composition_rows"]) < 3:  # type: ignore[index]
        return 1
    unsupported = report["unsupported_probe"]  # type: ignore[assignment]
    if int(unsupported["validated"]) != 0:  # type: ignore[index]
        return 1
    return 0


@dataclass(frozen=True)
class SXFeatureSpec:
    name: str
    kind: str
    param: str = ""


def _sx_json_key(value: object) -> str:
    return json.dumps(value, sort_keys=True, separators=(",", ":"),
                      default=str)


def _sx_recursive_key_values(obj, key_name: str) -> List[object]:
    out: List[object] = []
    if isinstance(obj, dict):
        for key in sorted(obj, key=lambda k: str(k)):
            value = obj[key]
            if str(key) == key_name:
                out.append(value)
            out.extend(_sx_recursive_key_values(value, key_name))
    elif isinstance(obj, (list, tuple)):
        for item in obj:
            out.extend(_sx_recursive_key_values(item, key_name))
    return out


def _sx_graph_shortest_query(obj) -> int:
    if not isinstance(obj, dict):
        return 0
    nodes = obj.get("nodes")
    edges = obj.get("edges")
    query = obj.get("query")
    if not isinstance(nodes, (list, tuple)) or not isinstance(edges, (list, tuple)):
        return 0
    if not isinstance(query, (list, tuple)) or len(query) != 2:
        return 0
    start, goal = str(query[0]), str(query[1])
    graph: Dict[str, List[str]] = {str(n): [] for n in nodes}
    for edge in edges:
        if isinstance(edge, (list, tuple)) and len(edge) >= 2:
            graph.setdefault(str(edge[0]), []).append(str(edge[1]))
    if start == goal:
        return 0
    frontier = [(start, 0)]
    seen = {start}
    for node, dist in frontier:
        for nxt in graph.get(node, []):
            if nxt == goal:
                return dist + 1
            if nxt not in seen:
                seen.add(nxt)
                frontier.append((nxt, dist + 1))
    return 0


def _sx_num_inc_run(obj) -> int:
    nums = _gdx_numbers(obj)
    if not nums:
        return 0
    best = cur = 1
    for prev, cur_val in zip(nums, nums[1:]):
        if cur_val > prev:
            cur += 1
        else:
            cur = 1
        best = max(best, cur)
    return best


def _sx_find_matrix(obj) -> List[List[int]]:
    if isinstance(obj, dict):
        for key in ("pixels", "matrix", "grid"):
            if key in obj:
                found = _sx_find_matrix(obj[key])
                if found:
                    return found
        for key in sorted(obj, key=lambda k: str(k)):
            found = _sx_find_matrix(obj[key])
            if found:
                return found
    if isinstance(obj, (list, tuple)) and obj \
            and all(isinstance(row, (list, tuple)) for row in obj):
        rows: List[List[int]] = []
        for row in obj:
            vals: List[int] = []
            for cell in row:
                if isinstance(cell, (int, float, bool)):
                    vals.append(int(cell))
                else:
                    return []
            rows.append(vals)
        return rows
    return []


def _sx_matrix_diag_sum(obj) -> int:
    mat = _sx_find_matrix(obj)
    if not mat:
        return 0
    return int(sum(mat[i][i] for i in range(min(len(mat), min(len(r) for r in mat)))))


def _sx_matrix_positive_components(obj) -> int:
    mat = _sx_find_matrix(obj)
    if not mat:
        return 0
    rows = len(mat)
    cols = max((len(row) for row in mat), default=0)
    seen = set()
    comps = 0
    for r in range(rows):
        for c in range(len(mat[r])):
            if mat[r][c] <= 0 or (r, c) in seen:
                continue
            comps += 1
            stack = [(r, c)]
            seen.add((r, c))
            while stack:
                cr, cc = stack.pop()
                for nr, nc in ((cr - 1, cc), (cr + 1, cc), (cr, cc - 1), (cr, cc + 1)):
                    if 0 <= nr < rows and 0 <= nc < len(mat[nr]) \
                            and mat[nr][nc] > 0 and (nr, nc) not in seen:
                        seen.add((nr, nc))
                        stack.append((nr, nc))
    return int(comps)


def _sx_find_intervals(obj) -> List[Tuple[int, int]]:
    if isinstance(obj, dict):
        if isinstance(obj.get("intervals"), (list, tuple)):
            return _sx_find_intervals(obj["intervals"])
        for key in sorted(obj, key=lambda k: str(k)):
            found = _sx_find_intervals(obj[key])
            if found:
                return found
    if isinstance(obj, (list, tuple)):
        out: List[Tuple[int, int]] = []
        for item in obj:
            if isinstance(item, (list, tuple)) and len(item) >= 2 \
                    and isinstance(item[0], (int, float)) \
                    and isinstance(item[1], (int, float)):
                a, b = int(item[0]), int(item[1])
                out.append((min(a, b), max(a, b)))
            else:
                found = _sx_find_intervals(item)
                if found:
                    return found
        return out
    return []


def _sx_interval_overlap_count(obj) -> int:
    intervals = _sx_find_intervals(obj)
    total = 0
    for i, (a0, a1) in enumerate(intervals):
        for b0, b1 in intervals[i + 1:]:
            if max(a0, b0) <= min(a1, b1):
                total += 1
    return int(total)


def _sx_text_balanced_brackets(obj) -> int:
    text = "".join(_gdx_flat_strings(obj))
    pairs = {")": "(", "]": "[", "}": "{"}
    opens = set(pairs.values())
    stack: List[str] = []
    for ch in text:
        if ch in opens:
            stack.append(ch)
        elif ch in pairs:
            if not stack or stack.pop() != pairs[ch]:
                return 0
    return 1 if not stack else 0


def _sx_pair_abs_diff_sum(obj) -> int:
    nums = _gdx_numbers(obj)
    return int(sum(abs(b - a) for a, b in zip(nums, nums[1:])))


def _sx_text_unique_words(obj) -> int:
    words = set()
    for text in _gdx_flat_strings(obj):
        cur = []
        for ch in text.lower():
            if ch.isalnum():
                cur.append(ch)
            elif cur:
                words.add("".join(cur))
                cur = []
        if cur:
            words.add("".join(cur))
    return int(len(words))


def _sx_matrix_border_sum(obj) -> int:
    mat = _sx_find_matrix(obj)
    if not mat:
        return 0
    total = 0
    rows = len(mat)
    for r, row in enumerate(mat):
        for c, val in enumerate(row):
            if r == 0 or r == rows - 1 or c == 0 or c == len(row) - 1:
                total += int(val)
    return int(total)


def _sx_eval_spec(obj, spec: SXFeatureSpec) -> int:
    if spec.kind == "graph_shortest":
        return _sx_graph_shortest_query(obj)
    if spec.kind == "graph_reachable":
        return 1 if _sx_graph_shortest_query(obj) > 0 else 0
    if spec.kind == "num_inc_run":
        return _sx_num_inc_run(obj)
    if spec.kind == "key_distinct":
        vals = _sx_recursive_key_values(obj, spec.param)
        return len({_sx_json_key(v) for v in vals})
    if spec.kind == "text_prefix":
        prefix = spec.param
        return 1 if any(s.lower().startswith(prefix) for s in _gdx_flat_strings(obj)) else 0
    if spec.kind == "text_contains":
        token = spec.param
        return 1 if any(token in s.lower() for s in _gdx_flat_strings(obj)) else 0
    if spec.kind == "matrix_diag_sum":
        return _sx_matrix_diag_sum(obj)
    if spec.kind == "matrix_components":
        return _sx_matrix_positive_components(obj)
    if spec.kind == "interval_overlap_count":
        return _sx_interval_overlap_count(obj)
    if spec.kind == "text_balanced_brackets":
        return _sx_text_balanced_brackets(obj)
    if spec.kind == "pair_abs_diff_sum":
        return _sx_pair_abs_diff_sum(obj)
    if spec.kind == "text_unique_words":
        return _sx_text_unique_words(obj)
    if spec.kind == "matrix_border_sum":
        return _sx_matrix_border_sum(obj)
    raise ValueError(f"unknown SX feature kind {spec.kind}")


def sx_features(obj, specs: Sequence[SXFeatureSpec]) -> Dict[str, int]:
    out = eod_features(obj)
    for spec in specs:
        out[spec.name] = int(_sx_eval_spec(obj, spec))
    return out


def sx_candidate_features(inputs: Sequence[object],
                          specs: Sequence[SXFeatureSpec]) -> Tuple[str, ...]:
    names = set()
    for obj in inputs:
        names.update(sx_features(obj, specs))
    return tuple(sorted(names))


def sx_expr_eval(e: GDXExpr, obj, macros: Dict[str, GDXMacro],
                 specs: Sequence[SXFeatureSpec],
                 slot_value: Optional[int] = None) -> int:
    if e.op == "FEATURE":
        return sx_features(obj, specs).get(e.name, 0)
    if e.op == "CONST":
        return e.value
    if e.op == "SLOT":
        if slot_value is None:
            raise ValueError("slot used without value")
        return int(slot_value)
    if e.op == "MACRO":
        if e.name not in macros:
            raise ValueError(f"unknown macro {e.name}")
        arg = sx_expr_eval(e.args[0], obj, macros, specs, slot_value)
        return sx_expr_eval(macros[e.name].body, obj, macros, specs, arg)
    a = sx_expr_eval(e.args[0], obj, macros, specs, slot_value)
    b = sx_expr_eval(e.args[1], obj, macros, specs, slot_value)
    if e.op == "ADD":
        return a + b
    if e.op == "SUB":
        return a - b
    if e.op == "MUL":
        return a * b
    if e.op == "MAX":
        return a if a >= b else b
    if e.op == "MIN":
        return a if a <= b else b
    raise ValueError(f"unknown op {e.op}")


def sx_synthesize(task: GDXTask,
                  macros: Dict[str, GDXMacro],
                  specs: Sequence[SXFeatureSpec],
                  max_cost: int) -> Optional[GDXExpr]:
    features = sx_candidate_features([x for x, _ in task.train], specs)
    for expr in gdx_enumerate_exprs(macros, max_cost, features=features):
        ok = True
        for x, y in task.train:
            try:
                if sx_expr_eval(expr, x, macros, specs) != y:
                    ok = False
                    break
            except Exception:
                ok = False
                break
        if ok:
            return expr
    return None


def sx_validates(task: GDXTask, expr: GDXExpr,
                 macros: Dict[str, GDXMacro],
                 specs: Sequence[SXFeatureSpec]) -> bool:
    for x, y in task.holdout:
        try:
            if sx_expr_eval(expr, x, macros, specs) != y:
                return False
        except Exception:
            return False
    return True


def sx_solve_tasks(tasks: Sequence[GDXTask],
                   macros: Dict[str, GDXMacro],
                   specs: Sequence[SXFeatureSpec],
                   max_cost: int) -> Dict[str, object]:
    rows = []
    solved: Dict[str, GDXExpr] = {}
    for task in tasks:
        features = sx_candidate_features([x for x, _ in task.train], specs)
        expr = sx_synthesize(task, macros, specs, max_cost)
        valid = bool(expr is not None and sx_validates(task, expr, macros, specs))
        if valid and expr is not None:
            solved[task.name] = expr
        rows.append({
            "name": task.name,
            "domain": task.domain,
            "validated": valid,
            "expr": gdx_expr_key(expr) if expr is not None else "",
            "feature_count": len(features),
            "adopted_dynamic_features": [
                spec.name for spec in specs if spec.name in features
            ],
        })
    return {
        "validated": sum(1 for row in rows if row["validated"]),
        "total": len(rows),
        "rows": rows,
        "solved_exprs": solved,
    }


def sx_invent_feature_specs_from_failures(tasks: Sequence[GDXTask]) -> List[SXFeatureSpec]:
    specs: Dict[str, SXFeatureSpec] = {}

    def add(spec: SXFeatureSpec) -> None:
        specs.setdefault(spec.name, spec)

    for task in tasks:
        for obj, _ in task.train:
            strings = [s.lower() for s in _gdx_flat_strings(obj)]
            for text in strings:
                first = text.split()[0] if text.split() else ""
                if first and len(first) <= 16:
                    safe = _eod_safe_key(first.lower())
                    add(SXFeatureSpec(f"TEXT_PREFIX_{safe}", "text_prefix",
                                      first.lower()))
                for token in text.replace("_", " ").split():
                    if 2 <= len(token) <= 16:
                        safe = _eod_safe_key(token.lower())
                        add(SXFeatureSpec(f"TEXT_CONTAINS_{safe}",
                                          "text_contains", token.lower()))
            if isinstance(obj, dict) and {"nodes", "edges", "query"} <= set(obj):
                add(SXFeatureSpec("GRAPH_SHORTEST_QUERY", "graph_shortest"))
                add(SXFeatureSpec("GRAPH_REACHABLE_QUERY", "graph_reachable"))
            if _gdx_numbers(obj):
                add(SXFeatureSpec("NUM_INC_RUN", "num_inc_run"))
            if _sx_find_matrix(obj):
                add(SXFeatureSpec("MATRIX_DIAG_SUM", "matrix_diag_sum"))
                add(SXFeatureSpec("MATRIX_COMPONENTS", "matrix_components"))
            if _sx_find_intervals(obj):
                add(SXFeatureSpec("INTERVAL_OVERLAP_COUNT",
                                  "interval_overlap_count"))
            if any(ch in s for s in strings for ch in "()[]{}"):
                add(SXFeatureSpec("TEXT_BALANCED_BRACKETS",
                                  "text_balanced_brackets"))
            for key in sorted(eod_features(obj)):
                if key.startswith("KEYCOUNT_"):
                    raw = key[len("KEYCOUNT_"):]
                    add(SXFeatureSpec(f"KEYDISTINCT_{raw}", "key_distinct",
                                      raw))
    return [specs[name] for name in sorted(specs)]


def build_longcycle_attempt_tasks() -> Tuple[List[GDXTask], List[GDXTask], List[GDXTask]]:
    train, _, _ = build_emergent_domain_tasks()
    frontier = [
        GDXTask("graph_shortest_square", "residue_graph_algorithm",
               _gdx_pairs((
                   {"nodes": ["a", "b", "c"], "edges": [["a", "b"], ["b", "c"]], "query": ["a", "c"]},
                   {"nodes": ["a", "b"], "edges": [["a", "b"]], "query": ["a", "b"]},
                   {"nodes": ["x"], "edges": [], "query": ["x", "x"]},
                   {"nodes": ["p", "q", "r"], "edges": [["p", "q"]], "query": ["p", "r"]},
               ), lambda x: _sx_graph_shortest_query(x) ** 2),
               _gdx_pairs((
                   {"nodes": ["p", "q", "r", "s"], "edges": [["p", "q"], ["q", "r"], ["r", "s"], ["p", "s"]], "query": ["p", "s"]},
                   {"nodes": ["m", "n"], "edges": [["m", "n"]], "query": ["n", "m"]},
               ), lambda x: _sx_graph_shortest_query(x) ** 2)),
        GDXTask("sequence_inc_run_fourth", "residue_sequence_algorithm",
               _gdx_pairs((
                   [1, 2, 3, 0],
                   [3, 2, 1],
                   [1, 3, 2, 4, 5],
                   [5],
               ), lambda x: _sx_num_inc_run(x) ** 4),
               _gdx_pairs((
                   [0, 1, 2, 3, 4],
                   [5, 1, 2, 0, 3],
               ), lambda x: _sx_num_inc_run(x) ** 4)),
        GDXTask("table_distinct_user_square", "residue_table_identity",
               _gdx_pairs((
                   [{"user": "a", "v": 1}, {"user": "b", "v": 2}, {"user": "a", "v": 3}],
                   [{"user": "x", "v": 9}],
                   [{"user": "m"}, {"user": "n"}, {"user": "o"}],
               ), lambda x: len({_sx_json_key(v) for v in _sx_recursive_key_values(x, "user")}) ** 2),
               _gdx_pairs((
                   [{"user": "a"}, {"user": "b"}, {"user": "c"}, {"user": "a"}],
                   [{"user": "z"}, {"user": "z"}],
               ), lambda x: len({_sx_json_key(v) for v in _sx_recursive_key_values(x, "user")}) ** 2)),
        GDXTask("text_negation_prefix_square", "residue_text_pattern",
               _gdx_pairs((
                   "not approved",
                   "approved",
                   "not denied",
                   "ready",
               ), lambda x: (1 if x.lower().startswith("not") else 0) ** 2),
               _gdx_pairs(("not ready", "notice", "allowed"),
                         lambda x: (1 if x.lower().startswith("not") else 0) ** 2)),
    ]
    unsupported = [
        GDXTask("ambiguous_text_semantics", "unsupported_semantic_collision",
               _gdx_pairs((
                   "ab",
                   "ba",
               ), lambda x: 1 if x == "ab" else 0),
               _gdx_pairs((
                   "aa",
                   "bb",
               ), lambda x: 1 if x == "bb" else 0)),
        GDXTask("ambiguous_graph_semantics", "unsupported_graph_collision",
               _gdx_pairs((
                   {"nodes": ["a", "b"], "edges": [["a", "b"]], "query": ["a", "b"]},
                   {"nodes": ["a", "b"], "edges": [["a", "b"]], "query": ["a", "b"]},
               ), lambda x: 0),
               _gdx_pairs((
                   {"nodes": ["x", "y"], "edges": [["x", "y"]], "query": ["x", "y"]},
                   {"nodes": ["x", "y"], "edges": [["x", "y"]], "query": ["x", "y"]},
               ), lambda x: 1)),
    ]
    return train, frontier, unsupported


def longcycle_attempt_report() -> Dict[str, object]:
    train, frontier, unsupported = build_longcycle_attempt_tasks()
    cold_macros: Dict[str, GDXMacro] = {}
    train_result = eod_solve_tasks(train, cold_macros, max_cost=3)
    solved_train: Dict[str, GDXExpr] = train_result["solved_exprs"]  # type: ignore[assignment]
    proposed = gdx_mine_macros(solved_train, cold_macros, min_support=2, max_new=3)
    macros = dict(cold_macros)
    for macro in proposed:
        macros[macro.name] = macro

    before_residue = eod_solve_tasks(frontier, macros, max_cost=4)
    failed = [
        task for task, row in zip(frontier, before_residue["rows"])  # type: ignore[index]
        if not row["validated"]
    ]
    invented_specs = sx_invent_feature_specs_from_failures(failed)
    after_residue = sx_solve_tasks(frontier, macros, invented_specs, max_cost=4)
    unsupported_result = sx_solve_tasks(unsupported, macros, invented_specs, max_cost=4)
    recursive_rows = [
        row for row in after_residue["rows"]  # type: ignore[index]
        if "GM0(" in str(row.get("expr", ""))
    ]
    return {
        "claim_boundary": (
            "finite longcycle-attempt loop: failure residues invent feature "
            "families and rerun synthesis; not actual technological longcycle"
        ),
        "train_validated": train_result["validated"],
        "train_total": train_result["total"],
        "proposed_macros": [
            {
                "name": macro.name,
                "body": gdx_expr_key(macro.body),
                "source_tasks": list(macro.source_tasks),
            }
            for macro in proposed
        ],
        "residue_loop": {
            "failed_before_residue": len(failed),
            "invented_feature_count": len(invented_specs),
            "invented_feature_examples": [s.name for s in invented_specs[:24]],
        },
        "meta_gate": {
            "accepted": int(after_residue["validated"]) > int(before_residue["validated"]),
            "before_residue_validated": before_residue["validated"],
            "after_residue_validated": after_residue["validated"],
            "delta": int(after_residue["validated"]) - int(before_residue["validated"]),
            "recursive_macro_rows": len(recursive_rows),
            "budget_max_cost": 4,
        },
        "before_residue": {k: v for k, v in before_residue.items() if k != "solved_exprs"},
        "after_residue": {k: v for k, v in after_residue.items() if k != "solved_exprs"},
        "unsupported_probe": {k: v for k, v in unsupported_result.items() if k != "solved_exprs"},
    }


def run_longcycle_attempt_test(save_path: str = "") -> int:
    report = longcycle_attempt_report()
    if save_path:
        with open(save_path, "w", encoding="utf-8") as f:
            json.dump(report, f, indent=2, sort_keys=True)
    print(json.dumps(report, indent=2, sort_keys=True))
    meta = report["meta_gate"]  # type: ignore[assignment]
    if not meta["accepted"]:  # type: ignore[index]
        return 1
    if int(meta["before_residue_validated"]) != 0:  # type: ignore[index]
        return 1
    if int(meta["after_residue_validated"]) < 4:  # type: ignore[index]
        return 1
    if int(meta["recursive_macro_rows"]) < 3:  # type: ignore[index]
        return 1
    unsupported = report["unsupported_probe"]  # type: ignore[assignment]
    if int(unsupported["validated"]) != 0:  # type: ignore[index]
        return 1
    return 0


