# LatentNavigator - Neural Logic Memory Network (NLMN)
# ==============================================================================
try:
    import torch
    import torch.nn as nn
    import torch.nn.functional as F
    import torch.optim as optim
    HAS_TORCH = True
except ImportError:
    HAS_TORCH = False

class NLMN:
    """
    Advanced Meta-Learning System: Neural Logic Memory Network (NLMN)
    Replaces LatentNavigator.
    """
    def __init__(self, embedding_dim=64):
        print(f"DEBUG: NLMN.__init__ called. HAS_TORCH={HAS_TORCH}")
        self.enabled = HAS_TORCH
        if not self.enabled: return
        
        self.embedding_dim = embedding_dim
        
        # 1. Set Encoder Phi: (Input, Output) -> Feature
        # Maps (x, y) to a high-dimensional feature space
        self.phi = nn.Sequential(
            nn.Linear(2, 64),
            nn.ReLU(),
            nn.Linear(64, 64),
            nn.ReLU(),
            nn.Linear(64, embedding_dim)
        )
        
        # 2. Memory Bank
        # Keys: Tensor of shape (N, embedding_dim)
        # Values: List of Dict[str, float] (Priors)
        self.memory_keys = []
        self.memory_values = []
        
        self.optimizer = optim.Adam(self.phi.parameters(), lr=0.005)
        
    def encode_task(self, io_pairs):
        """
        DeepSets Logic: Aggregation(Phi(x) for x in X)
        Returns normalized task embedding.
        """
        if not io_pairs: return None
        
        features = []
        for p in io_pairs:
            # Normalize simply by tanh for stability
            inp = math.tanh(float(p['input']) * 0.1)
            out = math.tanh(float(p['output']) * 0.1)
            t = torch.tensor([inp, out], dtype=torch.float32)
            features.append(t)
            
        if not features: return None
        
        # Stack: (M, 2)
        batch = torch.stack(features)
        
        # Apply phi to each pair: (M, 64)
        phi_out = self.phi(batch)
        
        # Sum Pooling (Invariant Aggregation): (1, 64)
        task_vec = torch.sum(phi_out, dim=0, keepdim=True)
        
        # Normalize for Cosine Sim
        task_vec = F.normalize(task_vec, p=2, dim=1)
        return task_vec

    def get_priors(self, io_pairs):
        """Content-Addressable Retrieval"""
        if not self.enabled or not self.memory_keys: return {}
        
        with torch.no_grad():
            query_vec = self.encode_task(io_pairs) # (1, D)
            if query_vec is None: return {}
            
            # Stack memory keys: (K, D)
            keys = torch.cat(self.memory_keys, dim=0)
            
            # Cosine Similarity: (1, K)
            sims = torch.mm(query_vec, keys.t())
            
            # Find Best Match
            best_sim, best_idx = torch.max(sims, dim=1)
            best_sim = best_sim.item()
            best_idx = best_idx.item()
            
            print(f"    [NLMN] Memory Query: Best Sim={best_sim:.4f}")
            
            # Retrieval Threshold (Must be somewhat similar)
            if best_sim > 0.85:
                # "I remember this!"
                print(f"    [NLMN] 🧠 Memory Hit! Retrieving strategy from experience.")
                return self.memory_values[best_idx]
            elif best_sim > 0.5:
                 # "Vaguely familiar..." - Return blended/weaker priors? 
                 # For now, let's look for strong matches only to avoid confusion.
                 pass
                 
        return {}
        
    def learn(self, io_pairs, success_expr_str=None, **kwargs):
        """Episodic Storage: Store (Task, Solution). Accepts success kwarg for compatibility."""
        if not self.enabled: return
        # Handle legacy/alternate keyword args safely
        if success_expr_str is None and "success" in kwargs:
            success_expr_str = str(kwargs.get("success", ""))
        
        # 1. Extract idealized priors from solution string
        ideal_priors = {}
        # Count atoms in the success string to form a distribution
        count_map = {k: 0 for k in NAVIGATOR_ATOM_MAP}
        total = 0
        for k in NAVIGATOR_ATOM_MAP:
            if k in success_expr_str:
                count_map[k] += 1
                total += 1
        
        # Normalize to create a probability-like distribution, then scale to priors
        if total > 0:
            for k, c in count_map.items():
                if c > 0:
                    ideal_priors[k] = 5.0 # Strong hint
                else:
                    ideal_priors[k] = 0.1 # Suppression
        else:
            return

        # 2. Encode Task
        task_vec = self.encode_task(io_pairs)
        if task_vec is None: return
        
        # 3. Store in Memory
        # Check if we already have a very similar memory (Update vs Add)
        if self.memory_keys:
            # Flatten keys: list of [1, D] -> [N, D]
            keys = torch.cat(self.memory_keys, dim=0)
            
            # Query is [1, D], Keys is [N, D]. Broadcast to calculate N sims.
            sims = F.cosine_similarity(task_vec, keys, dim=1)
            
            best_sim, best_idx = torch.max(sims, dim=0)
            
            if best_sim.item() > 0.95:
                # Update existing memory? Or just ignore dupes?
                # Updating strategies might be good.
                self.memory_values[best_idx] = ideal_priors
                return

        self.memory_keys.append(task_vec)
        self.memory_values.append(ideal_priors)
        self.optimizer.zero_grad() # Keep optimizer alive but we don't 'train' parameters yet? 
        # Actually in Memory Networks, we might fine-tune the Encoder to separate task clusters.
        # But for now, Fixed Random Encoder + Memory is strong enough.
        
        print(f"    [NLMN] 🧠 Memorized new strategy. Total Memories: {len(self.memory_keys)}")

    def learn_from_partial(self, io_pairs, expr, hits, total):
        """
        Called when a solution is partial (not 100% correct).
        In the 'Goal-Less' architecture, we generally ignore these unless they are
        'Near Misses' (e.g., 99% accuracy) which might refine the memory.
        For now: No-Op to prevent crash.
        """
        pass

# ==============================================================================
# GrowthAnalyzer - Heuristic based on Growth Analysis (No Cheating!)
# ==============================================================================
class GrowthAnalyzer:
    """
    Analyzes the growth pattern of data to suggest operator priors only.
    Strictly NO code generation or injection.
    
    Principles:
    - Linear Growth -> Increase priors for '+', '-'
    - Geometric/Factorial Growth -> Increase priors for '*', 'Rec'
    - Fibonacci-like Growth -> Increase priors for '+', 'Rec'
    """
    
    def analyze_growth(self, io_pairs: List[Dict[str, Any]]) -> Dict[str, float]:
        if len(io_pairs) < 3: return {}
        
        sorted_io = sorted(io_pairs, key=lambda x: x['input'])
        ys = [p['output'] for p in sorted_io]
        
        priors = {}
        
        # 1. Check for Zero/Constant
        if all(y == 0 for y in ys):
            return {'Const': 2.0}
        if len(set(ys)) == 1:
            return {'Const': 2.0}

        # 2. Check Growth Rate
        diffs = [ys[i] - ys[i-1] for i in range(1, len(ys))]
        ratios = []
        for i in range(1, len(ys)):
            if ys[i-1] != 0:
                ratios.append(ys[i] / ys[i-1])
            else:
                ratios.append(0)
                
        # (A) Linear Pattern: Diffs are constant or slowly changing
        is_linear = False
        if len(set(diffs)) <= 2: # Constant diff
            is_linear = True
        elif all(abs(d1 - d2) <= 1 for d1, d2 in zip(diffs, diffs[1:])):
            is_linear = True
            
        if is_linear:
            priors['+'] = 1.5
            priors['-'] = 1.0
            priors['Const'] = 1.0
            priors['Arg'] = 1.2
        
        # (B) Geometric/Factorial Pattern - CHECK FIRST TO AVOID SPURIOUS RECURRENCE
        is_geometric = False
        is_factorial = False
        
        # 1. Geometric: Ratios roughly constant/large (> 1.2)
        ratio_growth = sum(1 for r in ratios if r > 1.2)
        if ratio_growth >= len(ratios) * 0.6:
            is_geometric = True
            
        # 2. Factorial-like: Ratios increasing (e.g., 1, 2, 3...)
        if len(ratios) >= 2:
            ratio_diffs = [ratios[i] - ratios[i-1] for i in range(1, len(ratios))]
            increasing_ratios = sum(1 for d in ratio_diffs if d >= 0.9)
            if increasing_ratios >= len(ratio_diffs) * 0.6:
                is_factorial = True

        # EARLY RETURN for Factorial/Geometric - these are multiplicative, not additive
        if is_factorial:
            print(f"    [GrowthAnalyzer] FACTORIAL pattern detected. Ratios: {[round(r,2) for r in ratios]}")
            priors['*'] = 20.0   # STRONG hint for multiplication
            priors['Rec'] = 20.0 # Rec is essential
            priors['+'] = 1.0    # Suppress additive
            priors['-'] = 5.0    # Essential for n-1
            return priors        # SKIP linear recurrence check
            
        if is_geometric:
            print(f"    [GrowthAnalyzer] Geometric pattern detected. Ratios: {[round(r,2) for r in ratios]}")
            priors['*'] = 10.0
            priors['Rec'] = 10.0
            priors['+'] = 2.0
            priors['-'] = 5.0
            return priors        # SKIP linear recurrence check

        # (C) Linear Recurrence Check (Depth 2) - "Honest Fibonacci Detector"
        # Only checked if NOT factorial/geometric
        recurrence_coeffs = self._check_linear_recurrence(sorted_io)
        if recurrence_coeffs:
            print(f"    [GrowthAnalyzer] Linear Recurrence Detected: {recurrence_coeffs} (Strong Hint for Rec+Add)")
            priors['Rec'] = 20.0
            priors['*'] = 0.5
            priors['+'] = 20.0
            priors['-'] = 5.0
            priors['Const'] = 1.0
            return priors
        
        return priors

    def _check_linear_recurrence(self, sorted_io):
        """
        General Affine Recurrence Solver (The 'Bible Code' Lens).
        Solves y[n] = c1*y[n-1] + c2*y[n-2] + c0 using Linear Algebra.
        
        STRICT: Only returns if the integer solution is EXACT.
        """
        ys = [p['output'] for p in sorted_io]
        inputs = [p['input'] for p in sorted_io]
        if len(ys) < 5: return None
        
        # Ensure contiguous inputs
        for i in range(1, len(inputs)):
            if inputs[i] != inputs[i-1] + 1: return None

        # Prepare matrices for: y[n] = c1*y[n-1] + c2*y[n-2] + c0
        A_rows = []
        B_rows = []
        
        for i in range(2, len(ys)):
            A_rows.append([ys[i-1], ys[i-2], 1.0])
            B_rows.append(ys[i])
            
        if not A_rows: return None
        
        try:
            if np:
                A = np.array(A_rows)
                B = np.array(B_rows)
                
                x, residuals, rank, s = np.linalg.lstsq(A, B, rcond=None)
                
                c1, c2, c0 = x
                
                # Round to nearest integer
                ic1, ic2, ic0 = int(round(c1)), int(round(c2)), int(round(c0))
                
                # STRICT VERIFICATION: Check if integer solution is EXACT
                is_exact = True
                for i in range(2, len(ys)):
                    predicted = ic1 * ys[i-1] + ic2 * ys[i-2] + ic0
                    if predicted != ys[i]:
                        is_exact = False
                        break
                
                if not is_exact:
                    # Not a linear recurrence (e.g., factorial is multiplicative)
                    return None
                
                # Filter trivial identity (1,0,0) -> y[n] = y[n-1] (Const)
                if ic1 == 1 and ic2 == 0 and ic0 == 0 and ys[0] == ys[1]:
                    return None
                    
                return (ic1, ic2, ic0)
            
            else:
                # Fallback to expanded candidates if no numpy
                candidates = [
                    (1, 1, 0), (1, -1, 0), (2, 0, 0), (1, 1, 1), 
                    (2, -1, 0), (1, 2, 0), (2, 1, 0),
                    (0, 1, 2), (0, 1, 0), (1, 0, 1),
                ]
                for c1, c2, c0 in candidates:
                    match = True
                    for i in range(2, len(ys)):
                        if c1 * ys[i-1] + c2 * ys[i-2] + c0 != ys[i]:
                            match = False
                            break
                    if match:
                        return (c1, c2, c0)

        except Exception:
            pass
            
        return None



class FeedbackCollector:
    """Collects feedback from synthesis attempts to improve future searches."""
    
    def __init__(self):
        self.attempts = []  # List of (expr, success, depth, behavior_hash)
        self.op_success_counts = {'+': 0, '-': 0, '*': 0, 'Rec': 0, 'Arg': 0, 'Const': 0}
        self.op_total_counts = {'+': 0, '-': 0, '*': 0, 'Rec': 0, 'Arg': 0, 'Const': 0}
        self.best_depth_reached = 0
        self.promising_patterns = []  # Expressions with high partial match scores
        
    def record_attempt(self, expr: 'BSExpr', passes: int, total: int, depth: int):
        """Record a synthesis attempt for learning."""
        success_rate = passes / max(1, total)
        atoms = self._extract_ops(expr)
        
        # Update operator counts
        for atom in atoms:
            if atom in self.op_total_counts:
                self.op_total_counts[atom] += 1
                if success_rate > 0.5:
                    self.op_success_counts[atom] += 1
        
        # Track promising patterns (partial matches)
        if success_rate > 0.3 and success_rate < 1.0:
            self.promising_patterns.append((str(expr), success_rate, depth))
            self.promising_patterns = self.promising_patterns[-50:]  # Keep last 50
            
        self.best_depth_reached = max(self.best_depth_reached, depth)
        
    def _extract_ops(self, expr: 'BSExpr') -> List[str]:
        """Extract operator types from an expression."""
        ops = []
        if isinstance(expr, BSBinOp):
            ops.append(expr.op)
            ops.extend(self._extract_ops(expr.left))
            ops.extend(self._extract_ops(expr.right))
        elif isinstance(expr, BSRecCall):
            ops.append('Rec')
            ops.extend(self._extract_ops(expr.arg))
        elif isinstance(expr, BSVar):
            ops.append('Arg')
        elif isinstance(expr, BSVal):
            ops.append('Const')
        return ops
    
    def get_learned_priors(self) -> Dict[str, float]:
        """Generate priors based on observed success rates."""
        priors = {}
        for op in self.op_total_counts:
            total = self.op_total_counts[op]
            if total > 0:
                success = self.op_success_counts[op]
                # Bayesian-like update: prior = (success + 1) / (total + 2)
                priors[op] = (success + 1) / (total + 2)
            else:
                priors[op] = 0.5  # Uninformative prior
        return priors
    
    def get_insights(self) -> Dict[str, Any]:
        """Return insights for debugging/logging."""
        return {
            "best_depth": self.best_depth_reached,
            "promising_count": len(self.promising_patterns),
            "learned_priors": self.get_learned_priors(),
        }

NAVIGATOR_ATOM_MAP = ["+", "-", "*", "Rec", "Arg", "Const"]

class LatentNavigator(nn.Module if torch else object):
    def __init__(self, input_dim=2, hidden_dim=64, num_atoms=6):
        super().__init__()
        self.active = bool(torch)
        if not self.active: return
        
        # Encoder: (batch, seq, 2) -> (batch, hidden)
        self.encoder = nn.GRU(input_dim, hidden_dim, batch_first=True)
        
        # Policy Head: (hidden) -> (num_atoms)
        self.policy = nn.Sequential(
             nn.Linear(hidden_dim, hidden_dim),
             nn.ReLU(),
             nn.Linear(hidden_dim, num_atoms),
             nn.Softmax(dim=-1)
        )
        self.optim = optim.Adam(self.parameters(), lr=0.005)

    def forward(self, x):
         if not self.active: return None
         _, h_n = self.encoder(x)
         return self.policy(h_n[-1])

    def get_priors(self, io_pairs: List[Dict[str, Any]]) -> Dict[str, float]:
         if not self.active: return {}
         feats = []
         for p in io_pairs:
             # Simple normalization
             feats.append([math.tanh(p['input']/10.0), math.tanh(p['output']/10.0)])
         
         xt = torch.tensor([feats], dtype=torch.float32)
         with torch.no_grad():
             probs = self(xt)[0].tolist()
         
         priors = {k: v for k, v in zip(NAVIGATOR_ATOM_MAP, probs)}
         
         return priors

    def learn(self, io_pairs: List[Dict[str, Any]], used_atoms: List[str], success: bool = True):
         """Learn from synthesis outcomes - both success and failure."""
         if not self.active: return
         self.optim.zero_grad()
         
         feats = []
         for p in io_pairs:
             feats.append([math.tanh(p['input']/10.0), math.tanh(p['output']/10.0)])
         xt = torch.tensor([feats], dtype=torch.float32)
         
         pred_probs = self(xt)[0] 
         
         target_indices = [NAVIGATOR_ATOM_MAP.index(a) for a in used_atoms if a in NAVIGATOR_ATOM_MAP]
         if not target_indices: return
         
         loss = torch.tensor(0.0, requires_grad=True)
         
         if success:
             # SUCCESS: Increase probability of used atoms
             for idx in target_indices:
                 loss = loss - torch.log(pred_probs[idx] + 1e-6)
         else:
             # FAILURE: Decrease probability of used atoms (they didn't help)
             for idx in target_indices:
                 # Penalize by decreasing log(1 - p) 
                 loss = loss + 0.3 * torch.log(pred_probs[idx] + 1e-6)
              
         loss.backward()
         self.optim.step()

    def learn_from_partial(self, io_pairs: List[Dict[str, Any]], expr: 'BSExpr', 
                           passes: int, total: int):
         """Learn from partial matches - expressions that almost worked."""
         if not self.active: return
         if passes == 0 or passes == total: return  # Only learn from partial matches
         
         success_rate = passes / total
         atoms = []
         if isinstance(expr, BSBinOp):
             atoms.append(expr.op)
         elif isinstance(expr, BSRecCall):
             atoms.append('Rec')
         
         if not atoms: return
         
         self.optim.zero_grad()
         
         feats = []
         for p in io_pairs:
             feats.append([math.tanh(p['input']/10.0), math.tanh(p['output']/10.0)])
         xt = torch.tensor([feats], dtype=torch.float32)
         
         pred_probs = self(xt)[0]
         
         # Weighted learning: the closer to success, the stronger the reinforcement
         weight = success_rate  # 0.8 match = 0.8 weight
         
         loss = torch.tensor(0.0, requires_grad=True)
         for atom in atoms:
             if atom in NAVIGATOR_ATOM_MAP:
                 idx = NAVIGATOR_ATOM_MAP.index(atom)
                 # Partial reinforcement - weighted by how close we were
                 loss = loss - weight * torch.log(pred_probs[idx] + 1e-6)
         
         if loss.item() != 0.0:
             loss.backward()
             self.optim.step()



@dataclass
class ReplaySample:
    task_id: str
    state_features: List[float]
    action: List[float]
    reward: float
    done: bool
    timestamp: float

class ReplayBuffer:
    def __init__(self, capacity: int = 50000):
        self.capacity = capacity
        self.buffer: List[ReplaySample] = []
        self.index = 0

    def add(self, sample: ReplaySample) -> None:
        if len(self.buffer) < self.capacity:
            self.buffer.append(sample)
        else:
            self.buffer[self.index] = sample
            self.index = (self.index + 1) % self.capacity

    def sample(self, batch_size: int) -> List[ReplaySample]:
        if not self.buffer:
            return []
        k = min(batch_size, len(self.buffer))
        return random.sample(self.buffer, k)

    def __len__(self) -> int:
        return len(self.buffer)

class PolicyModel:
    def __init__(self, input_dim: int, hidden_dim: int = 64, lr: float = 0.005):
        self.input_dim = input_dim
        self.hidden_dim = hidden_dim
        self.lr = lr
        self.use_torch = bool(torch)
        self.loss_ema: Optional[float] = None
        self.weight_norm: Optional[float] = None
        if self.use_torch:
            self.model = nn.Sequential(
                nn.Linear(input_dim, hidden_dim),
                nn.ReLU(),
                nn.Linear(hidden_dim, 1),
            )
            self.optimizer = optim.Adam(self.model.parameters(), lr=lr)
            self._last_params = [p.detach().clone() for p in self.model.parameters()]
        else:
            if np is None:
                self.W1 = [[random.uniform(-0.1, 0.1) for _ in range(hidden_dim)] for _ in range(input_dim)]
                self.b1 = [0.0 for _ in range(hidden_dim)]
                self.W2 = [random.uniform(-0.1, 0.1) for _ in range(hidden_dim)]
                self.b2 = 0.0
            else:
                self.W1 = np.random.uniform(-0.1, 0.1, size=(input_dim, hidden_dim))
                self.b1 = np.zeros(hidden_dim)
                self.W2 = np.random.uniform(-0.1, 0.1, size=(hidden_dim,))
                self.b2 = 0.0

    def _sanitize_features(self, features: List[List[float]]) -> List[List[float]]:
        sanitized = []
        for row in features:
            cleaned = []
            for v in row:
                if not math.isfinite(v):
                    cleaned.append(0.0)
                else:
                    cleaned.append(math.tanh(v))
            sanitized.append(cleaned)
        return sanitized

    def _relu(self, x):
        if np is None:
            return [max(0.0, v) for v in x]
        return np.maximum(0.0, x)

    def score(self, features: List[List[float]]) -> List[float]:
        features = self._sanitize_features(features)
        if self.use_torch:
            with torch.no_grad():
                xt = torch.tensor(features, dtype=torch.float32)
                scores = self.model(xt).squeeze(-1).tolist()
            if isinstance(scores, float):
                return [scores]
            return scores
        if np is None:
            scores = []
            for f in features:
                hidden = [sum(fi * wi for fi, wi in zip(f, col)) + b for col, b in zip(zip(*self.W1), self.b1)]
                hidden = self._relu(hidden)
                score = sum(h * w for h, w in zip(hidden, self.W2)) + self.b2
                scores.append(score)
            return scores
        xt = np.asarray(features, dtype=float)
        hidden = self._relu(xt @ self.W1 + self.b1)
        scores = hidden @ self.W2 + self.b2
        return scores.tolist()

    def train_batch(self, features: List[List[float]], targets: List[float]) -> Dict[str, float]:
        if not features:
            return {"loss": 0.0, "drift": 0.0}
        features = self._sanitize_features(features)
        targets = [t if math.isfinite(t) else 0.0 for t in targets]
        if self.use_torch:
            xt = torch.tensor(features, dtype=torch.float32)
            yt = torch.tensor(targets, dtype=torch.float32).unsqueeze(-1)
            preds = self.model(xt)
            loss = torch.mean((preds - yt) ** 2)
            self.optimizer.zero_grad()
            loss.backward()
            self.optimizer.step()
            drift = 0.0
            with torch.no_grad():
                drift = 0.0
                for p, last in zip(self.model.parameters(), self._last_params):
                    drift += torch.norm(p - last).item()
                self._last_params = [p.detach().clone() for p in self.model.parameters()]
            loss_val = loss.item()
            self.loss_ema = loss_val if self.loss_ema is None else 0.9 * self.loss_ema + 0.1 * loss_val
            return {"loss": loss_val, "drift": drift}
        if np is None:
            loss = 0.0
            for f, target in zip(features, targets):
                hidden = [sum(fi * wi for fi, wi in zip(f, col)) + b for col, b in zip(zip(*self.W1), self.b1)]
                hidden = self._relu(hidden)
                pred = sum(h * w for h, w in zip(hidden, self.W2)) + self.b2
                err = pred - target
                loss += err * err
                for i in range(len(self.W2)):
                    self.W2[i] -= self.lr * err * hidden[i]
                self.b2 -= self.lr * err
            loss /= max(1, len(features))
            self.loss_ema = loss if self.loss_ema is None else 0.9 * self.loss_ema + 0.1 * loss
            return {"loss": loss, "drift": 0.0}
        xt = np.asarray(features, dtype=float)
        yt = np.asarray(targets, dtype=float)
        hidden = self._relu(xt @ self.W1 + self.b1)
        preds = hidden @ self.W2 + self.b2
        errors = preds - yt
        loss = float(np.mean(errors ** 2))
        grad_W2 = hidden.T @ errors / len(features)
        grad_b2 = float(np.mean(errors))
        grad_hidden = np.outer(errors, self.W2)
        grad_hidden[hidden <= 0] = 0.0
        grad_W1 = xt.T @ grad_hidden / len(features)
        grad_b1 = np.mean(grad_hidden, axis=0)
        self.W2 -= self.lr * grad_W2
        self.b2 -= self.lr * grad_b2
        self.W1 -= self.lr * grad_W1
        self.b1 -= self.lr * grad_b1
        self.loss_ema = loss if self.loss_ema is None else 0.9 * self.loss_ema + 0.1 * loss
        return {"loss": loss, "drift": float(np.linalg.norm(grad_W2))}

class BottomUpSynthesizer:
    def __init__(
        self,
        max_depth=6,
        max_candidates=20000,
        bank_cap=1500,
        guided: bool = False,
        replay_capacity: int = 50000,
        meta_state: Optional[MetaState] = None,
        mutator: Optional[GrammarMutator] = None,
    ):
        self.max_depth = max_depth
        self.max_candidates = max_candidates
        self.bank_cap = bank_cap
        self.guided = guided
        self.interpreter = SafeInterpreter(limit=2000)
        self.navigator = NLMN() # Neural Logic Memory Network
        self.growth_analyzer = GrowthAnalyzer()  # Independent Evaluator (Strict Separation)
        self.feedback = FeedbackCollector()
        self.latent_priors_detected = False
        self.replay = ReplayBuffer(capacity=replay_capacity)
        self.training_every = 200
        self.training_batches = 3
        self.batch_size = 32
        self.alpha = 0.01
        self.beta = 0.005
        self.model: Optional[PolicyModel] = None
        self.step_count = 0
        self.last_improvement_step = 0
        self.reward_stats = {"min": 0.0, "max": 0.0, "mean": 0.0, "count": 0}

        # Meta-Hypothesis Components
        self.meta_state = meta_state
        self.mutator = mutator
        
        # [L6 Actuation] Structural Grammar Weights (Controlled by MetaBrain)
        # Default: Neutral weights
        self.grammar_weights = {
            'assign': 1.0,
            'loop': 1.0,
            'branch': 1.0
        }

    def _score_expr(self, expr: BSExpr, priors: Dict[str, float]) -> float:
        if not priors: return 1.0
        val = 1.0
        if isinstance(expr, BSBinOp):
            val *= priors.get(expr.op, 0.1)
            val *= self._score_expr(expr.left, priors)
            val *= self._score_expr(expr.right, priors)
        elif isinstance(expr, BSRecCall):
            val *= priors.get("Rec", 0.1)
            val *= self._score_expr(expr.arg, priors)
        elif isinstance(expr, BSVar):
            val *= priors.get("Arg", 0.5)
        elif isinstance(expr, BSVal):
            val *= priors.get("Const", 0.5)
        return val

    def _extract_atoms(self, expr: BSExpr) -> List[str]:
        atoms = []
        if isinstance(expr, BSBinOp):
            atoms.append(expr.op)
            atoms.extend(self._extract_atoms(expr.left))
            atoms.extend(self._extract_atoms(expr.right))
        elif isinstance(expr, BSRecCall):
            atoms.append("Rec")
            atoms.extend(self._extract_atoms(expr.arg))
        elif isinstance(expr, BSVar):
            atoms.append("Arg")
        elif isinstance(expr, BSVal):
            atoms.append("Const")
        return atoms

    def _ast_signature(self, expr: BSExpr) -> Tuple[int, int, Dict[str, int]]:
        counts = {"+": 0, "-": 0, "*": 0, "Rec": 0, "Arg": 0, "Const": 0}
        def walk(node: BSExpr, depth: int) -> Tuple[int, int]:
            if isinstance(node, BSBinOp):
                counts[node.op] += 1
                l_depth, l_nodes = walk(node.left, depth + 1)
                r_depth, r_nodes = walk(node.right, depth + 1)
                return max(depth, l_depth, r_depth), 1 + l_nodes + r_nodes
            if isinstance(node, BSRecCall):
                counts["Rec"] += 1
                d, n = walk(node.arg, depth + 1)
                return max(depth, d), 1 + n
            if isinstance(node, BSVar):
                counts["Arg"] += 1
                return depth, 1
            if isinstance(node, BSVal):
                counts["Const"] += 1
                return depth, 1
            return depth, 0
        max_depth, nodes = walk(expr, 1)
        return max_depth, nodes, counts

    # [AUDIT CLEANUP] _guided_templates removed.

    def _state_features(
        self,
        task_id: str,
        task_params: Dict[str, float],
        best_passes: int,
        error_mean: float,
        expr: BSExpr,
    ) -> List[float]:
        depth, nodes, counts = self._ast_signature(expr)
        features = [
            float(task_params.get("task_index", 0.0)),
            float(task_params.get("task_size", 0.0)),
            float(task_params.get("train_size", 0.0)),
            float(task_params.get("holdout_size", 0.0)),
            float(task_params.get("base_k", 0.0)),
            float(task_params.get("base_v", 0.0)),
            float(best_passes),
            float(error_mean),
            float(depth),
            float(nodes),
        ]
        features.extend([float(counts[k]) for k in ["+", "-", "*", "Rec", "Arg", "Const"]])
        return features

    def _action_features(self, expr: BSExpr) -> List[float]:
        _, nodes, counts = self._ast_signature(expr)
        features = [float(nodes)]
        features.extend([float(counts[k]) for k in ["+", "-", "*", "Rec", "Arg", "Const"]])
        return features

    def _score_expr(self, expr: BSExpr, priors: Dict[str, float]) -> float:
        """Score based on MAX prior - Penalty * Nodes"""
        max_prior = 0.1
        nodes = 0
        
        def visit(e):
            nonlocal max_prior, nodes
            nodes += 1
            p = 0.0
            if isinstance(e, BSBinOp): 
                p = priors.get(e.op, 0.0)
                visit(e.left); visit(e.right)
            elif isinstance(e, BSRecCall):
                p = priors.get('Rec', 0.0)
                visit(e.arg)
            elif isinstance(e, BSCustomOp):
                p = 0.5
                for a in e.args: visit(a)
            elif isinstance(e, BSVar):
                p = priors.get('Arg', 0.0)
            elif isinstance(e, BSVal):
                p = priors.get('Const', 0.0)
            
            if p > max_prior: max_prior = p
        
        visit(expr)
        # Cap the heuristic score so it doesn't overwhelm accuracy (0-100)
        final_score = max_prior - 0.2 * nodes
        return min(final_score, 10.0)

    # =========================================================================
    # EVOLUTIONARY SEARCH (Autonomous Discovery via Genetic Algorithm)
    # =========================================================================

    def _generate_random_expr(self, depth: int, priors: Dict[str, float], ops_list: List[Tuple[str, int]], atoms: List[BSExpr]) -> BSExpr:
        if depth <= 0 or random.random() < 0.1:
            return copy.deepcopy(random.choice(atoms))
        
        # [L6 Actuation] Apply structural grammar weights
        # Map operator names to structural types
        op_names = [op[0] for op in ops_list]
        weights = []
        for op in op_names:
            base_w = priors.get(op, 0.5)
            # Structural mapping
            struct_mult = 1.0
            if op == 'Rec': struct_mult = self.grammar_weights.get('loop', 1.0)
            elif op == 'if_gt': struct_mult = self.grammar_weights.get('branch', 1.0)
            
            # Apply multiplier
            weights.append(base_w * struct_mult)
            
        chosen_op_name = random.choices(op_names, weights=weights, k=1)[0]
        arity = next(fitness for name, fitness in ops_list if name == chosen_op_name)
        
        if chosen_op_name == 'Rec':
            arg = self._generate_random_expr(depth - 1, priors, ops_list, atoms)
            return BSRecCall(arg)
        elif arity == 2:
            left = self._generate_random_expr(depth - 1, priors, ops_list, atoms)
            right = self._generate_random_expr(depth - 1, priors, ops_list, atoms)
            return BSBinOp(chosen_op_name, left, right)
        else: 
            return copy.deepcopy(random.choice(atoms))

    def _mutate(self, expr: BSExpr, priors: Dict[str, float], ops_list: List[Tuple[str, int]], atoms: List[BSExpr], reservoir=None) -> Tuple[BSExpr, str]:
        """
        ReSTIR Mutation: Uses Reservoir to pick mutation type.
        Returns: (new_expr, mutation_type_str)
        """
        mutation_type = None
        
        # 1. RIS Sampling (50% chance to use history)
        if reservoir and random.random() < 0.5 and len(reservoir) > 0:
            mutation_type = random.choice(reservoir)
            
        # Decision Logic (Biased by mutation_type if set)
        
        # Case A: Subtree Replacement
        is_subtree = (mutation_type == 'subtree') if mutation_type else (random.random() < 0.1)
        if is_subtree: 
            return self._generate_random_expr(2, priors, ops_list, atoms), 'subtree'
            
        # Case B: Point / Recurse
        if isinstance(expr, BSBinOp):
            # Point Mutation
            is_point = (mutation_type == 'point') if mutation_type else (random.random() < 0.3)
            
            if is_point: 
                op_names = [op[0] for op in ops_list if op[1] == 2]
                weights = [priors.get(op, 0.5) for op in op_names]
                if op_names:
                    new_op = random.choices(op_names, weights=weights, k=1)[0]
                    return BSBinOp(new_op, expr.left, expr.right), 'point'
            else: 
                # Recurse (Preserve structure, dive deeper)
                # We don't record 'recurse' broadly, we trust the leaf mutation to report.
                # But for ReSTIR, we stick to top-level types 'subtree' vs 'point'. 
                # If we recurse, we bubble up the child's mutation type? 
                # For simplicity, we label recursion as 'recurse' for now.
                if random.random() < 0.5:
                    new_left, m_type = self._mutate(expr.left, priors, ops_list, atoms, reservoir)
                    return BSBinOp(expr.op, new_left, expr.right), m_type
                else:
                    new_right, m_type = self._mutate(expr.right, priors, ops_list, atoms, reservoir)
                    return BSBinOp(expr.op, expr.left, new_right), m_type
                    
        elif isinstance(expr, BSRecCall):
            new_arg, m_type = self._mutate(expr.arg, priors, ops_list, atoms, reservoir)
            return BSRecCall(new_arg), m_type
            
        elif isinstance(expr, (BSVar, BSVal)):
             # Leaf replacement
             # Treat as 'subtree' or 'point' depending on view. Let's call it 'leaf'.
             is_leaf = (mutation_type == 'leaf') if mutation_type else (random.random() < 0.5)
             if is_leaf:
                  return copy.deepcopy(random.choice(atoms)), 'leaf'
                  
        # No mutation happened
        return expr, 'none'

    def _crossover(self, expr1: BSExpr, expr2: BSExpr) -> BSExpr:
        # Swap subtrees (Simplified: Create new node with swapped child)
        try:
             child = expr1 # Immutable, no copy needed strictly but good practice
             if isinstance(child, BSBinOp):
                 replacement = expr2 # No deepcopy needed if immutable
                 if random.random() < 0.5:
                     return BSBinOp(child.op, replacement, child.right)
                 else:
                     return BSBinOp(child.op, child.left, replacement)
             elif isinstance(child, BSRecCall):
                 # Replace arg with entire expr2
                 return BSRecCall(expr2)
             else:
                 return expr2
        except:
             return expr1

    def _evaluate_fitness(self, expr, io_pairs, priors, base_k, base_v):
        """
        Ray Tracing Inspired Evaluation: BVH Fast Pass
        1. Fast Intersection: Check 1st ray (IO pair). If miss, reject immediately.
        2. Detailed Trace: Check remaining rays.
        """
        if not io_pairs: return 0.0
        
        hits = 0
        total = len(io_pairs)
        
        try:
            # [BVH] Fast Intersection Test (The Box Check)
            # Run only the FIRST case. If it fails, the object is likely 'junk'.
            # This saves running the interpreter 19 times for bad candidates.
            first_p = io_pairs[0]
            val_0 = self.interpreter.run_recursive(expr, first_p['input'], base_k, base_v)
            
            if val_0 != first_p['output']:
                # [BVH] Missed the Box. Early Rejection.
                # Return only the structural score (likely low/negative)
                # We do NOT run the rest of the loop.
                return self._score_expr(expr, priors)
            
            # [BVH] Hit the Box. Now trace the full geometry (Detailed Check).
            hits = 1
            for p in io_pairs[1:]:
                res = self.interpreter.run_recursive(expr, p['input'], base_k, base_v)
                if res == p['output']:
                    hits += 1
        except:
             # Runtime Error = Immediate Rejection
             return -10.0 
        
        accuracy = hits / total
        
        # Debug: If accuracy is 100% but expression is suspicious (no Rec?), print inputs
        if accuracy > 0.99 and 'Rec' not in str(expr) and total > 4:
             print(f"    [DEBUG] Suspicious High Fitness for {expr}")
             for p in io_pairs:
                 val = self.interpreter.run_recursive(expr, p['input'], base_k, base_v)
                 print(f"      In: {p['input']} Out: {val} Exp: {p['output']}")

        # 2. Heuristic Score (Complexity Penalty included)
        h_score = self._score_expr(expr, priors)
        
        # Combined Fitness: Accuracy * 100 + Score
        return accuracy * 100 + h_score

    def _adapt_priors(self, priors: Dict[str, float], population: List[BSExpr]) -> Dict[str, float]:
        """
        Dynamically adapts priors when search stagnates.
        Strategy: Invert the 'Dominant' operator priorities.
        If population is obsessed with '*' (Geometric), boost '+' (Additive).
        """
        new_priors = copy.deepcopy(priors)
        op_counts = collections.defaultdict(int)
        
        # Count operator usage in current population
        for expr in population:
            # Simple recursive counting
            to_visit = [expr]
            while to_visit:
                curr = to_visit.pop()
                if isinstance(curr, BSBinOp):
                    op_counts[curr.op] += 1
                    to_visit.append(curr.left)
                    to_visit.append(curr.right)
                elif isinstance(curr, BSRecCall):
                    op_counts['Rec'] += 1
                    to_visit.append(curr.arg)
                    
        # Identify Dominant vs Suppressed
        max_op = max(op_counts.items(), key=lambda x: x[1])[0] if op_counts else None
        
        print(f"      [DAP] Stagnation Detected! Dominant Op: {max_op}. Adapting Priors...")
        
        # Adaptation Logic: Bounded Shift
        # 1. Reset all to baseline 1.0
        for k in new_priors: new_priors[k] = 1.0
        
        # 2. Suppress Dominant
        if max_op:
             new_priors[max_op] = 0.05
             
        # 3. Boost Others
        curr_ops = ['+', '-', '*']
        for op in curr_ops:
            if op != max_op:
                new_priors[op] = 5.0
                
        # 4. Critical: Boost Rec specifically if we suspect recursive depth needed
        new_priors['Rec'] = 8.0 
        
        print(f"      [DAP] New Priors: {new_priors}")
        return new_priors

    def synthesize_evolutionary(self, io_pairs, generations=50, pop_size=500, deadline=None, task_id=""):
        if not io_pairs: return []
        sorted_io = sorted(io_pairs, key=lambda x: x['input'])
        base_k = sorted_io[0]['input']
        
        # Base Value Logic
        base_v = sorted_io[0]['output']

        # Priors
        priors = {}
        if self.growth_analyzer:
            priors = self.growth_analyzer.analyze_growth(io_pairs)
            if not priors: priors = {'Rec': 0.1, '*': 0.1, '+':0.1, '-':0.1}
            
        # [ARCHITECTURAL CHANGE: NO GOAL]
        # We do NOT query NLMN at start. The "Invention Module" sleeps.
        # It only wakes up if the Heuristic Evaluator (GrowthAnalyzer) fails (Stagnation).
        
        # Atoms & Ops
        
        # Atoms & Ops
        atoms = [BSVar('n'), BSVal(1), BSVal(0)]
        ops_list = [('+', 2), ('-', 2), ('*', 2), ('Rec', 1)]
        
        # Initialize Population
        population = []
        
        # [INTERNAL LOGIC ONLY]
        # Check if we found a Linear Recurrence using our internal Math Heuristic
        # This detection comes from GrowthAnalyzer._check_linear_recurrence (Brute Force Math)
        is_linear_recurrence = (priors.get('Rec', 0) >= 15.0 and priors.get('+', 0) >= 15.0)
        
        for _ in range(pop_size):
            depth = random.randint(1, 4)
            # Pure Random Generation (Guided by Priors only)
            expr = self._generate_random_expr(depth, priors, ops_list, atoms)
            population.append(expr)
            
        best_fitness_history = []
        stagnation_counter = 0
        last_best_fit = -1.0
        
        # Disable DAP if we are confident (Learned Knowledge should be trusted)
        enable_dap = not is_linear_recurrence
        
        # [ARCHITECTURAL CHANGE] ENERGY BUDGET
        # Tax attempts. Failure must be expensive to force structure.
        energy_budget = 100 
        
        for gen in range(generations):
            if deadline and time.time() > deadline: break
            
            # Tax Energy
            energy_budget -= 1
            if energy_budget <= 0:
                print("    [System] Energy Depleted. Stopping search.")
                break
            
            # Evaluate
            scored_pop = []
            for expr in population:
                fit = self._evaluate_fitness(expr, io_pairs, priors, base_k, base_v)
                scored_pop.append((fit, expr))
                
                if fit >= 100: # 100% accuracy found
                    # [Meta-Meta Learning] Feedback success to Neural Brain
                    if hasattr(self, 'navigator') and self.navigator:
                        try:
                            self.navigator.learn(io_pairs, str(expr))
                        except: pass
                    return [(str(expr), fit)]
            
            scored_pop.sort(key=lambda x: x[0], reverse=True)
            current_best_fit = scored_pop[0][0]
            
            if gen % 10 == 0:
                 print(f"[Evo Gen {gen} | Energy {energy_budget}] Best: {current_best_fit:.2f}")

            # Stagnation Check
            if current_best_fit > last_best_fit + 0.01:
                stagnation_counter = 0
                last_best_fit = current_best_fit
                # Reward: Refill energy slightly on progress
                energy_budget = min(energy_budget + 10, 100)
            else:
                stagnation_counter += 1
            
            # [ARCHITECTURAL CHANGE] WAKEUP CALL (Invention Module)
            # Only wake up Neural Logic (NLMN) if stagnating
            if stagnation_counter > 8:
                 if hasattr(self, 'navigator') and self.navigator:
                     # Query Intuition
                     try:
                         neural_priors = self.navigator.get_priors(io_pairs)
                         if neural_priors:
                             print(f"      [System] Stagnation! Waking up NLMN... Intuition: {neural_priors}")
                             # Strong Injection
                             for k, v in neural_priors.items():
                                 priors[k] = max(priors.get(k, 0.1), v * 2.0)
                             stagnation_counter = 0 # Reset to give intuition time
                     except Exception as e:
                         pass
            
            # DAP (Self-Correction - Heuristic Fallback)
            if enable_dap and stagnation_counter > 10:
                priors = self._adapt_priors(priors, population)
                stagnation_counter = 0 # Reset
                new_blood_count = int(pop_size * 0.3)
                fresh_blood = [self._generate_random_expr(random.randint(1,4), priors, ops_list, atoms) for _ in range(new_blood_count)]
                scored_pop = scored_pop[:-new_blood_count] + [(0, expr) for expr in fresh_blood]
            
            # Elitism: Keep top 10%
            next_pop = [copy.deepcopy(x[1]) for x in scored_pop[:int(pop_size*0.1)]] 
            
            # Reproduction
            pool = scored_pop[:int(pop_size*0.5)]
            if not pool: pool = scored_pop
            
            # ReSTIR Reservoir
            mutation_reservoir = collections.deque(maxlen=20)

            while len(next_pop) < pop_size:
                # Tournament Selection
                # p1, p2 are (fitness, expr) tuples from scored_pop
                parent1_tuple = max(random.sample(pool, min(3, len(pool))), key=lambda x:x[0])
                parent2_tuple = max(random.sample(pool, min(3, len(pool))), key=lambda x:x[0])
                
                p1, p1_fit = parent1_tuple[1], parent1_tuple[0]
                p2 = parent2_tuple[1]
                
                if random.random() < 0.7:
                     child = self._crossover(p1, p2)
                else:
                     child = copy.deepcopy(p1)
                
                m_type = 'none'
                if random.random() < 0.5:
                     child, m_type = self._mutate(child, priors, ops_list, atoms, reservoir=mutation_reservoir)

                # [ReSTIR] Immediate Evaluation for Reservoir Update
                # Only if mutation happened
                if m_type != 'none':
                    # Fast Eval (BVH makes this cheap)
                    child_fit = self._evaluate_fitness(child, io_pairs, priors, base_k, base_v)
                    
                    # If Improved, Store Strategy
                    if child_fit > p1_fit:
                        mutation_reservoir.append(m_type)
                        # Optional: Print occasionally?
                
                next_pop.append(child)
            
            population = next_pop
            
        return []

    def _ensure_model(self, input_dim: int) -> None:
        if self.model is None:
            self.model = PolicyModel(input_dim=input_dim, hidden_dim=64, lr=0.01)
        
    def synthesize(
        self,
        io_pairs: List[Dict[str, Any]],
        deadline: Optional[float] = None,
        task_id: str = "task",
        task_params: Optional[Dict[str, float]] = None,
    ) -> List[str]:
        # Form: def f(n): if n <= BASE_K: return BASE_V else: return {EXPR}
        if deadline and time.time() > deadline:
            raise TimeoutError("Synthesis timeout")

        if task_params is None:
            task_params = {}
        
        base_k = 1
        base_v = 1
        sorted_io = sorted(io_pairs, key=lambda x: x['input'])
        
        if sorted_io and sorted_io[0]['input'] <= 1:
            base_k = sorted_io[0]['input']
            base_v = sorted_io[0]['output']
            
            # Check for Identity Base Case (y = x)
            # This is critical for Fibonacci (0->0, 1->1) where "return n" is needed
            # If 0->0 and 1->1, we extend base_k to 1 and set base_v to SENTINEL -9999
            if len(sorted_io) > 1 and sorted_io[1]['input'] == base_k + 1:
                # Check for Identity: y=x behavior in base region
                if base_v == base_k and sorted_io[1]['output'] == sorted_io[1]['input']:
                    base_k = sorted_io[1]['input']
                    base_v = -9999 # Identity Sentinel
                # Check for Constant: y=c behavior (existing logic)
                elif sorted_io[1]['output'] == base_v:
                     base_k = sorted_io[1]['input']

        active_io = [p for p in io_pairs if p['input'] > base_k]
        if not active_io: return []

        # [AUDIT CLEANUP] Removed hardcoded _guided_templates.
        # The system must discover recursion patterns via Stitch, not templates.

        # === Phase 6: GrowthAnalyzer - Heuristic (No Code Injection!) ===
        # Adjust operator priors based on growth patterns. No direct code injection.
        growth_priors = {}
        if self.growth_analyzer:
            growth_priors = self.growth_analyzer.analyze_growth(io_pairs)
        
        # Latent Space Guidance + Organic Learned Priors
        priors = self.navigator.get_priors(active_io) if self.navigator else {}
        learned_priors = self.feedback.get_learned_priors()
        
        # Priority: GrowthAnalyzer > Navigator > Learned
        if growth_priors:
            print(f"    [GrowthAnalyzer] Growth-based priors: {growth_priors}")
            for op, val in growth_priors.items():
                if op in priors:
                    # Heuristic overrides existing priors strongly (0.9 vs 0.1)
                    priors[op] = 0.9 * val + 0.1 * priors.get(op, 0.1)
                else:
                    priors[op] = val
        
        # ORGANIC: Combine Navigator priors with learned experience priors
        # Only blend if heuristic did NOT provide strong signals
        if not growth_priors and learned_priors and sum(self.feedback.op_total_counts.values()) > 100:
            # Blend: 70% Navigator + 30% Learned (after sufficient experience)
            for k in priors:
                if k in learned_priors:
                    priors[k] = 0.7 * priors[k] + 0.3 * learned_priors[k]
            print(f"    [Organic] Blending learned priors: { {k: round(v,3) for k,v in learned_priors.items()} }")
        
        if priors:
            self.latent_priors_detected = True
            print(f"    [Latent] Combined Priors: { {k: round(v,3) for k,v in priors.items()} }")

        print(f"    [Synthesizer] Growing atoms for {len(active_io)} inputs (Base: n<={base_k}->{base_v})...")

        # Bank 0: atoms
        bank = [BSVal(0), BSVal(1), BSVar('n')]
        
        # === NO CHEATING: Code Injection Removed ===
        # GrowthAnalyzer gives priors only. The synthesizer must find the structure itself.
        
        
        bank_behaviors = {} 
        
        # Pre-calc target signature for solution matching
        target_sig = tuple(p['output'] for p in active_io)
        
        # Pre-calc behaviors (using SAFE RUNNER)
        # Check if initial atoms are solutions immediately!
        for expr in bank:
            sig = []
            valid = True
            for pair in active_io:
                 try: 
                     # For atoms, recursion is irrelevant, but we use the general runner for consistency
                     res = self.interpreter.run_recursive(expr, pair['input'], base_k, base_v)
                     sig.append(res)
                 except: valid = False; break
            
            if valid:
                sig_tuple = tuple(sig)
                bank_behaviors[sig_tuple] = expr
                
                # === Emergent Approach: Check if injected template is immediate solution ===
                if sig_tuple == target_sig:
                    print(f"      [Immediate Solution!] RelationAnalyzer template solves: {expr}")
                    
                    if self.navigator:
                        self.navigator.learn(active_io, self._extract_atoms(expr), success=True)
                    
                    code = self._to_python(expr, base_k, base_v)
                    return [(code, expr, base_k, base_v)]
        
        best_passes = 0
        best_error_mean = float("inf")
        reward_running = 0.0
        reward_count = 0
        reward_min = 0.0
        reward_max = 0.0
        def clamp_reward(val: float) -> float:
            return max(-5.0, min(5.0, val))

        for depth in range(self.max_depth):
            if deadline and time.time() > deadline:
                raise TimeoutError("Synthesis timeout")
            if not bank: break
            
            # Meta-Hypothesis: Check for new abstractions
            if self.mutator and depth % 2 == 0:
                proposal = self.mutator.propose_mutation()
                if proposal:
                     name, expr = proposal
                     print(f"    [Meta-Hypothesis] Proposed Abstraction: {name} = {expr}")
                     # Irreversible Commitment
                     self.meta_state.add_abstraction(name, expr)

            next_bank = []
            
            # Dynamic Ops Generation
            ops_list = [('+', 2), ('-', 2), ('*', 2), ('Rec', 1)]
            if self.meta_state:
                ops_list.extend([(name, self.meta_state.get_arity(name)) for name in self.meta_state.abstractions])
            
            for op, arity in ops_list:
                if arity == 0:
                    # Constant-like macro
                    if op in self.meta_state.abstractions:
                        next_bank.append(BSCustomOp(op, self.meta_state.abstractions[op], []))
                elif arity == 1:
                    for e in bank:
                        if op == 'Rec': next_bank.append(BSRecCall(e))
                        elif op in self.meta_state.abstractions:
                            next_bank.append(BSCustomOp(op, self.meta_state.abstractions[op], [e]))
                elif arity == 2:
                    for e1 in bank:
                        for e2 in bank:
                            if op in ['+', '-', '*']: next_bank.append(BSBinOp(op, e1, e2))
                            elif op in self.meta_state.abstractions:
                                next_bank.append(BSCustomOp(op, self.meta_state.abstractions[op], [e1, e2]))

            # Neural Sort (Implicit Search)
            if priors:
                next_bank.sort(key=lambda e: self._score_expr(e, priors), reverse=True)
                if depth >= 1:
                    print(f"      [Debug] Depth {depth} Top 5: {next_bank[:5]}")

            # Beam Width Limit
            if len(next_bank) > self.max_candidates:
                next_bank = next_bank[:self.max_candidates]

            # Guided selection using policy model
            if self.guided:
                example_expr = next_bank[0]
                state_features = self._state_features(task_id, task_params, best_passes, best_error_mean, example_expr)
                action_features = self._action_features(example_expr)
                self._ensure_model(len(state_features) + len(action_features))
                features = []
                for expr in next_bank:
                    state = self._state_features(task_id, task_params, best_passes, best_error_mean, expr)
                    action = self._action_features(expr)
                    features.append(state + action)
                scores = self.model.score(features)
                ranked = []
                for score, expr in zip(scores, next_bank):
                    _, nodes, _ = self._ast_signature(expr)
                    heuristic = -0.05 * nodes
                    ranked.append((score + heuristic, expr))
                ranked.sort(key=lambda x: x[0], reverse=True)
                beam_width = min(max(2000, len(next_bank) // 10), len(next_bank))
                next_bank = [expr for _, expr in ranked[:beam_width]]
                
            # Update bank
            new_additions = 0
            pruned_count = 0
            candidate_count = len(next_bank)
            unique_behaviors = {}
            
            for idx, expr in enumerate(next_bank):
                if deadline and idx % 1000 == 0 and time.time() > deadline:
                    raise TimeoutError("Synthesis timeout")
                sig = []
                valid = True
                passes = 0
                error_sum = 0.0
                
                # Check all inputs using TRUE EXECUTION
                for pair in active_io:
                    n_val = pair['input']
                    try:
                        # CRITICAL: This runs the actual AST recursively. No Oracle.
                        res = self.interpreter.run_recursive(expr, n_val, base_k, base_v)
                        sig.append(res)
                        expected = pair['output']
                        if res == expected:
                            passes += 1
                        else:
                            error_sum += abs(res - expected)
                    except Exception:
                        valid = False # Gas limit, infinite loop, etc
                        break
                
                if valid:
                    error_mean = error_sum / max(1, len(active_io) - passes)
                    sig_tuple = tuple(sig)
                    
                    # ORGANIC FEEDBACK: Record this attempt for learning
                    self.feedback.record_attempt(expr, passes, len(active_io), depth)
                    
                    # PHASE 3: Learn from partial matches (near-misses)
                    if passes > 0 and passes < len(active_io) and self.navigator:
                        self.navigator.learn_from_partial(active_io, expr, passes, len(active_io))
                    
                    # Unique check
                    # FIX: Do not prune BSRecCall against non-recursive items. 
                    # They are structurally distinct and crucial for future compositions.
                    is_new = True
                    if sig_tuple in unique_behaviors:
                         is_new = False
                    elif sig_tuple in bank_behaviors:
                         existing = bank_behaviors[sig_tuple]
                         # Allow if new is RecCall and existing is NOT RecCall
                         if isinstance(expr, BSRecCall) and not isinstance(existing, BSRecCall):
                             is_new = True
                         else:
                             is_new = False
                    
                    if is_new:
                        # Add to local unique
                        unique_behaviors[sig_tuple] = expr
                        
                        # Add to global bank immediately? Or batch?
                        # Batching prevents using new items in current depth (which is BFS standard)
                        # But we need global check.
                        
                        # Optimization: Check if solved
                        target_sig = tuple(p['output'] for p in active_io)
                        if sig_tuple == target_sig:
                            print(f"      [Success] Found solution at Depth {depth}: {expr}")
                            
                            # Self-Correction (Reinforcement)
                            if self.navigator:
                                print("      [Latent] Learning success pattern...")
                                self.navigator.learn(active_io, self._extract_atoms(expr))

                            if self.mutator:
                                self.mutator.add_solution(expr)

                            code = self._to_python(expr, base_k, base_v)
                            # Return full info for safe verification
                            # MDL Implementation
                            # L(H): Length of Hypothesis (AST size in bits equivalent, rough approx)
                            len_h = len(str(expr)) 
                            # L(D|H): Length of Data given Hypothesis (Residuals)
                            # Only count errors on valid outputs. Exact match = 0 bits.
                            # Error e: log2(1 + |e|) bits approx
                            len_d_given_h = 0.0
                            for res, pair in zip(sig, active_io):
                                err = abs(res - pair['output'])
                                if err > 0:
                                    len_d_given_h += math.log2(1 + err)
                            
                            mdl_score = len_h + len_d_given_h
                            
                            # Reward is negative MDL (Minimize Description Length)
                            # Normalized for RL stability: start with a baseline
                            reward = -0.1 * mdl_score 
                            reward = clamp_reward(reward)

                            # Calculate features for replay (needed if guided=False or skipped)
                            state_features = self._state_features(task_id, task_params, best_passes, 0.0, expr)
                            action_features = self._action_features(expr)

                            self.replay.add(
                                ReplaySample(
                                    task_id=task_id,
                                    state_features=state_features,
                                    action=action_features,
                                    reward=reward,
                                    done=True,
                                    timestamp=time.time(),
                                )
                            )
                            return [(code, expr, base_k, base_v)]
                    else:
                        pruned_count += 1
                else:
                    pruned_count += 1

                if valid:
                    # MDL Calculation
                    len_h = len(str(expr))
                    len_d_given_h = 0.0
                    for res, pair in zip(sig, active_io):
                         err = abs(res - pair['output'])
                         if err > 0:
                             len_d_given_h += math.log2(1 + err)
                    
                    mdl_score = len_h + len_d_given_h
                    
                    # Negative MDL reward
                    reward = -0.1 * mdl_score
                    reward = clamp_reward(reward)
                    if passes > best_passes:
                        best_passes = passes
                        best_error_mean = min(best_error_mean, error_mean)
                        self.last_improvement_step = self.step_count
                    state_features = self._state_features(task_id, task_params, best_passes, best_error_mean, expr)
                    action_features = self._action_features(expr)
                    self.replay.add(
                        ReplaySample(
                            task_id=task_id,
                            state_features=state_features,
                            action=action_features,
                            reward=reward,
                            done=False,
                            timestamp=time.time(),
                        )
                    )
                    reward_running += reward
                    reward_count += 1
                    reward_min = min(reward_min, reward)
                    reward_max = max(reward_max, reward)

                    if self.guided and self.step_count % self.training_every == 0 and len(self.replay) >= self.batch_size:
                        batch = self.replay.sample(self.batch_size)
                        feats = [s.state_features + s.action for s in batch]
                        targets = [s.reward for s in batch]
                        stats = self.model.train_batch(feats, targets) if self.model else {"loss": 0.0, "drift": 0.0}
                        print(
                            f"      [Train] loss={stats['loss']:.4f} ema={self.model.loss_ema:.4f} drift={stats['drift']:.4f}"
                        )
                    self.step_count += 1
            
            # Batch update bank
            for sig, expr in unique_behaviors.items():
                # Note: We might overwrite non-rec with rec in bank_behaviors map, which is fine
                bank_behaviors[sig] = expr
                bank.append(expr)
                new_additions += 1
            
            print(f"      [Depth {depth}] Candidates: {candidate_count} | Pruned: {pruned_count} | New Behaviors: {new_additions} | Total Bank: {len(bank)}")
            if new_additions == 0: break
            
            if len(bank) > self.bank_cap:
                 bank.sort(key=lambda x: len(str(x)))
                 bank = bank[:self.bank_cap]
                 
        if reward_count:
            self.reward_stats = {
                "min": reward_min,
                "max": reward_max,
                "mean": reward_running / reward_count,
                "count": reward_count,
            }
            print(
                f"      [Reward] mean={self.reward_stats['mean']:.3f} min={self.reward_stats['min']:.3f} max={self.reward_stats['max']:.3f}"
            )

        # PHASE 3: Learn from failure - extract patterns from promising near-misses
        if self.feedback.promising_patterns and self.navigator:
            best_pattern = max(self.feedback.promising_patterns, key=lambda x: x[1])
            print(f"      [Learning] Best partial match: {best_pattern[0][:50]}... ({best_pattern[1]*100:.1f}%)")
            # Learn to AVOID patterns that didn't work completely
            # This is implicit through learn_from_partial already, but we can log it
            
        return []


    def _to_python(self, expr: BSExpr, k: int, v: int) -> str:
        base_stmt = f"return {v}"
        return f"def f(n):\n    if n <= {k}: {base_stmt}\n    return {expr}"


class HRMSidecar:
    def __init__(self, tools_registry: ToolRegistry, quick: bool = False, guided: bool = False):
        self.tools = tools_registry
        self.stitch = StitchLite()
        self.py2lam = PyToLambda()
        self.lam2py = LambdaToPy()
        
        
        # Meta-Hypothesis Components
        self.meta_state = MetaState()
        self.mutator = GrammarMutator(self.meta_state)
        self.critic = SelfCritic(self.meta_state, SafeInterpreter(limit=5000))
        
        # Bezalel Engine Integration (Universal Resonance)
        self.bezalel = BezalelSynthesizer()

        # [NEW] Neuro-Genetic Synthesis Engine
        # Replaces old BottomUpSynthesizer with Intelligent Evolution
        if guided and HAS_TORCH:
            print("[HRM] Initializing Neural Guide (NLMN)...")
            self.guide = NLMN(embedding_dim=64)
            self.synthesizer = NeuroGeneticSynthesizer(
                neural_guide=self.guide,
                pop_size=200,
                generations=20
            )
        else:
            # Fallback to unguided genetic synthesis if no torch
            self.synthesizer = NeuroGeneticSynthesizer(
                neural_guide=None, 
                pop_size=200,
                generations=20
            )
        self.concept_count = 0
        
        # [NEW] Human-Level Concept Transfer Engine (No Transformers)
        self.transfer_engine = None
        if HAS_CONCEPT_TRANSFER:
            self.transfer_engine = ConceptTransferEngine(interpreter=self.synthesizer.interp)
            print("[HRM] ConceptTransferEngine initialized for human-level generalization.")

    def dream(
        self,
        experiences_as_code: List[str],
        io_examples: List[Dict[str, Any]] = None,
        deadline: Optional[float] = None,
        task_id: str = "task",
        task_params: Optional[Dict[str, float]] = None,
    ) -> List[Tuple[str, Any]]:
        print(f"[HRM-Sidecar] Dreaming on {len(experiences_as_code)} experiences...")
        
        # [NEW] Attempt concept transfer first (Human-Level Generalization)
        if io_examples and self.transfer_engine:
            print(f"  > [ConceptTransfer] Attempting transfer from library ({self.transfer_engine.get_stats()['total_concepts']} concepts)...")
            candidates = self.transfer_engine.transfer(io_examples)
            if candidates:
                top_name, top_expr, score, method = candidates[0]
                if score >= 0.9:  # High confidence transfer
                    print(f"  > [ConceptTransfer] SUCCESS! Transferred '{top_name}' (score={score:.2f}, method={method})")
                    return [(str(top_expr), (top_expr, 0, 0))]
                elif score >= 0.7:
                    print(f"  > [ConceptTransfer] Partial match '{top_name}' (score={score:.2f}). Continuing synthesis...")
        
        # 0. Bezalel Engine (Universal Resonance) - Honest & Fast
        # Only for I/O tasks.
        if io_examples:
            print(f"  > [Bezalel] Checking Universal Resonance (Tzimtzum)...")
            bezalel_res = self.bezalel.synthesize(io_examples, timeout=5) # Fast check
            if bezalel_res:
                print(f"  > [Bezalel] Instant Resonance Found!")
                code_str, ast_obj, k, v = bezalel_res[0]
                
                self.concept_count += 1
                name = f"concept_rez_{self.concept_count}"
                # Rename function to unique concept name
                final_code = code_str.replace("def f(n):", f"def {name}(n):")
                final_code = final_code.replace("f(", f"{name}(")
                
                print(f"  [INVENTION] {name}: {final_code.splitlines()[2]} (Tzimtzum Verified)")
                
                # PERSISTENCE (RSI PROOF): Save checkpoint
                try:
                    ckpt_dir = "checkpoints"
                    if not os.path.exists(ckpt_dir): os.makedirs(ckpt_dir)
                    timestamp = int(time.time() * 1000)
                    # FIX: Filename must match rsi_evolution_driver regex r"brain_gen_(\d+)\.pkl"
                    ckpt_path = os.path.join(ckpt_dir, f"brain_gen_{timestamp}.pkl")
                    with open(ckpt_path, "wb") as f:
                        pickle.dump({
                            "name": name,
                            "code": final_code, 
                            "ast": ast_obj,
                            "meta": {}, # Bezalel doesn't update meta yet
                            "source": "bezalel"
                        }, f)
                    print(f"  [Persistence] Saved RSI Checkpoint (Bezalel): {ckpt_path}")
                except Exception as e:
                    print(f"  [Persistence] Failed to save checkpoint: {e}")

                return [(final_code, (ast_obj, k, v))]
    def inject(self, concepts):
        """Inject discovered concepts into the system's grammar."""
        for item in concepts:
            # Handle different result formats safely
            if len(item) == 4:
                code, ast_obj, k, v = item
            elif len(item) == 2:
                code, meta = item
                ast_obj = meta[0] if isinstance(meta, tuple) else meta
            else:
                continue

            if hasattr(self, 'meta_state') and hasattr(ast_obj, '__repr__'):
                name = f"Op{len(self.meta_state.abstractions)}"
                self.meta_state.add_abstraction(name, ast_obj)
                # [RSI] Register with Neuro-Genetic Synthesizer (Library Learning)
                if hasattr(self, 'synthesizer'):
                    # Create a callable wrapper for the AST
                    # The interpreter needs a python function.
                    # We can use the synthesizer's interpreter to run this AST.
                    def make_primitive(expr_ast, interp):
                        return lambda *args: interp.run(expr_ast, {'n': args[0] if args else 0})

                    # Register as a new primitive (e.g., 'Op5')
                    # We need to bind the current AST to the lambda
                    # Note: We assume unary for now or needs deeper signature analysis
                    # For safety, we skip complex signature inference and assume unary 'n' based.
                    wrapper = make_primitive(ast_obj, self.synthesizer.interp)
                    self.synthesizer.register_primitive(name, wrapper)
                    print(f"  [RSI-Library] Learned new primitive '{name}' (DreamCoder-style reuse enabled)")
            
            # [Bezalel] Feedback loop
            if hasattr(self, 'bezalel'):
                self.bezalel.feedback(code, 1.0)
            if hasattr(self.synthesizer, 'register_primitive'):
                try:
                    # Construct valid context with base primitives
                    context = {}
                    context.update(NeuroInterpreter.PRIMS)
                    
                    # Create the function
                    # code is like "mul(n, n)"
                    # We want "lambda n: mul(n, n)"
                    lambda_src = f"lambda n: {code}"
                    
                    # Compile
                    func = eval(lambda_src, context)
                    
                    # Name it
                    concept_name = f"concept_{self.concept_count}"
                    self.synthesizer.register_primitive(concept_name, func)
                    print(f"  [RSI] Registered executable primitive: {concept_name} -> {code}")
                    
                except Exception as e:
                    print(f"  [RSI] Failed to register primitive: {e}")
            
            # [NEW] Register with ConceptTransferEngine for generalization
            if self.transfer_engine and ast_obj:
                try:
                    concept_name = f"concept_{self.concept_count}"
                    self.transfer_engine.register_concept(concept_name, ast_obj)
                    self.concept_count += 1
                except Exception as e:
                    print(f"  [ConceptTransfer] Failed to register: {e}")


