class CausalReasoner:
    """Causal Reasoning - Identifies cause-effect relationships."""
    def __init__(self):
        self.causal_graph = {}
    
    def infer_causality(self, io_pairs):
        if len(io_pairs) < 3: return {"causal_type": "unknown", "confidence": 0.0}
        inputs = [p['input'] for p in io_pairs]
        outputs = [p['output'] for p in io_pairs]
        diffs_in = [inputs[i+1] - inputs[i] for i in range(len(inputs)-1)]
        diffs_out = [outputs[i+1] - outputs[i] for i in range(len(outputs)-1)]
        causal_type, confidence = "unknown", 0.0
        if all(d >= 0 for d in diffs_in) and all(d >= 0 for d in diffs_out):
            causal_type, confidence = "monotonic_positive", 0.9
        elif all(d >= 0 for d in diffs_in) and all(d <= 0 for d in diffs_out):
            causal_type, confidence = "monotonic_negative", 0.9
        return {"causal_type": causal_type, "confidence": confidence}


class PhysicsIntuition:
    """Physical Intuition - Embeds basic physics knowledge."""
    def analyze_sequence(self, values):
        if len(values) < 2: return {"pattern": "insufficient_data"}
        d1 = [values[i+1] - values[i] for i in range(len(values)-1)]
        d2 = [d1[i+1] - d1[i] for i in range(len(d1)-1)] if len(d1) > 1 else []
        pattern = "unknown"
        if all(abs(d) < 0.01 for d in d1): pattern = "equilibrium"
        elif len(d2) > 0 and all(abs(d) < 0.01 for d in d2): pattern = "linear_motion"
        elif len(d2) > 0 and len(set(round(d, 1) for d in d2)) == 1: pattern = "quadratic"
        return {"pattern": pattern, "d1": d1, "d2": d2}


class SelfStateModel:
    """Self-State Modeling - Internal state representation."""
    def __init__(self):
        self.state = {"concepts": 0, "tasks": 0, "capability": 1.0, "confidence": 0.5}
        self.history = []
    
    def update(self, key, value):
        old = self.state.get(key)
        self.state[key] = value
        self.history.append({"time": time.time(), "key": key, "old": old, "new": value})
    
    def introspect(self):
        return {"state": dict(self.state), "changes": len(self.history)}
    
    def assess(self):
        cap = self.state.get("capability", 1.0)
        if cap > 5: return "highly_capable"
        elif cap > 2: return "competent"
        return "learning"


class MetaCognition:
    """Meta-Cognition - Thinks about thinking."""
    def __init__(self):
        self.thinking_log = []
        self.strategy_scores = {}
        self.meta_level = 1
        self.associations = {}
        self.transfers = []
    
    def log_thought(self, thought_type, content, success=None):
        self.thinking_log.append({"time": time.time(), "type": thought_type, "success": success, "level": self.meta_level})
        if success is not None:
            old = self.strategy_scores.get(thought_type, 0.5)
            self.strategy_scores[thought_type] = 0.9 * old + 0.1 * (1.0 if success else 0.0)
    
    def reflect(self):
        self.meta_level = 2
        recent = self.thinking_log[-20:] if len(self.thinking_log) > 20 else self.thinking_log
        successes = sum(1 for t in recent if t.get("success") is True)
        failures = sum(1 for t in recent if t.get("success") is False)
        rate = successes / max(1, successes + failures)
        rec = "change_strategy" if failures > successes * 2 else "continue"
        self.meta_level = 1
        return {"recent_success_rate": rate, "recommendation": rec}
    
    def meta_transfer(self, source, target, knowledge):
        self.transfers.append({"source": source, "target": target, "time": time.time()})
        if source not in self.associations: self.associations[source] = []
        if target not in self.associations[source]: self.associations[source].append(target)
    
    def continuous_associate(self, concept):
        result, queue, depth = set(), [concept], 0
        while queue and depth < 3:
            next_q = []
            for c in queue:
                for n in self.associations.get(c, []):
                    if n not in result: result.add(n); next_q.append(n)
            queue, depth = next_q, depth + 1
        return list(result)
    
    def elevate_meta_level(self):
        self.meta_level = min(self.meta_level + 1, 5)
    
    def get_cognitive_state(self):
        return {"meta_level": self.meta_level, "thoughts": len(self.thinking_log), "transfers": len(self.transfers)}


class CognitiveCore:
    """Unified Cognitive Core integrating all 4 capabilities."""
    def __init__(self):
        self.causal = CausalReasoner()
        self.physics = PhysicsIntuition()
        self.self_model = SelfStateModel()
        self.meta = MetaCognition()
    
    def analyze_task(self, io_pairs):
        causal_info = self.causal.infer_causality(io_pairs)
        outputs = [p['output'] for p in io_pairs]
        physics_info = self.physics.analyze_sequence(outputs)
        self.meta.log_thought("analysis", f"{len(io_pairs)} pairs")
        return {"causal": causal_info, "physics": physics_info}
    
    def learn_result(self, task, success):
        self.meta.log_thought("result", task, success)
        delta = 0.05 if success else -0.02
        self.self_model.update("confidence", max(0.1, min(1.0, self.self_model.state["confidence"] + delta)))
        if success: self.self_model.update("tasks", self.self_model.state["tasks"] + 1)


class AutonomousTaskGenerator:
    """Generates increasingly complex tasks based on strict curriculum."""
    LEVELS = {
        1: [("identity", lambda n: n), ("increment", lambda n: n+1), ("decrement", lambda n: n-1 if n>0 else 0)],
        2: [("add_k", lambda n: n+2), ("sub_k", lambda n: n-2 if n>1 else 0), ("double", lambda n: n * 2)],
        3: [("mul_k", lambda n: n*3), ("square", lambda n: n * n), ("modulo_k", lambda n: n % 3)],
        4: [("triangular", lambda n: n * (n + 1) // 2), ("cube", lambda n: n*n*n)],
    }
    
    def __init__(self, seed=42):
        self.rng = random.Random(seed)
        self.solved_counts = {1:0, 2:0, 3:0, 4:0}
        self.current_level = 1
        self.gen = 0
    
    def generate(self):
        self.gen += 1
        # Gating logic
        if self.current_level == 1 and self.solved_counts[1] >= 5: self.current_level = 2
        elif self.current_level == 2 and self.solved_counts[2] >= 5: self.current_level = 3
        elif self.current_level == 3 and self.solved_counts[3] >= 5: self.current_level = 4
        
        # Fallback if level undefined
        pool = self.LEVELS.get(self.current_level, self.LEVELS[1])
        name, fn = self.rng.choice(pool)
        
        ios = [{"input": n, "output": fn(n)} for n in range(7)]
        return f"{name}_L{self.current_level}_g{self.gen}", ios
    
    def report_solved(self, name):
        # Extract level from name format "name_LX_gY"
        try:
            parts = name.split('_')
            for p in parts:
                if p.startswith('L') and p[1:].isdigit():
                    lvl = int(p[1:])
                    self.solved_counts[lvl] = self.solved_counts.get(lvl, 0) + 1
                    print(f"[Curriculum] Level {lvl} progress: {self.solved_counts[lvl]}/5")
                    break
        except: pass


class SingularityMonitor:
    """Monitors progress toward singularity."""
    def __init__(self):
        self.start = time.time()
        self.concepts = 0
        self.tasks = 0
        self.depth = 0
        self.caps = []
    
    def record_concept(self, complexity=1): self.concepts += 1; self.depth = max(self.depth, complexity)
    def record_task(self): self.tasks += 1
    
    def capability(self):
        s = self.concepts * math.log(1 + self.tasks) * (1 + self.depth)
        self.caps.append(s); return s
    
    def accelerating(self):
        if len(self.caps) < 5: return False
        diffs = [self.caps[i+1] - self.caps[i] for i in range(-5, -1)]
        return all(diffs[i+1] > diffs[i] for i in range(len(diffs)-1))
    
    def status(self):
        s = self.capability()
        acc = "🚀 ACCELERATING!" if self.accelerating() else ""
        print(f"\n[SINGULARITY] C:{self.concepts} T:{self.tasks} D:{self.depth} S:{s:.2f} {acc}")


def run_hrm_life():
    """INFINITE HRM LIFE LOOP - 4 Cognitive Capabilities + RSI"""
    print("\n" + "=" * 70)
    print("  SINGULARITY LOOP - causal reasoning | physical intuition | self-state | metacognition")
    print("  Ctrl+C to stop.")
    print("=" * 70)
    
    seed = int(time.time()) % 10000
    random.seed(seed)
    if np: np.random.seed(seed)
    
    tools = ToolRegistry()
    hrm = HRMSidecar(tools, quick=False, guided=True)
    gen = AutonomousTaskGenerator(seed)
    mon = SingularityMonitor()
    cog = CognitiveCore()
    
    state_path = "rsi_state.pkl"
    if os.path.exists(state_path):
        try:
            with open(state_path, "rb") as f:
                # SECURITY WARNING: Only load trusted pickles. Checksums or signatures recommended for public usage.
                s = pickle.load(f)
                gen.solved = s.get("solved", set())
                gen.complexity = s.get("complexity", 1)
                mon.concepts = s.get("concepts", 0)
                mon.tasks = s.get("tasks", 0)
        except: pass
    
    cycle, last_save = 0, time.time()
    try:
        while True:
            cycle += 1
            print(f"\n{'='*50} CYCLE {cycle} | L:{gen.complexity} | M:{cog.meta.meta_level} {'='*10}")
            
            name, ios = gen.generate()
            print(f"[Task] {name}")
            
            analysis = cog.analyze_task(ios)
            print(f"[Cognitive] {analysis['causal']['causal_type']} | {analysis['physics']['pattern']}")
            
            try:
                # Use BottomUpSynthesizer directly for actual synthesis
                results = hrm.synthesizer.synthesize(
                    ios, 
                    deadline=time.time()+30, 
                    task_id=name,
                    task_params={"task_index": float(cycle), "task_size": float(len(ios))}
                )
                success = bool(results)
                if success:
                    print("[SUCCESS] ✅")
                    gen.report_solved(name); mon.record_task()
                    for code, expr, k, v in results:
                        mon.record_concept(gen.complexity)
                        print(f"  [Discovered] {expr}")
                        # Save checkpoint for RSI proof
                        try:
                            ckpt_dir = "checkpoints"
                            if not os.path.exists(ckpt_dir): os.makedirs(ckpt_dir)
                            ckpt_path = os.path.join(ckpt_dir, f"brain_gen_{int(time.time()*1000)}.pkl")
                            with open(ckpt_path, "wb") as f:
                                pickle.dump({"name": name, "code": code, "expr": str(expr)}, f)
                            print(f"  [RSI Checkpoint] {ckpt_path}")
                        except: pass
                    
                    # [ACTIVE RSI] Inject discoveries back into the engine immediately
                    hrm.inject(results)
                    
                    cog.meta.meta_transfer("synthesis", name, results)
                else: print("[FAILED] ❌")
                cog.learn_result(name, success)
            except Exception as e: print(f"[ERROR] {e}"); cog.learn_result(name, False)
            
            if cycle % 5 == 0:
                mon.status()
                ref = cog.meta.reflect()
                print(f"[Meta] rate:{ref['recent_success_rate']:.2f} rec:{ref['recommendation']}")
                if ref["recommendation"] == "change_strategy": cog.meta.elevate_meta_level()
            
            if time.time() - last_save > 60:
                try:
                    with open(state_path, "wb") as f:
                        pickle.dump({"solved": gen.solved, "complexity": gen.complexity, "concepts": mon.concepts, "tasks": mon.tasks}, f)
                    last_save = time.time()
                except: pass
            
            time.sleep(0.5)
    except KeyboardInterrupt:
        try:
            with open(state_path, "wb") as f:
                pickle.dump({"solved": gen.solved, "complexity": gen.complexity, "concepts": mon.concepts, "tasks": mon.tasks}, f)
        except: pass
        mon.status()
        print(f"\n[Summary] Cycles:{cycle} Tasks:{len(gen.solved)} Meta:{cog.meta.meta_level}")
        if mon.accelerating(): print("🚀 ACCELERATION DETECTED!")
        print("Goodbye! 👋")


def run_synthesis_verification_suite(
    quick: bool = False,
    max_seconds: Optional[float] = None,
    tasks: Optional[Iterable[str]] = None,
    guided: bool = False,
    seed: Optional[int] = None,
) -> Dict[str, Any]:
    tools = ToolRegistry()
    setup = HRMSidecar(tools, quick=quick, guided=guided)
    if seed is not None:
        random.seed(seed)
        if np is not None:
            np.random.seed(seed)
    start_time = time.time()
    timeout = False
    tasks_attempted = 0
    tasks_succeeded = 0
    first_solve_time = None

    def _coerce_float(value: Any) -> float:
        try:
            return float(value)
        except (TypeError, ValueError):
            return 0.0

    def default_tasks() -> List[Dict[str, Any]]:
        return [
            {
                "name": "increment",
                "io_pairs": [{"input": i, "output": i + 1} for i in range(5)],
            },
            {
                "name": "double",
                "io_pairs": [{"input": i, "output": i * 2} for i in range(5)],
            },
            {
                "name": "square",
                "io_pairs": [{"input": i, "output": i * i} for i in range(5)],
            },
            {
                "name": "list_reverse",
                "io_pairs": [
                    {"input": [1, 2, 3], "output": [3, 2, 1]},
                    {"input": [4, 5], "output": [5, 4]},
                    {"input": [], "output": []},
                ],
            },
            {
                "name": "string_reverse",
                "io_pairs": [
                    {"input": "abc", "output": "cba"},
                    {"input": "hello", "output": "olleh"},
                    {"input": "", "output": ""},
                ],
            },
            {
                "name": "list_to_string_concat",
                "io_pairs": [
                    {"input": ["a", "b", "c"], "output": "abc"},
                    {"input": ["hi", "!", "?"], "output": "hi!?"},
                    {"input": [], "output": ""},
                ],
            },
        ]

    selected_tasks = default_tasks()
    if tasks:
        desired = {t.strip() for t in tasks if t and t.strip()}
        selected_tasks = [t for t in selected_tasks if t["name"] in desired]
        missing = sorted(desired.difference({t["name"] for t in selected_tasks}))
        if missing:
            print(f"[Synthesis] Unknown task names skipped: {', '.join(missing)}")

    if not selected_tasks:
        print("[Synthesis] No tasks selected; skipping run.")

    deadline = start_time + max_seconds if max_seconds is not None else None

    try:
        for idx, task in enumerate(selected_tasks):
            if deadline and time.time() > deadline:
                timeout = True
                print("[Synthesis] Timeout reached before task start.")
                break

            io_pairs = task["io_pairs"]
            task_params = {
                "task_index": float(idx),
                "task_size": float(len(io_pairs)),
                "train_size": float(len(io_pairs)),
                "holdout_size": 0.0,
                "base_k": _coerce_float(io_pairs[0]["input"]) if io_pairs else 0.0,
                "base_v": _coerce_float(io_pairs[0]["output"]) if io_pairs else 0.0,
            }

            print(f"[Synthesis] Task {task['name']} ({len(io_pairs)} pairs)")
            tasks_attempted += 1
            try:
                results = setup.synthesizer.synthesize(
                    io_pairs,
                    deadline=deadline,
                    task_id=task["name"],
                    task_params=task_params,
                )
                if results:
                    tasks_succeeded += 1
                    if first_solve_time is None:
                        first_solve_time = time.time() - start_time
                    print(f"[Synthesis] ✅ solved {task['name']}")
                else:
                    print(f"[Synthesis] ⚠️ no solution for {task['name']}")
            except TimeoutError:
                timeout = True
                print(f"[Synthesis] Timeout while solving {task['name']}")
                break
            except Exception as e:
                print(f"[Synthesis] Error on {task['name']}: {e}")
    finally:
        elapsed_seconds = time.time() - start_time
        latent_priors_detected = getattr(setup.synthesizer, "latent_priors_detected", False)
        summary = {
            "timeout": timeout,
            "latent_priors_detected": latent_priors_detected,
            "tasks_attempted": tasks_attempted,
            "tasks_succeeded": tasks_succeeded,
            "elapsed_seconds": round(elapsed_seconds, 3),
            "first_solve_seconds": round(first_solve_time, 3) if first_solve_time is not None else None,
            "guided": guided,
            # METRICS FIX for RSI Driver
            "concepts": setup.concept_count,
            "memories": len(setup.meta_state.abstractions) if list(setup.meta_state.abstractions.keys()) else 0
        }
        print(f"SUMMARY_JSON={json.dumps(summary, separators=(',', ':'))}")
        return summary

def run_ab_compare(
    seeds: int = 5,
    max_seconds: Optional[float] = None,
    quick: bool = False,
    tasks: Optional[Iterable[str]] = None,
) -> Dict[str, Any]:
    guided_results = []
    unguided_results = []
    per_run_max = max_seconds
    if max_seconds is not None:
        total_runs = max(1, seeds * 2)
        per_run_max = max(5.0, max_seconds / total_runs)
    for seed in range(seeds):
        print("\n" + "=" * 20 + f" SEED {seed} UNGUIDED " + "=" * 20)
        unguided = run_synthesis_verification_suite(
            quick=quick,
            max_seconds=per_run_max,
            tasks=tasks,
            guided=False,
            seed=seed,
        )
        unguided_results.append(unguided)
        print("\n" + "=" * 20 + f" SEED {seed} GUIDED " + "=" * 20)
        guided = run_synthesis_verification_suite(
            quick=quick,
            max_seconds=per_run_max,
            tasks=tasks,
            guided=True,
            seed=seed,
        )
        guided_results.append(guided)

    def summarize(results: List[Dict[str, Any]]) -> Dict[str, Any]:
        solved = sum(1 for r in results if r["tasks_succeeded"] > 0)
        total_succeeded = sum(r["tasks_succeeded"] for r in results)
        times = [r["first_solve_seconds"] for r in results if r["first_solve_seconds"] is not None]
        median_time = None
        if times:
            times_sorted = sorted(times)
            mid = len(times_sorted) // 2
            if len(times_sorted) % 2 == 0:
                median_time = (times_sorted[mid - 1] + times_sorted[mid]) / 2.0
            else:
                median_time = times_sorted[mid]
        return {
            "seeds": len(results),
            "seeds_with_solve": solved,
            "total_tasks_succeeded": total_succeeded,
            "median_time_to_first_solve": median_time,
        }

    guided_summary = summarize(guided_results)
    unguided_summary = summarize(unguided_results)
    guided_wins = False
    criteria = []
    if guided_summary["total_tasks_succeeded"] > unguided_summary["total_tasks_succeeded"]:
        guided_wins = True
        criteria.append("more_tasks_solved")
    if guided_summary["median_time_to_first_solve"] is not None:
        if unguided_summary["median_time_to_first_solve"] is None or guided_summary["median_time_to_first_solve"] < unguided_summary["median_time_to_first_solve"]:
            guided_wins = True
            criteria.append("lower_median_time_to_first_solve")
    if guided_summary["seeds_with_solve"] > unguided_summary["seeds_with_solve"]:
        guided_wins = True
        criteria.append("higher_success_rate")
    summary = {
        "guided": guided_summary,
        "unguided": unguided_summary,
        "guided_wins": guided_wins,
        "criteria": criteria,
    }
    print(f"AB_COMPARE_JSON={json.dumps(summary, separators=(',', ':'))}")
    return summary


def orchestrator_benchmark_main(args):
    # Auto-run Honest Synthesis Verification as requested
    run_synthesis_verification_suite()
    
    print(f"=== ORCHESTRATOR BENCHMARK: {args.suite} ===")
    result = run_benchmark_suite(args.suite, args.seed, args.trials)
    print(json.dumps(result, ensure_ascii=False))
    return result

