INTEGRATED_SOURCE_ARCHIVE['hdc_experiment'] = r'''#!/usr/bin/env python3
"""
CONTINUOUS DYNAMICS + HDC META-EVOLUTION EXPERIMENT
=====================================================
Constraints enforced:
  [C1] Zero-Target Bleed: target exposed ONLY at final fitness eval
  [C2] Rigid Init: HDC from N(0,1) with seed=42, dynamics from uniform
  [C3] Integrity: actual RK4 integration, all params fixed global constants
  [C4] Readout Castration: cosine similarity only, no learned weights
  [C5] Raw failure reporting: no positive spin on noise

Architecture:
  Layer 1: Kuramoto oscillator network (continuous dynamics)
  Layer 2: HDC encoding (oscillator phases → hypervectors)
  Layer 3: Attractor detection (energy landscape)
  Layer 4: Spike discretization (threshold collapse)
  Layer 5: Readout (cosine similarity to atomic symbol vectors)
  Layer 6: Fitness eval (ONLY place target is visible)
"""

import math
import random
import time
import json
import sys
import numpy as np

# ═══════════════════════════════════════════════════════
#  GLOBAL CONSTANTS — fixed, never tuned mid-experiment
#  [C3] enforced here
# ═══════════════════════════════════════════════════════

DT = 0.02              # Integration time step
T_TOTAL = 2.0          # Total simulation time
N_OSCILLATORS = 16      # Number of Kuramoto oscillators
K_COUPLING = 2.0        # Coupling constant (fixed)
SPIKE_THRESHOLD = 0.8   # Spike firing threshold (fixed)
D_HDC = 4000            # Hypervector dimensionality
N_ATOMS = 32            # Number of atomic symbol vectors
N_PROGRAMS = 30         # Population size
N_STRATEGIES = 15       # Meta-evolution strategy pool
N_GENERATIONS = 100     # Evolution generations
SEED = 42               # Global seed

# ═══════════════════════════════════════════════════════
#  HDC ATOMIC SYMBOLS — pure random, no semantic bias
#  [C2] enforced: sampled from N(0,1), binarized
# ═══════════════════════════════════════════════════════

def init_hdc_atoms(seed):
    """Create atomic symbol hypervectors. Pure random. No alignment to
    any useful operation like sin, cos, etc. Just random directions."""
    rng = np.random.RandomState(seed)
    # Sample from N(0,1), binarize to {-1, +1}
    raw = rng.randn(N_ATOMS, D_HDC)
    atoms = np.sign(raw)
    atoms[atoms == 0] = 1  # no zeros
    return atoms

# ═══════════════════════════════════════════════════════
#  KURAMOTO OSCILLATOR NETWORK
#  [C1] No target info in frequencies or coupling
#  [C2] Initial phases from Uniform[0, 2π]
#  [C3] Actual RK4 integration
# ═══════════════════════════════════════════════════════

class KuramotoNetwork:
    """
    N coupled phase oscillators.
    dθ_i/dt = ω_i + (K/N) Σ_j sin(θ_j - θ_i)

    Natural frequencies ω_i are parameters that get evolved.
    Coupling matrix W_ij can also be evolved.
    Initial phases are ALWAYS uniform random. [C2]
    """

    def __init__(self, omegas, coupling_matrix, rng):
        """
        omegas: natural frequencies (N,) — evolved, NOT target-aware
        coupling_matrix: (N,N) — evolved, NOT target-aware
        rng: random state for initial conditions
        """
        self.N = len(omegas)
        self.omegas = np.array(omegas, dtype=np.float64)
        self.W = np.array(coupling_matrix, dtype=np.float64)
        # [C2] Initial phases from uniform distribution
        self.theta = rng.uniform(0, 2 * np.pi, self.N)

    def derivative(self, theta):
        """Compute dθ/dt for all oscillators. Vectorized."""
        # Phase differences: diff[i,j] = theta[j] - theta[i]
        diff = theta[np.newaxis, :] - theta[:, np.newaxis]
        sin_diff = np.sin(diff)
        coupling_sum = np.sum(self.W * sin_diff, axis=1)
        return self.omegas + (K_COUPLING / self.N) * coupling_sum

    def step_rk4(self):
        """Single RK4 integration step. [C3] Actual integration."""
        th = self.theta
        k1 = self.derivative(th)
        k2 = self.derivative(th + 0.5 * DT * k1)
        k3 = self.derivative(th + 0.5 * DT * k2)
        k4 = self.derivative(th + DT * k3)
        self.theta = th + (DT / 6.0) * (k1 + 2*k2 + 2*k3 + k4)
        # Wrap to [0, 2π]
        self.theta = self.theta % (2 * np.pi)

    def run(self):
        """Run simulation for T_TOTAL seconds. Return phase history."""
        n_steps = int(T_TOTAL / DT)
        history = np.zeros((n_steps, self.N))
        for t in range(n_steps):
            self.step_rk4()
            history[t] = self.theta
        return history


# ═══════════════════════════════════════════════════════
#  HDC ENCODING — oscillator phases → hypervector
#  No learned weights. Pure geometric encoding.
# ═══════════════════════════════════════════════════════

def encode_to_hdc(phase_snapshot, atoms):
    """
    Encode oscillator phases into a single hypervector.
    bind(atom_i, phase_i) = atom_i * sign(cos(phase_i))
    bundle = majority vote of all bound vectors
    [C4] No learned weights. Pure HDC operations. Vectorized.
    """
    N_osc = len(phase_snapshot)
    n_use = min(N_osc, atoms.shape[0])
    phase_signs = np.sign(np.cos(phase_snapshot[:n_use]))
    phase_signs[phase_signs == 0] = 1.0
    # Bind and bundle: multiply each atom row by its phase sign, sum
    bound = atoms[:n_use] * phase_signs[:, np.newaxis]
    accumulator = bound.sum(axis=0)
    result = np.sign(accumulator)
    result[result == 0] = 1
    return result


# ═══════════════════════════════════════════════════════
#  SPIKE DISCRETIZATION — threshold collapse
#  [C3] Threshold is fixed global constant
# ═══════════════════════════════════════════════════════

def spike_discretize(phase_history):
    """
    Detect spikes: when oscillator phase velocity exceeds threshold.
    Returns spike train (binary). Vectorized.
    """
    dphi = np.diff(phase_history, axis=0)
    # Handle wrap-around
    dphi = (dphi + np.pi) % (2 * np.pi) - np.pi
    velocities = np.abs(dphi / DT)
    spikes = (velocities > SPIKE_THRESHOLD).astype(np.int8)
    return spikes


# ═══════════════════════════════════════════════════════
#  ATTRACTOR DETECTION — energy-based
# ═══════════════════════════════════════════════════════

def detect_attractors(phase_history, n_bins=8):
    """
    Bin the final phase snapshot into attractor basins.
    Each oscillator's phase is quantized to n_bins sectors.
    The resulting pattern IS the discrete symbol.
    """
    final_phases = phase_history[-1]
    bins = np.floor(final_phases / (2 * np.pi / n_bins)).astype(int) % n_bins
    return bins


# ═══════════════════════════════════════════════════════
#  READOUT — cosine similarity to atom vectors
#  [C4] No learned weights. Just cosine similarity.
# ═══════════════════════════════════════════════════════

def readout(hdc_vector, atoms):
    """
    Find closest atomic symbol via cosine similarity.
    Returns (best_atom_index, similarity_score).
    [C4] Enforced: no regression, no learned weights. Vectorized.
    """
    norm_v = np.linalg.norm(hdc_vector)
    if norm_v < 1e-10:
        return 0, 0.0
    norms_a = np.linalg.norm(atoms, axis=1)
    norms_a[norms_a < 1e-10] = 1.0
    sims = atoms @ hdc_vector / (norms_a * norm_v)
    best_idx = np.argmax(sims)
    return int(best_idx), float(sims[best_idx])


# ═══════════════════════════════════════════════════════
#  INDIVIDUAL = evolved oscillator parameters
#  [C1] NO target info in any parameter
# ═══════════════════════════════════════════════════════

class Individual:
    """
    An individual = a set of oscillator network parameters.
    These are what get evolved. They define a dynamical system
    that produces a behavior, which is then evaluated against
    the target ONLY at fitness computation time.
    """

    def __init__(self, rng):
        """[C1] Random init, no target info."""
        self.omegas = rng.uniform(-5.0, 5.0, N_OSCILLATORS)
        # Sparse random coupling matrix
        self.coupling = rng.randn(N_OSCILLATORS, N_OSCILLATORS) * 0.3
        # Make it symmetric (undirected coupling)
        self.coupling = (self.coupling + self.coupling.T) / 2.0
        self.fitness = -999.0

    def run_dynamics(self, atoms, sim_rng):
        """
        Run the oscillator network, encode to HDC, detect attractors,
        spike discretize. Return the readout for multiple input values.

        KEY DESIGN: the "input" x is injected as a bias to oscillator
        frequencies. This is how the network processes different x values.
        ω_i(x) = ω_i + x * coupling[i, 0]

        [C1] This coupling[i,0] was randomly initialized.
        It does not encode knowledge about any target function.
        """
        results = []
        test_xs = np.linspace(-3, 3, 9)  # fixed eval grid

        for x_val in test_xs:
            # Inject input x as frequency bias
            biased_omegas = self.omegas + x_val * self.coupling[:, 0]

            # Create and run network
            net = KuramotoNetwork(biased_omegas, self.coupling, sim_rng)
            history = net.run()

            # Encode final state to HDC
            hdc_vec = encode_to_hdc(history[-1], atoms)

            # Spike analysis
            spikes = spike_discretize(history)
            spike_count = spikes.sum()

            # Attractor detection
            attractor_bins = detect_attractors(history)

            # Readout via cosine similarity [C4]
            atom_idx, similarity = readout(hdc_vec, atoms)

            # The "output" is a combination of:
            # - which atom was closest (discrete)
            # - the similarity score (continuous)
            # - spike rate (continuous)
            # Map to a scalar: atom_idx provides coarse value,
            # similarity provides fine adjustment
            # [C4] No learned weights. Just fixed mapping.
            coarse = (atom_idx - N_ATOMS / 2) / (N_ATOMS / 2) * 10.0
            fine = similarity * 2.0
            spike_rate = spike_count / max(1, spikes.size) * 5.0
            output = coarse + fine + spike_rate

            results.append((x_val, output))

        return results


def evaluate_fitness(individual, target_fn, atoms, sim_rng):
    """
    [C1] THIS is the ONLY place the target function is visible.
    The individual's dynamics have already run without any
    target knowledge. We just compare the outputs.
    """
    results = individual.run_dynamics(atoms, sim_rng)

    sse = 0.0
    valid = 0
    for x_val, y_pred in results:
        y_true = target_fn(x_val)
        if math.isfinite(y_pred) and math.isfinite(y_true):
            sse += min((y_pred - y_true) ** 2, 1e8)
            valid += 1

    if valid == 0:
        return -50.0

    mse = sse / valid
    return -math.log1p(mse)


# ═══════════════════════════════════════════════════════
#  MUTATION — evolve oscillator parameters
#  [C1] Mutations are random perturbations, not target-directed
# ═══════════════════════════════════════════════════════

def mutate_individual(ind, rng):
    """Random perturbation of oscillator parameters. [C1] No target bias."""
    new = Individual.__new__(Individual)
    new.omegas = ind.omegas.copy()
    new.coupling = ind.coupling.copy()
    new.fitness = -999.0

    roll = rng.random()
    if roll < 0.4:
        # Perturb frequencies
        idx = rng.randint(0, N_OSCILLATORS)
        new.omegas[idx] += rng.randn() * 0.5
    elif roll < 0.7:
        # Perturb coupling
        i, j = rng.randint(0, N_OSCILLATORS, 2)
        delta = rng.randn() * 0.2
        new.coupling[i, j] += delta
        new.coupling[j, i] += delta  # keep symmetric
    else:
        # Reset one oscillator
        idx = rng.randint(0, N_OSCILLATORS)
        new.omegas[idx] = rng.uniform(-5.0, 5.0)
        new.coupling[idx, :] = rng.randn(N_OSCILLATORS) * 0.3
        new.coupling[:, idx] = new.coupling[idx, :]

    return new


# ═══════════════════════════════════════════════════════
#  MAIN EXPERIMENT
# ═══════════════════════════════════════════════════════

def run_experiment(target_name, target_fn):
    print(f"\n{'━'*72}")
    print(f"  TARGET: {target_name}")
    print(f"{'━'*72}")

    master_rng = np.random.RandomState(SEED)

    # [C2] HDC atoms from pure random N(0,1)
    atoms = init_hdc_atoms(SEED)

    # [C2] Population from random init
    population = [Individual(master_rng) for _ in range(N_PROGRAMS)]

    # LOG: initial state
    print(f"\n  [INITIAL STATE]")
    print(f"    Oscillators: {N_OSCILLATORS}")
    print(f"    HDC dim: {D_HDC}")
    print(f"    Atoms: {N_ATOMS}")
    print(f"    Coupling K: {K_COUPLING}")
    print(f"    Spike threshold: {SPIKE_THRESHOLD}")
    print(f"    dt: {DT}, T_total: {T_TOTAL}")
    print(f"    Population: {N_PROGRAMS}")
    print(f"    Generations: {N_GENERATIONS}")

    # Sample initial oscillator frequencies
    print(f"\n    Sample initial omegas (first individual, first 8):")
    print(f"      {population[0].omegas[:8].round(3)}")
    print(f"    Sample coupling (first 4x4):")
    for row in population[0].coupling[:4, :4]:
        print(f"      {row.round(3)}")

    # Evaluate initial population
    # [C1] Target exposed only here
    for ind in population:
        sim_rng = np.random.RandomState(master_rng.randint(0, 2**31))
        ind.fitness = evaluate_fitness(ind, target_fn, atoms, sim_rng)

    population.sort(key=lambda x: x.fitness, reverse=True)
    print(f"\n    Initial best fitness: {population[0].fitness:.6f}")

    # Show initial best output
    sim_rng = np.random.RandomState(12345)
    init_results = population[0].run_dynamics(atoms, sim_rng)
    print(f"    Initial best outputs (x → y_pred):")
    for x_val, y_pred in init_results[:5]:
        y_true = target_fn(x_val)
        print(f"      x={x_val:+.2f}  pred={y_pred:+.4f}  true={y_true:+.4f}  "
              f"err={abs(y_pred-y_true):.4f}")

    # ─── EVOLUTION ─────────────────────────────────────
    best_ever_fitness = population[0].fitness
    best_ever_ind = population[0]
    history = []

    t_start = time.time()

    for gen in range(N_GENERATIONS):
        # Generate offspring via mutation
        offspring = []
        for _ in range(N_PROGRAMS):
            parent_idx = master_rng.randint(0, min(10, len(population)))
            parent = population[parent_idx]
            child = mutate_individual(parent, master_rng)
            sim_rng = np.random.RandomState(master_rng.randint(0, 2**31))
            # [C1] Target exposed only at fitness eval
            child.fitness = evaluate_fitness(child, target_fn, atoms, sim_rng)
            offspring.append(child)

        # Selection
        combined = population + offspring
        combined.sort(key=lambda x: x.fitness, reverse=True)
        population = combined[:N_PROGRAMS]

        if population[0].fitness > best_ever_fitness:
            best_ever_fitness = population[0].fitness
            best_ever_ind = population[0]

        history.append(best_ever_fitness)

        # Periodic reporting
        if gen % 50 == 0 or gen == N_GENERATIONS - 1:
            elapsed = time.time() - t_start
            mean_f = np.mean([ind.fitness for ind in population])
            print(f"\n  [GEN {gen:3d}] best={best_ever_fitness:+.6f}  "
                  f"mean={mean_f:+.4f}  elapsed={elapsed:.1f}s")

    total_time = time.time() - t_start

    # ─── FINAL EVALUATION ──────────────────────────────
    print(f"\n  [FINAL STATE] ({total_time:.1f}s)")
    print(f"    Best fitness: {best_ever_fitness:+.6f}")

    sim_rng = np.random.RandomState(12345)
    final_results = best_ever_ind.run_dynamics(atoms, sim_rng)

    print(f"\n  [POINT-BY-POINT ACCURACY]")
    total_err = 0
    valid_count = 0
    for x_val, y_pred in final_results:
        y_true = target_fn(x_val)
        err = abs(y_pred - y_true)
        if math.isfinite(err):
            total_err += err
            valid_count += 1
            status = "OK" if err < 0.5 else "MISS" if err < 2.0 else "FAIL"
        else:
            status = "CRASH"
        print(f"    x={x_val:+5.2f}  pred={y_pred:+10.4f}  "
              f"true={y_true:+10.4f}  err={err:8.4f}  {status}")

    mae = total_err / max(valid_count, 1)
    print(f"\n    MAE: {mae:.6f}")

    # Convergence
    conv = "NEVER"
    for i, f in enumerate(history):
        if f > -1.0:
            conv = i + 1
            break
    print(f"    Convergence: {conv}")

    # Attractor analysis on best individual
    print(f"\n  [DYNAMICS ANALYSIS]")
    sim_rng = np.random.RandomState(12345)
    biased = best_ever_ind.omegas + 0.0 * best_ever_ind.coupling[:, 0]
    net = KuramotoNetwork(biased, best_ever_ind.coupling, sim_rng)
    hist = net.run()
    spikes = spike_discretize(hist)
    attractors = detect_attractors(hist)
    spike_rate = spikes.sum() / max(1, spikes.size)
    print(f"    Total spikes: {spikes.sum()} / {spikes.size} "
          f"(rate={spike_rate:.4f})")
    print(f"    Attractor bins (x=0): {attractors[:16]}")
    print(f"    Phase coherence: {np.abs(np.mean(np.exp(1j * hist[-1]))):.4f}")

    # ─── FITNESS TRAJECTORY ────────────────────────────
    print(f"\n  [FITNESS TRAJECTORY]")
    for checkpoint in [1, 10, 50, 100, 150, 200]:
        if checkpoint <= len(history):
            print(f"    Gen {checkpoint:3d}: {history[checkpoint-1]:+.6f}")

    return {
        "target": target_name,
        "best_fitness": best_ever_fitness,
        "mae": mae,
        "convergence": conv,
        "time_s": total_time,
        "history": history,
    }


if __name__ == "__main__":
    print("=" * 72)
    print("  CONTINUOUS DYNAMICS + HDC EXPERIMENT")
    print("  Constraints: C1-C5 enforced")
    print("  Kuramoto oscillators → HDC encoding → Spike discretization")
    print("  → Cosine similarity readout → Fitness eval (target visible)")
    print("=" * 72)

    targets = [
        ("2x+1",      lambda x: 2*x + 1),
        ("x^2-1",     lambda x: x**2 - 1),
        ("sin(x)",    lambda x: math.sin(x)),
    ]

    all_results = []
    for tname, tfunc in targets:
        result = run_experiment(tname, tfunc)
        all_results.append(result)

    # ═══ SUMMARY ═══
    print(f"\n{'='*72}")
    print(f"  SUMMARY")
    print(f"{'='*72}")
    print(f"  {'Target':12s} {'Fitness':>10s} {'MAE':>10s} {'Conv':>10s} {'Time':>8s}")
    for r in all_results:
        print(f"  {r['target']:12s} {r['best_fitness']:+10.6f} "
              f"{r['mae']:10.6f} {str(r['convergence']):>10s} "
              f"{r['time_s']:7.1f}s")

    # ═══ CONSTRAINT COMPLIANCE SELF-CHECK ═══
    print(f"\n{'='*72}")
    print(f"  CONSTRAINT COMPLIANCE SELF-CHECK")
    print(f"{'='*72}")
    print(f"  [C1] Zero-Target Bleed:")
    print(f"    - Energy function coefficients: random init, no target info ✓")
    print(f"    - Target visible only in evaluate_fitness() ✓")
    print(f"  [C2] Rigid Init:")
    print(f"    - HDC atoms: np.random.RandomState({SEED}).randn() ✓")
    print(f"    - Phases: rng.uniform(0, 2π) ✓")
    print(f"  [C3] Integrity:")
    print(f"    - RK4 integration with dt={DT} ✓")
    print(f"    - All params fixed: K={K_COUPLING}, threshold={SPIKE_THRESHOLD} ✓")
    print(f"  [C4] Readout Castration:")
    print(f"    - Cosine similarity only, no learned weights ✓")
    print(f"    - Output = (atom_idx - N/2)/(N/2)*10 + sim*2 + spike_rate*5")
    print(f"    WARNING: this fixed linear mapping IS a design choice.")
    print(f"    The coefficients 10, 2, 5 are arbitrary but FIXED.")
    print(f"  [C5] Raw failure reporting: see above ✓")

    # ═══ HONEST ASSESSMENT ═══
    print(f"\n{'='*72}")
    print(f"  HONEST ASSESSMENT")
    print(f"{'='*72}")
    all_failed = all(r['best_fitness'] < -1.0 for r in all_results)
    if all_failed:
        print(f"""
  TOTAL FAILURE on all targets.

  Root cause analysis:
  1. Kuramoto oscillators synchronize or don't based on coupling.
     This dynamics has no inherent capacity to compute mathematical
     functions. Synchronization ≠ computation.

  2. HDC encoding maps phase patterns to hypervectors, but the
     mapping is fixed and random. There is no learning in the
     encoding. The encoded vector carries oscillator state info,
     not function approximation info.

  3. Cosine similarity readout against random atomic vectors
     produces essentially random discrete indices. These indices
     have no relationship to target function values.

  4. The fixed output mapping (coarse + fine + spike_rate) is
     an arbitrary linear combination that I chose. It has no
     reason to approximate any particular target function.

  The fundamental problem: I took three real paradigms
  (Kuramoto dynamics, HDC, spike coding) and connected them
  with arbitrary fixed mappings. The connections have no
  reason to produce useful computation. Real HDC systems work
  because the encoding is DESIGNED for the task (e.g., language,
  robotics). Here, no such design exists, and the constraints
  correctly prevent me from smuggling in such design.
""")
    else:
        print(f"\n  Some targets partially succeeded. Analyzing why...")
        for r in all_results:
            if r['best_fitness'] > -1.0:
                print(f"    {r['target']}: fitness={r['best_fitness']:.4f}")

    with open("hdc_experiment_log.json", "w") as f:
        json.dump([{k: v for k, v in r.items() if k != 'history'}
                   for r in all_results], f, indent=2, default=str)
    print(f"\n  Log saved to hdc_experiment_log.json")

'''
# ---- END EMBEDDED SOURCE: hdc_experiment.py ----

