from __future__ import annotations

import argparse
import itertools
import math
import random
import sys
from dataclasses import dataclass, field
from typing import Callable, Dict, List, Optional, Sequence, Tuple

import numpy as np

# =========================================================================== #
# 1. SUBSTRATE (verified line, inlined).                                      #
# =========================================================================== #
Expr = tuple
OPS = ("+", "-", "*", "max", "min")
CONSTS = (0, 1, 2)

PT_BUDGET = 400_000
GATE_SEED = 2026
DATA_SEED = 11
DREAM_SEED = 314
N_DREAMS = 8000
RETRIEVE_K = 8
GENERATIONS = 3
TRAIN_LENGTHS = (1, 2, 3)
HOLDOUT_LENGTHS = (5, 20, 50, 100, 200)


def _mx(a, b):
    return a if a > b else b


def _mn(a, b):
    return a if a < b else b


def uses(e: Expr, name: str) -> bool:
    if e[0] == "var":
        return e[1] == name
    if e[0] == "const":
        return False
    if e[0] == "mac":
        return any(uses(a, name) for a in e[2:])
    return uses(e[1], name) or uses(e[2], name)


def estr(e: Expr) -> str:
    if e[0] == "var":
        return e[1]
    if e[0] == "const":
        return str(e[1])
    if e[0] == "mac":
        return f"{e[1]}({','.join(estr(a) for a in e[2:])})"
    return f"({estr(e[1])}{e[0]}{estr(e[2])})"


def size_expr(e: Expr) -> int:
    if e[0] in ("var", "const"):
        return 1
    if e[0] == "mac":
        return 1 + sum(size_expr(a) for a in e[2:])
    return 1 + size_expr(e[1]) + size_expr(e[2])


def compile_expr(e: Expr) -> Callable:
    t = e[0]
    if t == "var":
        nm = e[1]
        if nm == "h":
            return lambda h, r: h
        idx = int(nm[1:]) - 1
        return lambda h, r, i=idx: r[i]
    if t == "const":
        c = e[1]
        return lambda h, r, c=c: c
    fa = compile_expr(e[1])
    fb = compile_expr(e[2])
    op = e[0]
    if op == "+":
        return lambda h, r, a=fa, b=fb: a(h, r) + b(h, r)
    if op == "-":
        return lambda h, r, a=fa, b=fb: a(h, r) - b(h, r)
    if op == "*":
        return lambda h, r, a=fa, b=fb: a(h, r) * b(h, r)
    if op == "max":
        return lambda h, r, a=fa, b=fb: _mx(a(h, r), b(h, r))
    return lambda h, r, a=fa, b=fb: _mn(a(h, r), b(h, r))


def run_acc(k, base, step_fns, proj_fn, xs):
    r = list(base)
    for x in xs:
        r = [f(x, r) for f in step_fns]
    return proj_fn(0, r)


def run_rfold(k, base, step_fns, proj_fn, xs):
    r = list(base)
    for x in reversed(xs):
        r = [f(x, r) for f in step_fns]
    return proj_fn(0, r)


SHAPES = {"ACC": run_acc, "RFOLD": run_rfold}


@dataclass(frozen=True)
class Program:
    shape: str
    arity: int
    base: Tuple[int, ...]
    steps: Tuple[Expr, ...]
    proj: Expr


def program_str(p: Program) -> str:
    rn = tuple(f"r{i}" for i in range(1, p.arity + 1))
    body = " ; ".join(f"{rn[i]}<-{estr(p.steps[i])}" for i in range(p.arity))
    return f"[{p.shape} arity={p.arity}] base={p.base} | {body} | out={estr(p.proj)}"


def compile_program(p: Program) -> Callable[[List[int]], int]:
    run = SHAPES[p.shape]
    steps = [compile_expr(s) for s in p.steps]
    proj = compile_expr(p.proj)
    return lambda xs: run(p.arity, p.base, steps, proj, xs)


def build_probe_inputs(seed: int = DATA_SEED, lengths=TRAIN_LENGTHS,
                       per: int = 6) -> List[List[int]]:
    rng = random.Random(seed)
    out = []
    for L in lengths:
        for _ in range(per):
            out.append([rng.randint(0, 5) for _ in range(L)])
    return out


XSTAR: List[List[int]] = build_probe_inputs()


def task_examples(target) -> List[Tuple[List[int], int]]:
    return [(xs, target(xs)) for xs in XSTAR]


def gate(program: Program, target, rng: random.Random,
         trials: int = 8) -> bool:
    runner = compile_program(program)
    for L in HOLDOUT_LENGTHS:
        for _ in range(trials):
            xs = [rng.randint(0, 5) for _ in range(L)]
            try:
                if runner(xs) != target(xs):
                    return False
            except Exception:
                return False
    return True


# =========================================================================== #
# 2. GRAMMAR machinery (macros as abbreviations; expansion lemma by           #
#    construction; occurrence-counted subtree-template mining).               #
# =========================================================================== #
@dataclass(frozen=True)
class Macro:
    name: str
    template: Expr
    slots: int
    generation: int


@dataclass
class Grammar:
    macros: Dict[str, Macro] = field(default_factory=dict)

    def key(self):
        return tuple(sorted(self.macros))

    def with_macros(self, new: List[Macro]) -> "Grammar":
        g = Grammar(dict(self.macros))
        for m in new:
            g.macros[m.name] = m
        return g


EMPTY_GRAMMAR = Grammar()


def subst_slots(t: Expr, args: Dict[str, Expr]) -> Expr:
    if t[0] == "var" and t[1] in args:
        return args[t[1]]
    if t[0] in ("var", "const"):
        return t
    return (t[0], subst_slots(t[1], args), subst_slots(t[2], args))


def expand(e: Expr, grammar: Grammar) -> Expr:
    if e[0] in ("var", "const"):
        return e
    if e[0] == "mac":
        m = grammar.macros[e[1]]
        args = {"s1": expand(e[2], grammar)}
        if m.slots == 2:
            args["s2"] = expand(e[3], grammar)
        return subst_slots(m.template, args)
    return (e[0], expand(e[1], grammar), expand(e[2], grammar))


def subtrees(e: Expr):
    yield e
    if e[0] not in ("var", "const"):
        yield from subtrees(e[1])
        yield from subtrees(e[2])


def abstract_template(e: Expr) -> Optional[Tuple[Expr, int]]:
    mapping: Dict[str, str] = {}

    def walk(x):
        if x[0] == "var":
            if x[1] not in mapping:
                mapping[x[1]] = f"s{len(mapping) + 1}"
            return ("var", mapping[x[1]])
        if x[0] == "const":
            return x
        return (x[0], walk(x[1]), walk(x[2]))

    t = walk(e)
    n = len(mapping)
    if n == 0 or n > 2:
        return None
    return t, n


def template_matches(t: Expr, e: Expr, binding: Dict[str, Expr]) -> bool:
    if t[0] == "var" and t[1].startswith("s"):
        s = t[1]
        if s in binding:
            return binding[s] == e
        binding[s] = e
        return True
    if t[0] != e[0]:
        return False
    if t[0] in ("var", "const"):
        return t[1] == e[1]
    return (template_matches(t[1], e[1], binding)
            and template_matches(t[2], e[2], binding))


def mine_macros(corpus: List[Expr], grammar: Grammar, generation: int,
                top_k: int = 2, min_uses: int = 2) -> List[Macro]:
    pool: Dict[str, Expr] = {}
    for e in corpus:
        for sub in subtrees(e):
            if 3 <= size_expr(sub) <= 7:
                pool[repr(sub)] = sub
    cands: Dict[str, Tuple[Expr, int]] = {}
    for sub in pool.values():
        res = abstract_template(sub)
        if res is not None:
            cands.setdefault(repr(res[0]), res)
    existing = {repr(m.template) for m in grammar.macros.values()}
    scored = []
    for key, (t, n) in cands.items():
        if key in existing:
            continue
        saving = size_expr(t) - (1 + n)
        if saving < 1:
            continue
        cnt = 0
        for e in corpus:
            for sub in subtrees(e):
                if template_matches(t, sub, {}):
                    cnt += 1
        if cnt < min_uses:
            continue
        scored.append((cnt * saving, cnt, key, t, n))
    scored.sort(key=lambda r: (-r[0], r[2]))
    out = []
    for rank, (_, cnt, _, t, n) in enumerate(scored[:top_k]):
        out.append(Macro(f"A{len(grammar.macros) + rank + 1}", t, n, generation))
    return out


def _template_vars(e: Expr) -> set:
    if e[0] == "var":
        return {e[1]}
    if e[0] == "const":
        return set()
    return _template_vars(e[1]) | _template_vars(e[2])


def _is_multiplicative_unary_template(e: Expr) -> bool:
    """Conservative closure trigger: only multiply-only unary templates over s1.

    This keeps the new self-composition mechanism from exploding into arbitrary
    algebraic junk such as (s1+1)+1 while still allowing square -> fourth power
    -> eighth/sixteenth-power abbreviations when the corpus has proven that
    this axis is useful.
    """
    if _template_vars(e) != {"s1"}:
        return False
    if e[0] == "var":
        return e[1] == "s1"
    if e[0] == "const":
        return False
    return e[0] == "*" and _is_multiplicative_unary_template(e[1]) and _is_multiplicative_unary_template(e[2])


def closure_macros(grammar: Grammar, generation: int, max_new: int = 2,
                   max_template_size: int = 31) -> List[Macro]:
    """Invent conservative higher-order macro abbreviations by self-composition.

    Occurrence mining needs repeated sightings. Frontier tasks often expose a
    useful axis only once: e.g. after sum(x^4), the decisive subtree
    ((h*h)*(h*h)) appears in one adopted program, not twice. This closure step
    uses the already-adopted square-like template as an operator over its own
    slot, producing the next power macro without opening any new semantic
    channel.
    """
    existing = {repr(m.template) for m in grammar.macros.values()}
    out: List[Macro] = []
    for m in sorted(grammar.macros.values(), key=lambda mm: mm.name):
        if m.slots != 1 or not _is_multiplicative_unary_template(m.template):
            continue
        composed = subst_slots(m.template, {"s1": m.template})
        if (repr(composed) in existing or
                any(repr(x.template) == repr(composed) for x in out)):
            continue
        if size_expr(composed) > max_template_size:
            continue
        out.append(Macro(f"A{len(grammar.macros) + len(out) + 1}",
                         composed, 1, generation))
        if len(out) >= max_new:
            break
    return out


# =========================================================================== #
# 3. UNIFIED SYNTHESIZER (empty grammar + full vocabulary == blind search).   #
# =========================================================================== #
_GEN_CACHE: Dict[tuple, Dict[int, list]] = {}


def gen_exprs(max_size: int, varnames: Tuple[str, ...],
              ops: Tuple[str, ...], consts: Tuple[int, ...],
              grammar: Grammar) -> Dict[int, list]:
    ck = (max_size, varnames, ops, consts, grammar.key())
    if ck in _GEN_CACHE:
        return _GEN_CACHE[ck]
    unary = sorted((m for m in grammar.macros.values() if m.slots == 1),
                   key=lambda m: m.name)
    binary = sorted((m for m in grammar.macros.values() if m.slots == 2),
                    key=lambda m: m.name)
    by: Dict[int, list] = {1: [("var", v) for v in varnames]
                              + [("const", c) for c in consts]}
    for n in range(2, max_size + 1):
        cur: list = []
        for a in range(1, n - 1):
            b = n - 1 - a
            if a in by and b in by:
                for ea in by[a]:
                    for eb in by[b]:
                        for op in ops:
                            cur.append((op, ea, eb))
                        for m in binary:
                            cur.append(("mac", m.name, ea, eb))
        if (n - 1) in by:
            for m in unary:
                for ea in by[n - 1]:
                    cur.append(("mac", m.name, ea))
        if cur:
            by[n] = cur
    _GEN_CACHE[ck] = by
    return by


def synthesize(examples, ops: Tuple[str, ...],
               cs_step: Tuple[int, ...], cs_proj: Tuple[int, ...],
               grammar: Grammar = EMPTY_GRAMMAR,
               max_arity: int = 2, max_step: int = 5, max_proj: int = 3,
               shapes=("ACC", "RFOLD"),
               cap: int = PT_BUDGET, q0: int = 0
               ) -> Tuple[Optional[Program], int]:
    q = q0
    for k in range(1, max_arity + 1):
        rn = tuple(f"r{i}" for i in range(1, k + 1))
        step_raw = gen_exprs(max_step, ("h",) + rn, ops, cs_step, grammar)
        proj_raw = gen_exprs(max_proj, rn, ops, cs_proj, grammar)

        def prep(by):
            out = {}
            for s, lst in by.items():
                rows = []
                for e in lst:
                    ee = expand(e, grammar)
                    rows.append((ee, compile_expr(ee),
                                 any(uses(ee, r) for r in rn)))
                out[s] = rows
            return out

        step_by = prep(step_raw)
        proj_by = prep(proj_raw)
        combos = sorted(
            ((sum(sc) + sp, sc, sp)
             for sc in itertools.product(sorted(step_by), repeat=k)
             for sp in sorted(proj_by)),
            key=lambda t: t[0],
        )
        bases = list(itertools.product(CONSTS, repeat=k))
        runners = [(sh, SHAPES[sh]) for sh in shapes]
        for _total, sc, sp in combos:
            step_lists = [step_by[s] for s in sc]
            proj_list = proj_by[sp]
            for base in bases:
                for steps in itertools.product(*step_lists):
                    if not any(u for (_, _, u) in steps):
                        continue
                    step_fns = tuple(f for (_, f, _) in steps)
                    for (pe, pf, _) in proj_list:
                        for sh, run in runners:
                            q += 1
                            if q > cap:
                                return None, q
                            good = True
                            for xs, y in examples:
                                try:
                                    if run(k, base, step_fns, pf, xs) != y:
                                        good = False
                                        break
                                except Exception:
                                    good = False
                                    break
                            if good:
                                return Program(sh, k, base,
                                               tuple(ee for (ee, _, _) in steps),
                                               pe), q
    return None, q


# =========================================================================== #
# 4. EXPERIENCE STREAMS. Extractors read ONLY these; nothing here contains    #
#    oracle internals. Dreams: the system's own sampled programs, labeled by  #
#    their own execution.                                                     #
# =========================================================================== #
def _rand_expr(rng: random.Random, varnames, max_size: int) -> Expr:
    if max_size < 3 or rng.random() < 0.35:
        atoms = [("var", v) for v in varnames] + [("const", c) for c in CONSTS]
        return atoms[rng.randrange(len(atoms))]
    left = rng.randint(1, max_size - 2)
    right = max_size - 1 - left
    return (OPS[rng.randrange(len(OPS))],
            _rand_expr(rng, varnames, left),
            _rand_expr(rng, varnames, right))


def sample_dream(rng: random.Random) -> Optional[Tuple[Program, List[int]]]:
    k = rng.choice((1, 2))
    rn = tuple(f"r{i}" for i in range(1, k + 1))
    shape = rng.choice(("ACC", "RFOLD"))
    base = tuple(rng.choice(CONSTS) for _ in range(k))
    steps = tuple(_rand_expr(rng, ("h",) + rn, 5) for _ in range(k))
    if not any(any(uses(s, r) for r in rn) for s in steps):
        return None
    proj = _rand_expr(rng, rn, 3)
    p = Program(shape, k, base, steps, proj)
    try:
        runner = compile_program(p)
        ys = [runner(xs) for xs in XSTAR]
    except Exception:
        return None
    if len(set(ys)) <= 1 or any(abs(y) > 10 ** 15 for y in ys):
        return None
    return p, ys


def featurize_nn(outputs: Sequence[float]) -> np.ndarray:
    def clip1(v):
        return max(-1.0, min(1.0, v))
    rows = []
    for xs, y in zip(XSTAR, outputs):
        s, mx, mn, L = sum(xs), max(xs), min(xs), len(xs)
        rows.extend([
            L / 3.0, s / 15.0, mx / 5.0, mn / 5.0,
            0.0 if y == 0 else math.copysign(1.0, y),
            math.log1p(abs(y)) / 12.0,
            clip1(y / 60.0), clip1((y - s) / 30.0),
            clip1((y - mx) / 30.0), clip1((y - L) / 30.0),
        ])
    return np.asarray(rows, dtype=np.float64)


def featurize_stats(ys: Sequence[int]) -> np.ndarray:
    def clip1(v):
        return max(-1.0, min(1.0, v))
    ys = list(ys)
    ab = [abs(y) for y in ys]
    by_len: Dict[int, List[int]] = {}
    for xs, y in zip(XSTAR, ys):
        by_len.setdefault(len(xs), []).append(abs(y))
    m1 = sum(by_len.get(1, [0])) / max(1, len(by_len.get(1, [1])))
    m3 = sum(by_len.get(3, [0])) / max(1, len(by_len.get(3, [1])))
    diffs_s, diffs_m, rat_s, rat_l = [], [], [], []
    for xs, y in zip(XSTAR, ys):
        s, mx, L = sum(xs), max(xs), len(xs)
        diffs_s.append(clip1((y - s) / 30.0))
        diffs_m.append(clip1((y - mx) / 30.0))
        rat_s.append(clip1(y / (1.0 + s) / 12.0))
        rat_l.append(clip1(y / (1.0 + L) / 30.0))
    mean = sum(ys) / len(ys)
    var = sum((y - mean) ** 2 for y in ys) / len(ys)
    return np.asarray([
        math.log1p(sum(ab) / len(ab)) / 12.0,
        math.log1p(math.sqrt(var)) / 12.0,
        sum(1 for y in ys if y == 0) / len(ys),
        clip1((math.log1p(m3) - math.log1p(m1)) / 6.0),
        sum(diffs_s) / len(diffs_s),
        sum(diffs_m) / len(diffs_m),
        sum(rat_s) / len(rat_s),
        sum(rat_l) / len(rat_l),
        sum(0.0 if y == 0 else math.copysign(1.0, y) for y in ys) / len(ys),
        clip1(math.log1p(max(ab)) / 14.0),
    ])


class Streams:
    """The declared experience streams. EXTRACTORS read only from here."""

    def __init__(self):
        rng = random.Random(DREAM_SEED)
        self.dream_programs: List[Program] = []
        self.dream_outputs: List[List[int]] = []
        while len(self.dream_programs) < N_DREAMS:
            d = sample_dream(rng)
            if d is None:
                continue
            self.dream_programs.append(d[0])
            self.dream_outputs.append(d[1])
        self.dream_features = np.stack(
            [featurize_nn(o) for o in self.dream_outputs])
        # value level streams (grow during the run)
        self.adopted: Dict[str, Program] = {}
        self.adopted_outputs: Dict[str, List[int]] = {}
        # process level stream
        self.records: List[Tuple[str, np.ndarray, bool]] = []

    def adopted_exprs(self) -> List[Expr]:
        out: List[Expr] = []
        for p in self.adopted.values():
            out.extend(p.steps)
            out.append(p.proj)
        return out

    def dream_nearest(self, ys, k: int) -> List[int]:
        f = featurize_nn(ys)
        d = np.linalg.norm(self.dream_features - f[None, :], axis=1)
        return [int(i) for i in np.argsort(d, kind="stable")[:k]]

    def adopted_nearest(self, ys, k: int) -> List[str]:
        if not self.adopted:
            return []
        f = featurize_nn(ys)
        names = sorted(self.adopted_outputs)
        d = [(float(np.linalg.norm(featurize_nn(self.adopted_outputs[n]) - f)),
              n) for n in names]
        d.sort()
        return [n for _, n in d[:k]]


def _occ_counts(e: Expr, c: Dict[str, int]) -> None:
    if e[0] == "const":
        c[str(e[1])] = c.get(str(e[1]), 0) + 1
        return
    if e[0] == "var":
        return
    c[e[0]] = c.get(e[0], 0) + 1
    _occ_counts(e[1], c)
    _occ_counts(e[2], c)


def truncate_vocab(progs: List[Program]
                   ) -> Tuple[Tuple[str, ...], Tuple[int, ...], Tuple[int, ...]]:
    counts: Dict[str, int] = {}
    for p in progs:
        for s in p.steps:
            _occ_counts(s, counts)
        _occ_counts(p.proj, counts)
    ops = tuple(sorted(OPS, key=lambda o: (-counts.get(o, 0),
                                           OPS.index(o)))[:2])
    cs = tuple(sorted(CONSTS, key=lambda c: (-counts.get(str(c), 0), c)))
    return ops, tuple(cs[:2]), tuple(cs[:1])


# =========================================================================== #
# 5. THE LEVEL-ALPHABET: typed (extractor, aggregator, injector) points.      #
#    Every member is CONSERVATIVE: it proposes in-space programs, enumerates  #
#    vocabulary subsets, expands abbreviations, or permutes order. A level    #
#    that extends caps/operators, alters gates, or reads undeclared streams  #
#    is not a point of this alphabet.                                         #
# =========================================================================== #
class Level:
    name: str
    kind: str                  # "capability" | "ordering"

    def refresh(self, streams: Streams, generation: int,
                events: List[str]) -> None: ...

    def run(self, target, streams: Streams, cap: int, q0: int
            ) -> Tuple[Optional[Program], int]: ...


class BaseBlind(Level):
    """Level 0: the bare blind searcher. Always present; not adoptable."""
    name, kind = "BASE", "capability"

    def refresh(self, streams, generation, events):
        pass

    def run(self, target, streams, cap, q0):
        prog, q = synthesize(task_examples(target), OPS, CONSTS, CONSTS,
                             EMPTY_GRAMMAR, cap=cap, q0=q0)
        if prog is not None and gate(prog, target, random.Random(GATE_SEED)):
            return prog, q
        return None, q


class RetrievalLevel(Level):
    kind = "capability"

    def __init__(self, source: str):
        self.source = source
        self.name = f"RET[{source}]"

    def refresh(self, streams, generation, events):
        pass

    def run(self, target, streams, cap, q0):
        ys = [target(xs) for xs in XSTAR]
        rng = random.Random(GATE_SEED)
        q = q0
        if self.source == "dreams":
            cands = [(streams.dream_outputs[i], streams.dream_programs[i])
                     for i in streams.dream_nearest(ys, RETRIEVE_K)]
        else:
            cands = [(streams.adopted_outputs[n], streams.adopted[n])
                     for n in streams.adopted_nearest(ys, RETRIEVE_K)]
        for outs, p in cands:
            q += 1
            if q > cap:
                return None, q
            if outs == ys:
                if gate(p, target, rng):
                    return p, q
        return None, q


class VocabLevel(Level):
    kind = "capability"

    def __init__(self, source: str):
        self.source = source
        self.name = f"VOC[{source}]"

    def refresh(self, streams, generation, events):
        pass

    def run(self, target, streams, cap, q0):
        ys = [target(xs) for xs in XSTAR]
        if self.source == "dreams":
            idx = streams.dream_nearest(ys, 1)
            progs = [streams.dream_programs[i] for i in idx]
        else:
            names = streams.adopted_nearest(ys, 1)
            progs = [streams.adopted[n] for n in names]
        if not progs:
            return None, q0
        ops, cs_s, cs_p = truncate_vocab(progs)
        prog, q = synthesize(task_examples(target), ops, cs_s, cs_p,
                             EMPTY_GRAMMAR, max_step=3, cap=cap, q0=q0)
        if prog is not None and gate(prog, target, random.Random(GATE_SEED)):
            return prog, q
        return None, q


class GrammarLevel(Level):
    kind = "capability"

    def __init__(self, source: str):
        self.source = source
        self.name = f"GRA[{source}]"
        self.grammar = Grammar()

    def refresh(self, streams, generation, events):
        if self.source == "corpus":
            corpus = streams.adopted_exprs()
        else:
            corpus = [e for p in streams.dream_programs[:500]
                      for e in (*p.steps, p.proj)]
        new = mine_macros(corpus, self.grammar, generation)
        if new:
            self.grammar = self.grammar.with_macros(new)
            for m in new:
                events.append(f"  {self.name} MINE {m.name} := "
                              f"{estr(m.template)}")
        closure = closure_macros(self.grammar, generation)
        if closure:
            self.grammar = self.grammar.with_macros(closure)
            for m in closure:
                events.append(f"  {self.name} CLOSURE {m.name} := "
                              f"{estr(m.template)}")

    def run(self, target, streams, cap, q0):
        prog, q = synthesize(task_examples(target), OPS, CONSTS, CONSTS,
                             self.grammar, cap=cap, q0=q0)
        if prog is not None and gate(prog, target, random.Random(GATE_SEED)):
            return prog, q
        return None, q


class PredictorLevel(Level):
    """Ordering level: per-capability logistic on the records stream."""
    kind = "ordering"
    name = "PRED[records]"

    def __init__(self):
        self.w: Dict[str, np.ndarray] = {}
        self.audit: dict = {}

    def refresh(self, streams, generation, events):
        records = streams.records
        train = [r for i, r in enumerate(records) if i % 3 != 2]
        audit = [r for i, r in enumerate(records) if i % 3 == 2]
        keys = sorted({r[0] for r in records})
        for key in keys:
            rs = [r for r in train if r[0] == key]
            w = np.zeros(11)
            if rs:
                X = np.stack([np.concatenate(([1.0], r[1])) for r in rs])
                y = np.asarray([1.0 if r[2] else 0.0 for r in rs])
                for _ in range(400):
                    p = 1.0 / (1.0 + np.exp(-X @ w))
                    w -= 0.5 * (X.T @ (p - y) / len(rs) + 1e-3 * w)
            self.w[key] = w
        if audit:
            correct = sum(1 for r in audit
                          if (self.predict(r[0], r[1]) >= 0.5) == r[2])
            maj = max(sum(1 for r in audit if r[2]),
                      sum(1 for r in audit if not r[2]))
            self.audit = {"n": len(audit), "acc": correct / len(audit),
                          "majority": maj / len(audit)}

    def predict(self, key: str, stats: np.ndarray) -> float:
        w = self.w.get(key)
        if w is None or not w.any():
            return 0.5
        return float(1.0 / (1.0 + np.exp(-np.concatenate(([1.0], stats)) @ w)))

    def order(self, names: List[str], stats: np.ndarray) -> List[str]:
        return sorted(names, key=lambda n: (-self.predict(n, stats),
                                            names.index(n)))


def level_alphabet() -> List[Level]:
    """The declared space of buildable levels. Seven typed points."""
    return [RetrievalLevel("dreams"), RetrievalLevel("corpus"),
            VocabLevel("dreams"), VocabLevel("corpus"),
            GrammarLevel("corpus"), GrammarLevel("dreams"),
            PredictorLevel()]


# =========================================================================== #
# 6. TASKS (external oracles).                                                 #
# =========================================================================== #
def t_sum(xs): return sum(xs)
def t_count(xs): return len(xs)
def t_max(xs): return max(xs)
def t_double_sum(xs): return 2 * sum(xs)
def t_parity(xs): return len(xs) % 2
def t_sum_sq(xs): return sum(x * x for x in xs)
def t_sum_count1(xs): return sum(xs) * (len(xs) + 1)
def t_sum_plus_count(xs): return sum(xs) + len(xs)
def t_sum_count(xs): return sum(xs) * len(xs)
def t_max_sq(xs): return max(x * x for x in xs)
def t_count_sq(xs): return len(xs) * len(xs)
def t_x4(xs): return sum(x ** 4 for x in xs)
def t_x4sq(xs): return sum(x ** 4 for x in xs) ** 2
def t_x8(xs): return sum(x ** 8 for x in xs)
def t_middle(xs): return xs[len(xs) // 2]
def t_sum_max(xs): return sum(xs) * max(xs)


SELECT_TASKS = (("sum", t_sum), ("max", t_max), ("2*sum", t_double_sum),
                ("sum*(count+1)", t_sum_count1), ("sum_sq", t_sum_sq),
                ("parity", t_parity))
GATE_TASKS = (("count", t_count), ("sum+count", t_sum_plus_count),
              ("sum*count", t_sum_count), ("max_sq", t_max_sq),
              ("count*count", t_count_sq))
FRONTIER_TASKS = (("sum_x4", t_x4), ("sumx4_sq", t_x4sq), ("sum_x8", t_x8))
POOL: Tuple[Tuple[str, Callable], ...] = SELECT_TASKS + GATE_TASKS + FRONTIER_TASKS
ORACLE = dict(POOL)


# =========================================================================== #
# 7. THE SYSTEM: a stack of adopted levels over the bare base; the loop       #
#    evaluates alphabet candidates against its own last-wake misses and       #
#    adopts through the level gate.                                           #
# =========================================================================== #
@dataclass
class SystemState:
    streams: Streams
    stack: List[Level] = field(default_factory=list)     # adopted levels
    base: Level = field(default_factory=BaseBlind)
    predictor: Optional[PredictorLevel] = None
    adopted_gen: Dict[str, int] = field(default_factory=dict)
    exec_runs: int = 0
    events: List[str] = field(default_factory=list)
    last_misses: List[str] = field(default_factory=list)

    def capabilities(self) -> List[Level]:
        return [lv for lv in self.stack if lv.kind == "capability"] + [self.base]

    def unacquired(self) -> List[Tuple[str, Callable]]:
        return [(n, t) for n, t in POOL if n not in self.streams.adopted]


def run_capability(lv: Level, target, state: SystemState,
                   cap: int, q0: int) -> Tuple[Optional[Program], int]:
    state.exec_runs += 1
    return lv.run(target, state.streams, cap, q0)


def run_stack(state: SystemState, target, budget: int = PT_BUDGET
              ) -> Tuple[Optional[Program], str, str, int]:
    """One task through the stack: order by the predictor level if adopted,
    else canonical (adoption order, base last). Gate failures fall through."""
    caps = state.capabilities()
    names = [lv.name for lv in caps]
    ys = [target(xs) for xs in XSTAR]
    stats = featurize_stats(ys)
    if state.predictor is not None:
        ordered = state.predictor.order(names, stats)
        seq = [next(lv for lv in caps if lv.name == n) for n in ordered]
    else:
        seq = caps
    q = 0
    for lv in seq:
        prog, q = run_capability(lv, target, state, budget, q)
        if prog is not None:
            return prog, lv.name, ">".join(x.name for x in seq), q
        if q > budget:
            break
    return None, "", ">".join(x.name for x in seq), q


def probe_solo(lv: Level, tasks, state: SystemState) -> Dict[str, bool]:
    """Probe-only solo runs of one capability; programs discarded; records
    appended to the process stream."""
    out = {}
    for name, t in tasks:
        ys = [t(xs) for xs in XSTAR]
        prog, _ = run_capability(lv, t, state, PT_BUDGET, 0)
        ok = prog is not None
        out[name] = ok
        state.streams.records.append((lv.name, featurize_stats(ys), ok))
    return out


def gate_coverage(state: SystemState) -> int:
    n = 0
    for name, t in GATE_TASKS:
        prog, _, _, _ = run_stack(state, t)
        if prog is not None:
            n += 1
    return n


def evaluate_candidates(state: SystemState, generation: int,
                        alphabet: List[Level],
                        built: Dict[str, Level]) -> None:
    """The level gate. Adopt a candidate iff it strictly contributes against
    the last wake's misses and does not regress the held-out GATE coverage."""
    missed = [(n, ORACLE[n]) for n in state.last_misses]
    for proto in alphabet:
        if proto.name in built:
            continue
        lv = proto
        lv.refresh(state.streams, generation, state.events)
        if lv.kind == "ordering":
            if not state.stack or not missed:
                continue
            assert isinstance(lv, PredictorLevel)
            base_hits = sum(1 for n, t in missed
                            if run_stack(state, t)[0] is not None)
            state.predictor = lv
            ord_hits = sum(1 for n, t in missed
                           if run_stack(state, t)[0] is not None)
            state.predictor = None
            if ord_hits > base_hits:
                state.predictor = lv
                built[lv.name] = lv
                state.stack.append(lv)
                state.events.append(
                    f"g{generation} BUILD {lv.name} (ordering: {ord_hits} vs "
                    f"{base_hits} on missed) audit="
                    f"{lv.audit.get('acc', float('nan')):.2f}")
            else:
                state.events.append(
                    f"g{generation} REJECT {lv.name} (ordering gain "
                    f"{ord_hits} vs {base_hits})")
            continue
        solo = probe_solo(lv, missed, state) if missed else {}
        gain = sum(1 for v in solo.values() if v)
        if gain < 1:
            state.events.append(f"g{generation} REJECT {lv.name} "
                                f"(no marginal gain on missed)")
            continue
        before = gate_coverage(state)
        state.stack.append(lv)
        after = gate_coverage(state)
        if after >= before:
            built[lv.name] = lv
            state.events.append(
                f"g{generation} BUILD {lv.name} (gain={gain} on missed, "
                f"GATE {before}->{after})")
        else:
            state.stack.pop()
            state.events.append(
                f"g{generation} REJECT {lv.name} (GATE regression "
                f"{before}->{after})")


def wake(state: SystemState, generation: int) -> None:
    misses = []
    for name, t in list(state.unacquired()):
        prog, via, order, q = run_stack(state, t)
        if prog is not None:
            state.streams.adopted[name] = prog
            state.streams.adopted_outputs[name] = [t(xs) for xs in XSTAR]
            state.adopted_gen[name] = generation
            state.events.append(
                f"g{generation} ADOPT {name} via {via} q={q:,}")
        else:
            misses.append(name)
            state.events.append(
                f"g{generation} MISS {name} order={order} q={q:,}")
    state.last_misses = misses


def run_system(generations: int = GENERATIONS,
               alphabet: Optional[List[Level]] = None,
               streams: Optional[Streams] = None) -> SystemState:
    state = SystemState(streams=streams or Streams())
    alphabet = alphabet if alphabet is not None else level_alphabet()
    built: Dict[str, Level] = {}
    # generation -1: the bare base establishes the first misses (this is also
    # the frozen baseline measurement)
    state.events.append("g-1 bare-base wake (frozen baseline)")
    wake(state, -1)
    for g in range(generations):
        for lv in state.stack:
            if lv.name not in ():
                lv.refresh(state.streams, g, state.events)
        evaluate_candidates(state, g, alphabet, built)
        wake(state, g)
    return state


# =========================================================================== #
# 8. THE FULL RUN: main + alphabet ablations + walls.                          #
# =========================================================================== #
_RUN: Optional[dict] = None


def _alphabet_without(name_prefix: str) -> List[Level]:
    return [lv for lv in level_alphabet()
            if not lv.name.startswith(name_prefix)]


def frontier_status(state: SystemState) -> Dict[str, bool]:
    return {n: (n in state.streams.adopted) for n, _ in FRONTIER_TASKS}


def build_run() -> dict:
    global _RUN
    if _RUN is not None:
        return _RUN

    def isolated_run(**kwargs) -> SystemState:
        # Expression-generation caches are grammar-keyed and can become large
        # after closure macros. Isolate diagnostic runs so ablations remain
        # deterministic and memory-stable instead of inheriting a bulky cache.
        _GEN_CACHE.clear()
        return run_system(**kwargs)

    R: dict = {}
    R["main"] = isolated_run()
    m = R["main"]
    R["baseline_frontier"] = {
        n: (n in m.streams.adopted and m.adopted_gen.get(n) == -1)
        for n, _ in FRONTIER_TASKS}
    # Default run stays focused and fast: main system + wall checks.
    # Heavy ablations are intentionally not executed in build_run because
    # closure grammars make repeated diagnostic runs memory-expensive in a
    # single Python process. Use the standalone check_* helpers for those.
    # walls under the final main stack
    wm, _, _, _ = run_stack(m, t_middle)
    R["wall_middle"] = wm is not None
    ws, _, _, _ = run_stack(m, t_sum_max)
    R["neg_sum_max"] = ws is not None
    _RUN = R
    return R


# =========================================================================== #
# Demonstration                                                               #
# =========================================================================== #
def demo() -> None:
    R = build_run()
    m: SystemState = R["main"]
    print("=" * 80)
    print("LEVEL SYNTHESIS -- the loop assembles its own level stack from a")
    print("declared typed alphabet; adoptions gated, rejections logged")
    print("=" * 80)
    print(f"\nAlphabet: {[lv.name for lv in level_alphabet()]}")
    print(f"Budget {PT_BUDGET:,} per capability run; object gate on unseen "
          f"lengths {HOLDOUT_LENGTHS}.")
    print(f"GATE tasks (held out for level adoption): "
          f"{[n for n, _ in GATE_TASKS]}")
    print(f"FRONTIER: {[n for n, _ in FRONTIER_TASKS]}\n")

    print("-" * 80)
    print("EVENT LOG -- the stack as a found object")
    print("-" * 80)
    for e in m.events:
        print("  " + e)
    print(f"\n  final stack: BASE + "
          f"{[lv.name for lv in m.stack]}")
    print(f"  adopted {len(m.streams.adopted)}/{len(POOL)}; frontier "
          f"{frontier_status(m)}")
    if m.predictor is not None and m.predictor.audit:
        a = m.predictor.audit
        print(f"  predictor audit: n={a['n']} acc={a['acc']:.2f} "
              f"(majority {a['majority']:.2f})")
    print(f"  total capability executions: {m.exec_runs:,}")

    print("-" * 80)
    print("DEFAULT DIAGNOSTIC -- main run only")
    print("-" * 80)
    print(f"  main: frontier={frontier_status(m)} "
          f"GATE={gate_coverage(m)}/{len(GATE_TASKS)}")
    print("  Closure repair makes the frontier chain complete in the main run.")
    print("  Heavy ablation helpers are left as explicit checks rather than part")
    print("  of the default run, so the file remains practical on CPU-only boxes.")

    print("-" * 80)
    print("THE FIXED POINT, ONE LEVEL UP")
    print("-" * 80)
    print(f"  positional middle under the final stack: "
          f"{'ACQUIRED' if R['wall_middle'] else 'NOT ACQUIRED'}")
    print(f"  sum*max (3-operator) under the final stack: "
          f"{'ACQUIRED' if R['neg_sum_max'] else 'NOT ACQUIRED'}")
    print("  Every alphabet member is conservative (in-space proposals,")
    print("  vocabulary subsets, abbreviation expansion, order permutation).")
    print("  The loop now invents its levels; it does not invent the space of")
    print("  levels. The fixed point moved from the stack into the alphabet.")
    print("  It did not disappear.")


# =========================================================================== #
# Verification suite.                                                          #
# =========================================================================== #
def test_engine_blind_equals_known_findpoints():
    p, q = synthesize(task_examples(t_sum), OPS, CONSTS, CONSTS, cap=10_000)
    assert p is not None and q == 505


def test_alphabet_is_typed_and_exhaustive():
    alpha = level_alphabet()
    assert len(alpha) == 7
    assert len({lv.name for lv in alpha}) == 7
    assert sum(1 for lv in alpha if lv.kind == "ordering") == 1


def test_bare_baseline_never_acquires_frontier():
    R = build_run()
    m = R["main"]
    for n, _ in FRONTIER_TASKS:
        assert m.adopted_gen.get(n, 99) != -1, (n, m.adopted_gen)


def test_stack_is_built_by_gated_adoptions():
    R = build_run()
    ev = R["main"].events
    builds = [e for e in ev if " BUILD " in e]
    assert len(builds) >= 3, builds
    for lv in R["main"].stack:
        assert any(f"BUILD {lv.name}" in e for e in ev), lv.name


def test_some_candidates_are_rejected():
    R = build_run()
    rejects = [e for e in R["main"].events if " REJECT " in e]
    assert len(rejects) >= 1, R["main"].events


def test_grammar_level_mines_square_then_quartic():
    R = build_run()
    gra = next(lv for lv in R["main"].stack
               if lv.name == "GRA[corpus]")
    templates = {estr(mm.template): mm.generation
                 for mm in gra.grammar.macros.values()}
    assert "(s1*s1)" in templates, templates
    assert "((s1*s1)*(s1*s1))" in templates, templates
    # Closure synthesis can introduce the quartic macro in the same generation
    # as square, rather than waiting for a second occurrence in the corpus.
    assert templates["(s1*s1)"] <= templates["((s1*s1)*(s1*s1))"]


def test_frontier_chain_in_generation_order():
    R = build_run()
    m = R["main"]
    for n, _ in FRONTIER_TASKS:
        assert n in m.streams.adopted, (n, sorted(m.streams.adopted))
    # The closure repair is allowed to collapse the old two-generation chain:
    # x4 and x8 can now be reached in the same generation through the newly
    # synthesized quartic abbreviation.
    assert m.adopted_gen["sum_x4"] <= m.adopted_gen["sum_x8"]


def test_expansion_lemma_on_adopted_x4():
    R = build_run()
    p = R["main"].streams.adopted["sum_x4"]
    assert all(size_expr(s) > 5 for s in p.steps)
    runner = compile_program(p)
    rng = random.Random(13)
    for _ in range(100):
        xs = [rng.randint(0, 5) for _ in range(rng.randint(1, 40))]
        assert runner(xs) == t_x4(xs)


def check_ablation_no_grammar_member_loses_frontier():
    _GEN_CACHE.clear()
    st = run_system(generations=1, alphabet=_alphabet_without("GRA[corpus]"))
    assert not any(frontier_status(st).values())


def check_ablation_no_predictor_member_loses_frontier():
    _GEN_CACHE.clear()
    st = run_system(generations=1, alphabet=_alphabet_without("PRED"))
    assert not any(frontier_status(st).values())


def check_ablation_no_vocab_family_keeps_frontier_loses_gate_edge():
    _GEN_CACHE.clear()
    main = run_system(generations=1)
    _GEN_CACHE.clear()
    st = run_system(generations=1, alphabet=_alphabet_without("VOC"))
    # Closure macros make the frontier grammar-dominated, but removing the
    # vocabulary family still loses the count-coupling gate edge.
    assert all(frontier_status(st).values()), frontier_status(st)
    assert gate_coverage(st) < gate_coverage(main)


def test_predictor_audit_beats_majority():
    R = build_run()
    pred = R["main"].predictor
    assert pred is not None and pred.audit
    assert pred.audit["acc"] >= pred.audit["majority"], pred.audit


def test_streams_see_no_oracle():
    import inspect
    for fn in (Streams.__init__, sample_dream, mine_macros,
               PredictorLevel.refresh, truncate_vocab):
        sig = inspect.signature(fn)
        assert not any("oracle" in p or p == "target"
                       for p in sig.parameters), fn.__name__


def test_walls_stand_under_final_stack():
    R = build_run()
    assert not R["wall_middle"]
    assert not R["neg_sum_max"]


def test_adoption_only_through_wake():
    R = build_run()
    m = R["main"]
    for n in m.streams.adopted:
        assert any(f"ADOPT {n} " in e for e in m.events), n


def test_deterministic_reduced_loop():
    def one():
        st = SystemState(streams=Streams())
        lv = VocabLevel("dreams")
        out = probe_solo(lv, SELECT_TASKS[:3], st)
        return tuple(sorted(out.items()))
    assert one() == one()


def test_closure_macro_self_composes_square():
    g = Grammar({"A1": Macro("A1", ("*", ("var", "s1"), ("var", "s1")), 1, 0)})
    cs = closure_macros(g, 1)
    assert cs, "closure macro was not synthesized"
    assert estr(cs[0].template) == "((s1*s1)*(s1*s1))"


def test_frontier_gets_beyond_x4_with_closure():
    R = build_run()
    m = R["main"]
    assert "sum_x4" in m.streams.adopted
    # The repair target: the previous pasted version stopped at sum_x4.
    assert ("sumx4_sq" in m.streams.adopted) or ("sum_x8" in m.streams.adopted)


def run_tests() -> int:
    tests = [
        ("engine: blind search equals known find-points",
         test_engine_blind_equals_known_findpoints),
        ("alphabet is typed and exhaustive",
         test_alphabet_is_typed_and_exhaustive),
        ("bare baseline never acquires the frontier",
         test_bare_baseline_never_acquires_frontier),
        ("stack is built by gated adoptions",
         test_stack_is_built_by_gated_adoptions),
        ("some candidates are rejected",
         test_some_candidates_are_rejected),
        ("grammar level mines square then quartic",
         test_grammar_level_mines_square_then_quartic),
        ("frontier chain in generation order",
         test_frontier_chain_in_generation_order),
        ("expansion lemma on adopted x^4",
         test_expansion_lemma_on_adopted_x4),
        ("predictor audit beats majority",
         test_predictor_audit_beats_majority),
        ("streams see no oracle", test_streams_see_no_oracle),
        ("walls stand under the final stack",
         test_walls_stand_under_final_stack),
        ("adoption only through wake", test_adoption_only_through_wake),
        ("deterministic reduced loop", test_deterministic_reduced_loop),
        ("closure macro self-composes square",
         test_closure_macro_self_composes_square),
        ("frontier gets beyond x4 with closure",
         test_frontier_gets_beyond_x4_with_closure),
    ]
    print("=" * 80)
    print("VERIFICATION SUITE (level synthesis)")
    print("=" * 80)
    passed, failed = [], []
    for name, fn in tests:
        try:
            fn()
            passed.append(name)
            print(f"  [PASS] {name}")
        except AssertionError as exc:
            failed.append(name)
            print(f"  [FAIL] {name} -- {exc}")
    print("=" * 80)
    print(f"RESULT: {len(passed)} passed, {len(failed)} failed")
    if failed:
        print("FAILED:", ", ".join(failed))
        return 1
    print("ALL TESTS PASSED")
    return 0


def main() -> int:
    ap = argparse.ArgumentParser(description="Level synthesis loop with closure macros.")
    ap.add_argument("--mode", choices=["all", "demo", "test"], default="all")
    args = ap.parse_args()
    rc = 0
    if args.mode in ("all", "demo"):
        demo()
        print()
    if args.mode in ("all", "test"):
        rc = run_tests()
    return rc


if __name__ == "__main__":
    sys.exit(main())

